    this.ShowHideVectorLayerByZoomSetting = function () {
        let _Zoom = app.map.getZoom();
        const _OldlayerChekedState = app.layerChekedState;// new Map([...app.layerChekedState]);
        const _NewlayerChekedState = app.GetLayerEnableState();
        app.layerChekedState = _NewlayerChekedState;// new Map([..._NewlayerChekedState]);
        // All Layers redraw  to enable disable the colisition
        if (app.IsZoomInTriggered == true && _Zoom == app.CollisionEnableZoomConfiguration) {
            app.IsCollisionEnabled = false;
            app.RenderVectorLayer(0);
            return;
        } else if (app.IsZoomInTriggered == false && _Zoom == app.CollisionEnableZoomConfiguration - 1) {
            app.IsCollisionEnabled = true;
            app.RenderVectorLayer(0);
            return;
        }
        //All Layers redraw on layer checked/unchecked 
        let areValuesEqual = true;
        //If Size is different means any entity checked/unchecked completly
        if (_NewlayerChekedState.size !== _OldlayerChekedState.size) {
            areValuesEqual = false
        } else {
            // Compare values for each key if size is same           
            _OldlayerChekedState.forEach((_oldValue, key) => {
                const _newValue = _NewlayerChekedState.get(key);
                if (_oldValue !== _newValue) {
                    areValuesEqual = false;
                }
            });
        }
        if (areValuesEqual == false) {
            app.RenderVectorLayer(0);
            return;
        }
        //All Layers redraw on min/max zoom change
        $.each(app.geomTypes, function (i, itm) {
            $.each($(si.DE.ulNetworkLayers + " li[data-geomtype='" + itm + "'] .mainLyr:checked").not(":disabled").filter(function () {
                return ((app.IsZoomInTriggered == true && _Zoom == parseInt($(this).attr('data-minzoomlvl'))) || (app.IsZoomInTriggered == false && _Zoom == parseInt($(this).attr('data-minzoomlvl')) - 1))
            }).sort(function (a, b) { return parseInt($(a).attr('data-maplayerseq')) - parseInt($(b).attr('data-maplayerseq')) }), function () {
                let layrAbbr = $(this).attr('data-mapabbr');
                app.RenderVectorLayer(app.layerListAbbr.indexOf(layrAbbr));
            });
        });

    }
