    this.GetPolygonCenterPoint = function (_feature) {
        const centroid = turf.centroid(_feature.geometry);
        if (!turf.booleanPointInPolygon(centroid, _feature)) {
            // If centroid is outside the polygon, find a point closer to the center
            return turf.pointOnFeature(_feature).geometry.coordinates;
        } else {
            return centroid.geometry.coordinates;
        }
    }

