    this.GetIntersectedProvince = function () {
        var intersectingProvince = [];
        var isIntersected = false;
        var _bbox = [app.BBOXPointForVectorlayer[0], app.BBOXPointForVectorlayer[1], app.BBOXPointForVectorlayer[2], app.BBOXPointForVectorlayer[3]];
        var _bboxPolygon = turf.bboxPolygon(_bbox);
        for (let i = 0; i < app.provinceGeoJson.features.length; i++) {
            isIntersected = turf.booleanIntersects(app.provinceGeoJson.features[i], _bboxPolygon);
            if (isIntersected) {
                //console.log(app.provinceGeoJson.features[i].properties.province_id);
                intersectingProvince.push(app.provinceGeoJson.features[i].properties.province_id.toString());
            }
        }
        return intersectingProvince;
    }
    this.ProcessvectorDataForLabel = function (_entity_type, _distanceBetweenPoints) {
        //Spacing Between the tow points
        // let distanceBetweenPoints = _distanceBetweenPoints; 
        if (_entity_type == 'Cable' && app.cableGeoJson.features) {
            app.cableLabelData = [];
            app.cableCoreLabelData = [];
            //Loop through the every Cable
            app.cableGeoJson.features.forEach((feature) => {
                if (feature.geometry) {
                    const lineLength = turf.length(feature, { units: 'meters' });
                    let delta = 0.5 * lineLength;
                    let depth = 1;
                    let pointSpacing = (lineLength < _distanceBetweenPoints ? ((lineLength * .4)) : _distanceBetweenPoints);
                    while (delta > pointSpacing) {
                        for (let i = 1; i < 2 ** depth; i += 2) {
                            let priority = 100 - depth;
                            let dAlong = i * delta;
                            let offset = 3;
                            if (dAlong > 0.5 * lineLength) offset *= -1;
                            const pointOnLine = turf.along(feature, dAlong, { units: 'meters' });
                            const nextFeature = turf.along(feature, dAlong + offset, { units: 'meters' });
                            const { coordinates } = pointOnLine.geometry;
                            const next = nextFeature.geometry.coordinates;
                            if (!(coordinates[0] === next[0] && coordinates[1] === next[1])) {
                                let angle = 90 - turf.rhumbBearing(coordinates, next);
                                if (Math.abs(angle) > 90) angle += 180;
                                app.cableCoreLabelData.push({
                                    region_id: feature.properties.region_id,
                                    province_id: feature.properties.province_id,
                                    position: pointOnLine.geometry.coordinates,
                                    text: feature.properties.cable_cores,
                                    network_status: feature.properties.network_status,
                                    system_id: feature.properties.system_id,
                                    entity_category: feature.properties.entity_category,
                                    angle,
                                    priority
                                });
                                app.cableLabelData.push({
                                    region_id: feature.properties.region_id,
                                    province_id: feature.properties.province_id,
                                    position: pointOnLine.geometry.coordinates,
                                    text: app.GetLabelText(feature),
                                    network_status: feature.properties.network_status,
                                    system_id: feature.properties.system_id,
                                    entity_category: feature.properties.entity_category,
                                    angle,
                                    priority
                                });
                            }
                        }
                        depth++;
                        delta /= 2;
                    }
                }
            });
        } else if (_entity_type == 'Trench' && app.trenchGeoJson.features) {
            app.trenchLabelData = [];
            //Loop through the every Trench
            app.trenchGeoJson.features.forEach((feature) => {
                if (feature.geometry) {
                    const lineLength = turf.length(feature, { units: 'meters' });
                    let delta = 0.5 * lineLength;
                    let depth = 1;
                    let pointSpacing = (lineLength < _distanceBetweenPoints ? ((lineLength * .4)) : _distanceBetweenPoints);
                    while (delta > pointSpacing) {
                        for (let i = 1; i < 2 ** depth; i += 2) {
                            let priority = 100 - depth;
                            let dAlong = i * delta;
                            let offset = 3;
                            if (dAlong > 0.5 * lineLength) offset *= -1;
                            const pointOnLine = turf.along(feature, dAlong, { units: 'meters' });
                            const nextFeature = turf.along(feature, dAlong + offset, { units: 'meters' });
                            const { coordinates } = pointOnLine.geometry;
                            const next = nextFeature.geometry.coordinates;
                            if (!(coordinates[0] === next[0] && coordinates[1] === next[1])) {
                                let angle = 90 - turf.rhumbBearing(coordinates, next);
                                if (Math.abs(angle) > 90) angle += 180;
                                app.trenchLabelData.push({
                                    region_id: feature.properties.region_id,
                                    province_id: feature.properties.province_id,
                                    position: pointOnLine.geometry.coordinates,
                                    text: app.GetLabelText(feature),
                                    network_status: feature.properties.network_status,
                                    entity_category: feature.properties.entity_category,
                                    angle,
                                    priority
                                });
                            }
                        }
                        depth++;
                        delta /= 2;
                    }
                }
            });
        } else if (_entity_type == 'Duct' && app.ductGeoJson.features) {
            app.ductLabelData = [];
            //Loop through the every Trench
            app.ductGeoJson.features.forEach((feature) => {
                if (feature.geometry) {
                    const lineLength = turf.length(feature, { units: 'meters' });
                    let delta = 0.5 * lineLength;
                    let depth = 1;
                    let pointSpacing = (lineLength < _distanceBetweenPoints ? ((lineLength * .4)) : _distanceBetweenPoints);
                    while (delta > pointSpacing) {
                        for (let i = 1; i < 2 ** depth; i += 2) {
                            let priority = 100 - depth;
                            let dAlong = i * delta;
                            let offset = 3;
                            if (dAlong > 0.5 * lineLength) offset *= -1;
                            const pointOnLine = turf.along(feature, dAlong, { units: 'meters' });
                            const nextFeature = turf.along(feature, dAlong + offset, { units: 'meters' });
                            const { coordinates } = pointOnLine.geometry;
                            const next = nextFeature.geometry.coordinates;
                            if (!(coordinates[0] === next[0] && coordinates[1] === next[1])) {
                                let angle = 90 - turf.rhumbBearing(coordinates, next);
                                if (Math.abs(angle) > 90) angle += 180;
                                app.ductLabelData.push({
                                    region_id: feature.properties.region_id,
                                    province_id: feature.properties.province_id,
                                    position: pointOnLine.geometry.coordinates,
                                    text: app.GetLabelText(feature),
                                    network_status: feature.properties.network_status,
                                    entity_category: feature.properties.entity_category,
                                    angle,
                                    priority
                                });
                            }
                        }
                        depth++;
                        delta /= 2;
                    }
                }
            });
        }
    }
    this.HandleVectorHoverEvent = function (object) {
        //Fire double click on the click on single click
        if (!google.maps.event.hasListeners(app.map, 'click') && google.maps.event.hasListeners(app.map, 'dblclick')) {
            google.maps.event.addListener(app.map, 'click', function (event) {
                google.maps.event.trigger(app.map, 'dblclick', {
                    latLng: event.latLng,
                    customData: 'This additional patch/event is implemneted to convert the single click to double click because single click listener was removed on few click',
                });
            });
        }
        //Change the cursor while hover on deck layer but info feature is not active
        if (!$('.infoSwitch').hasClass('activeToolBar')) {
            const isOverLayer = Boolean(object);
            app.map.setOptions({ draggableCursor: isOverLayer ? 'pointer' : 'grab' });
        }
    }
    this.GetLayerEnableState = function () {
        let _layerState = new Map();
        $.each(app.geomTypes, function (i, itm) {
            $.each($(si.DE.ulNetworkLayers + " li[data-geomtype='" + itm + "'] .mainLyr").sort(function (a, b) { return parseInt($(a).attr('data-maplayerseq')) - parseInt($(b).attr('data-maplayerseq')) }), function () {
                let layrAbbr = $(this).attr('data-mapabbr');
                //console.log(layrAbbr);
                const listItem = $(this).closest('li');
                const siblingCheckboxes = listItem.find('input[type="checkbox"]');//.not(this);
                let sValCode = "C";
                siblingCheckboxes.each(function () {
                    const checkVal = $(this).prop('checked');
                    sValCode = sValCode + (checkVal ? "1" : "0");
                });
                _layerState.set(layrAbbr, sValCode);
            });
        });
        return _layerState;
    }
    this.OpenElementInfoWindow = function (_system_id, _entity_type, _geom_type, _network_id, _network_stage, _display_name) {
        ajaxReq('Main/GetInfo', {}, true, function (resp) {
            $(app.DE.infoMain).html(resp);
            $(app.DE.InfoDiv).show();
            $("#rdbDisplayedLayer").trigger("click");
            $('.infoMain #dvInfoElement').css('margin-left', '-445px');
            app.showElementInfo(_system_id, _entity_type, _geom_type, _network_id, _network_stage, _display_name, null, false);
        }, false, true);
    }
    this.RenderVectorLayer = function (layerIndex) {
        //FetchRequiredData
        app.ActivePlannedVectorlayers = app.getActiveNetworkLayers('P', false);
        app.ActiveAsBuiltVectorlayers = app.getActiveNetworkLayers('A', false);
        app.PolygonVectorlayers = app.getActivePolygonlayer();
        app.ActivePlannedVectorlayersWithLabels = app.getActiveNetworkLayers('P', true);
        app.ActiveAsBuiltVectorlayersWithLabels = app.getActiveNetworkLayers('A', true);
        app.PolygonVectorlayersWithLabel = app.getActivePolygonlayer(true);

        //Start process to Render Layres

        // Get an array of all LayerInstance values  
        let uniqueLayerInstancesSet = new Set();
        let _entityName = app.layestList[layerIndex];
        // Fetch all instances associted with entities in the order of entities exists in "layestListArranged" array
        app.layerListArranged.forEach(entityName => {
            if (layerIndex == 0 || entityName === _entityName) {
                const config = this.vectorLayerConfiguration[entityName];
                if (config) {
                    uniqueLayerInstancesSet.add(config.LayerInstance);
                }
            }
        });
        // Make the instances unique
        const uniqueLayerInstances = [...uniqueLayerInstancesSet];
        // Loop over every unique instance to draw vector layers through the deck gl library
        uniqueLayerInstances.forEach(function (_instance) {
            let _layer = [];
            let _entity = [];
            // Filter vectorLayerConfiguration to get entities where LayerInstance is current selected layers
            const filteredlayerConfig = Object.entries(app.vectorLayerConfiguration)
                .filter(([key, value]) => value.LayerInstance === _instance)
                .reduce((acc, [key, value]) => {
                    acc[key] = value;
                    return acc;
                }, {});

            // Arrange the filteredlayerConfig(entities) object based on the order in layestListArranged array
            const arrangedFilteredConfig = {};
            for (const entityName of app.layerListArranged) {
                if (filteredlayerConfig.hasOwnProperty(entityName)) {
                    arrangedFilteredConfig[entityName] = filteredlayerConfig[entityName];
                }
            }
            // Fetched the all layer and entities mapped with this instance
            Object.entries(arrangedFilteredConfig).forEach(([key, value]) => {
                //Check if layer have few Data
                if (app[value.DataObject].features) {
                    value.layerList.forEach(function (_layerFunctionName) {
                        //console.log("layer Fun:" + _layerFunctionName);
                        _layer.push(app[_layerFunctionName]());
                    });
                }
                _entity.push(value.entityName);
            });

            // Fetched the instance if created before
            let _instanceValue = app.layerOverlayInstanceValue.get(_instance);
            if (_instanceValue) {
                _instanceValue.setProps({ layers: _layer });
            } else {
                _instanceValue = new GoogleMapsOverlay({
                    layers: _layer
                });
                // store the instance to use later
                app.layerOverlayInstanceValue.set(_instance, _instanceValue);
            }
            _instanceValue.setMap(app.map);
        });
        app.minLayerIndex = 99;
    }
