    this.activeInactiveMenu = function (obj) {
        var isNotifBell = $(obj).hasClass('notibell');
        var isLogout = $(obj).hasClass('logout');
        //var isLegend = $(obj).hasClass('switch');
        var isInfoSwitch = $(obj).hasClass('infoSwitch');
        var isLibSwitch = $(obj).attr("id") == 'divLibSwitch';
        var isMainToolvar = $(obj).hasClass("maintoolbar");
        var isPlanTool = $(obj).attr("id") == 'Plantool';
        var isExternalDataView = $(obj).hasClass('externalDataView');
        var isSearchEntity = $(obj).attr("id") == 'dvSrch';
        $('#divLibSwitch').toggleClass('activeToolBar');

        $('.gMapProjSpecific, .gmapLineTools').not('.footerMenu').not('.footerRemove').addClass('bulkOhide'); // hide footer icon menus
        $('.myMenu ul li a').next('ul').slideUp(500);


        // console.log("isInfoSwitch:" + isInfoSwitch);
        if (!isInfoSwitch) {

            app.EnableInfoTool(false);
        }
        if (!isLibSwitch) {
            $(".NELibrary").hide('slide', { direction: 'right' }, 500);
        }
        if (!isMainToolvar) {
            app.showhideChildMenu('', '.parentToolbar,.childtoolbar');
        }
        if (!isPlanTool) {

            $("#dvAutoPlanData").hide('slide', { direction: 'up' }, 500);
            if (si.autoplanid > 0) {
                if ($('#openNetworkPlanningData:visible').length == 0 && $('#divNetworkPlanningData:visible').length == 0) {
                    si.autoplanid = 0;
                    si.LoadLayersOnMap();
                }
            }

            if (si.startMarker)
                si.startMarker.setMap(null);
            if (si.endMarker)
                si.endMarker.setMap(null);
            if (si.gMapObj.infoEntity != undefined) { si.gMapObj.infoEntity.setMap(null); }
            if (si.gMapObj.entitySrchObj)
                si.gMapObj.entitySrchObj.setMap(null);
            directionsDisplay.setMap(null);

        }
        if (!isExternalDataView) {
            $("#dvExternalData").hide('slide', { direction: 'up' }, 500);
            //$("#closeExtnlData").trigger("click");
        }
        //if (!isSearchEntity) {
        //    $("#EaSrch").hide('slide', { direction: 'up' }, 500);
        //}
        //if (!isLegend) {
        //    si.ClosedLegend('.legendDiv');
        //}
        if (!isNotifBell) {
            $("#closeUtilNotification").trigger("click");
        }
        if (!isLogout) {
            $(".logout").hide();
        }
        if (si.PointentityOBJ.length > 0) {
            for (var k = 0; k < si.PointentityOBJ.length; k++) {
                si.PointentityOBJ[k].setMap(null);
            }
            app.PointentityOBJ = [];
        }
    }

