        function fnWarningDialog(MasterCableId, SecondCableId) {
            $('.ui-dialog-buttonset button').addClass('okBtn');
            // Define the Dialog and its properties.
            $("#dialog-confirm").dialog({
                resizable: false,
                modal: true,
                title: "Warning!",
                width: 450,
                create: function (e, ui) {
                    $('.ui-dialog-titlebar-close').html('X');
                    var pane = $(this).dialog("widget").find(".ui-dialog-buttonpane");
                    $('.ui-dialog-buttonset button').addClass('okBtn');
                    $("<label class='WarningAcceptance' ><input  type='checkbox'/> I accept above consequences</label>").prependTo(pane);
                },
                buttons: {
                    "OK": function () {
                        if ($('.WarningAcceptance').find('input[type=checkbox]').is(":checked")) {
                            $(this).dialog('close');
                            ajaxReq('Library/CompleteMergeCablesOperation', { MasterCableId: parseInt(MasterCableId), SecondCableId: parseInt(SecondCableId) }
                                , false, function (resp) {
                                    if (resp.status == 'OK') {
                                        alert(resp.message, 'Success', 'success');
                                        $("#MergeCablesDiv").hide();
                                        $(app.DE.lyrRefresh).trigger("click");
                                        //app.showhideChildMenu('', '.parentToolbar,.childtoolbar');
                                    }
                                    else
                                        alert(resp.message, 'Error', 'error');
                                    //app.showhideChildMenu('', '.parentToolbar,.childtoolbar');

                                }, false, true, true);
                        }
                    }
                }
            });
        }
        $(document).on("change", ".WarningAcceptance input", function () {
            if ($('.WarningAcceptance').find('input[type=checkbox]').is(":checked")) {
                $('.ui-dialog-buttonset button').attr('style', 'background: #428600!important');
                $('.ui-dialog-buttonset button').prop("disabled", false);
            }
            else {
                $('.ui-dialog-buttonset button').removeAttr("style");
                $('.ui-dialog-buttonset button').addClass('okBtn');
                $('.ui-dialog-buttonset button').prop("disabled", "disabled");

            }
        });

        $(document).on("click", "#tblMergeCables tbody tr td input[type='checkbox']", function () {
            var rowcount = $('#tblMergeCables >tbody input:checkbox:checked').length;
            if (rowcount > 2) {
                $('#tblMergeCables >tbody input:checkbox:unchecked').prop('disabled', 'disabled');
                event.preventDefault();
                event.stopPropagation();
            }
            else {
                $('#tblMergeCables >tbody input:checkbox:unchecked').prop('disabled', false);
            }
        });


        $(document).on('click', '#btnMergesCablesForm', function () {
            var rowcount = $('#tblMergeCables >tbody input:checkbox:checked').length;
            if ($("#tblMergeCables tbody tr td").find('input[type=radio]').is(":checked")) {
                if (rowcount == 2) {
                    var MasterCableId = $("#tblMergeCables tbody tr td input[type='radio']:checked").val();
                    MasterCableId = parseInt(MasterCableId);
                    if ($("#tblMergeCables tbody tr td").find('input[type=checkbox]').is(":checked")) {
                        var SecondCableId = $("#tblMergeCables tbody tr td").find('input[type=checkbox]:checked').closest('td').prev().find('[type=radio]:unchecked').val();
                        $('.WarningAcceptance input').prop('checked', false);
                        $('.ui-dialog-buttonset button').prop("disabled", "disabled");
                        fnWarningDialog(MasterCableId, SecondCableId);
                    }
                }
                else {
                    alert(MultilingualKey.SI_OSP_GBL_GBL_GBL_298);
                    return;
                }
            }
            else {
                alert(MultilingualKey.SI_OSP_GBL_NET_GBL_189);
                return;
            }
        });
