                //    floorVal = parseInt(lastFloorName.split('_')[1])+1;
                //}

                var floorRowData = '<tr><td> <input style=" width:90%;" maxlength="20" id="lstFloorInfo_' + rowCount + '__floor_name" name="lstFloorInfo[' + rowCount + '].floor_name" type="text" value="floor_' + floorVal + '" class="floorName" ></td>';
                floorRowData += '<td> <input style=" width:30%;" maxlength="3" id="lstFloorInfo_' + rowCount + '__no_of_units" name="lstFloorInfo[' + rowCount + '].no_of_units"  type="text" value="' + lastUnitValue + '" class="FloorUnit" onkeypress="return allowOnlyNumber(event);"></td>';

                floorRowData += '<td><input data-val="true" data-val-number="The field system_id must be a number." data-val-required="The system_id field is required." id="lstFloorInfo_' + rowCount + '__system_id" name="lstFloorInfo[' + rowCount + '].system_id" type="hidden" value="0">';
                floorRowData += '<input data-val="true" data-val-number="The field length must be a number." data-val-required="The length field is required." id="lstFloorInfo_' + rowCount + '__length" name="lstFloorInfo[' + rowCount + '].length" type="hidden" value="0">';
                floorRowData += '<input data-val="true" data-val-number="The field width must be a number." data-val-required="The width field is required." id="lstFloorInfo_' + rowCount + '__width" name="lstFloorInfo[' + rowCount + '].width" type="hidden" value="0">';
                floorRowData += '<input data-val="true" data-val-number="The field height must be a number." data-val-required="The width field is required." id="lstFloorInfo_' + rowCount + '__height" name="lstFloorInfo[' + rowCount + '].height" type="hidden" value="0">';
                floorRowData += '<span class="floorRowDelete" title="Delete" >x</span></td></tr>';

                addRowInFloorTbl.append(floorRowData);
                var chk = $('#lstFloorInfo');
                $(app.DE.ShaftNFloorInut).unbind('keypress').keypress(function () { $(this).removeClass('NotValid'); });


