    this.getActivePolygonlayer = function (isWithlabel) {
        var _Zoom = app.map.getZoom();
        var layers = [];
        if (app.SetZoomLevelForLayers) {
            $.each($(si.DE.ulNetworkLayers + ' li input[data-is-networktype-required="False"][data-entity-geom-type="Polygon"]:checked').filter(function () { return _Zoom >= parseInt($(this).attr('data-minzoomlvl')) }).sort(function (a, b) { return parseInt($(a).attr('data-maplayerseq')) - parseInt($(b).attr('data-maplayerseq')) }), function () {

                var mapAbbr = $(this).data().mapabbr;
                if (!isWithlabel && $(this).parent().find('.chknetwork-L:checked').length == 0) {
                    layers.push(mapAbbr);
                }
                else if (isWithlabel && $(this).parent().find('.chknetwork-L:checked').length > 0) {
                    layers.push(mapAbbr);
                }
            });
        }
        else {
            $.each($(si.DE.ulNetworkLayers + ' li input[data-is-networktype-required="False"][data-entity-geom-type="Polygon"]:checked').sort(function (a, b) { return parseInt($(a).attr('data-maplayerseq')) - parseInt($(b).attr('data-maplayerseq')) }), function () {

                var mapAbbr = $(this).data().mapabbr;
                if (!isWithlabel && $(this).parent().find('.chknetwork-L:checked').length == 0) {
                    layers.push(mapAbbr);
                }
                else if (isWithlabel && $(this).parent().find('.chknetwork-L:checked').length > 0) {
                    layers.push(mapAbbr);
                }
            });
        }

        //app.SetZoomLevelForLayers = true;
        return layers;
    }

