    this.getParentallid = function (obj) {
        if (obj == 'P')
            return "chkPlannedAll";
        else if (obj == 'A')
            return "chkAsBuiltAll";
        else if (obj == 'D')
            return "chkDormentAll";
        else if (obj == 'L')
            return "chklabelAll";
    }
