    this.SetProjectSpecFilters = function () {

        app.projectcodevalue = $('#ddl_ProjectSpeciCode').val();
        app.planningcodevalue = $('#ddl_PlanningSpeciCode').val();
        app.workordercodevalue = $('#ddl_WorkorderSpeciCode').val();
        app.purposecodevalue = $('#ddl_PurposeSpeciCode').val();

        if (app.projectcodevalue != '0' && app.projectcodevalue != undefined) {
            app.filterprojectvalue = "([project_id] =" + app.projectcodevalue + ")";
        }

        if (app.planningcodevalue != '0' && app.planningcodevalue != undefined) {
            app.filterprojectvalue = "([planning_id] =" + app.planningcodevalue + ")";
        }
        if (app.workordercodevalue != '0' && app.workordercodevalue != undefined) {
            app.filterprojectvalue = " ([workorder_id] =" + app.workordercodevalue + ")";
        }
        if (app.purposecodevalue != '0' && app.purposecodevalue != undefined) {
            app.filterprojectvalue = "([purpose_id] =" + app.purposecodevalue + ")";
        }
        if (app.filterprojectvalue == "") {
            app.filterprojectvalue = "1 = 1";
        }
    }

    this.SetCableFilters = function () {
        app.filtercablevalue = "";
        app.cable_type = $('#ddlFilterCableType').val();
        app.cable_category = $('#ddlFilterCableCategory').val();

        if (app.cable_type != '0' && app.cable_type != undefined) {
            app.filtercablevalue += " ([cable_type] ='" + app.cable_type + "')";
        }
        if (app.cable_category != '0' && app.cable_category != undefined) {
            app.filtercablevalue += ((app.cable_type != '0' && app.cable_type != undefined) ? " and " : "") + " ([cable_category] ='" + app.cable_category + "')";
        }
        if (app.filtercablevalue == "") {
            app.filtercablevalue = "1 = 1";
        }


    }


    this.SetSectorFilters = function () {
        app.filterSectorValue = "";
        app.sector_type = $('#ddlSectorType').val();
        app.frequency = $('#ddlFrequency').val();

        if (app.sector_type != '0' && app.sector_type != undefined) {
            app.filterSectorValue += " ([sector_type]  in (" + '\'' + app.sector_type.join('\',\'') + '\'' + "))";
        }
        if (app.frequency != '0' && app.frequency != undefined) {
            app.filterSectorValue += ((app.sector_type != '0' && app.sector_type != undefined) ? " and " : "") + " ([frequency] in (" + '\'' + app.frequency.join('\',\'') + '\'' + "))";
        }
        if (app.filterSectorValue == "") {
            app.filterSectorValue = "1 = 1";
        }

    }

    this.SetAutoNetworkFilters = function () {
        app.filterAutoNetworkValue = "1 = 1";

        if (app.autoplanid != '0' && app.autoplanid != undefined) {
            app.filterAutoNetworkValue = " ([source_ref_id] ='" + app.autoplanid + "') and [source_ref_type]='planning'";
        }

    }


    this.SetFaultFilters = function () {
        app.filterFaultvalue = "";
        app.fault_status = $('#ddlFilterFaultStatus').val();

        if (app.fault_status != '0' && app.fault_status != undefined) {
            app.filterFaultvalue += " ([fault_status] ='" + app.fault_status + "')";
        }
        if (app.filterFaultvalue == "") {
            app.filterFaultvalue = "1 = 1";
        }
    }

    this.SetOwnershipFilters = function () {

        app.filterOwnershipvalue = "";
        app.ownership = $("#ddlFilterOwnership").val();
        app.thirdpartyvendor = $('#txt3rdPartyVendor').val();
        if (app.ownership != "" && app.ownership != undefined) {
            app.filterOwnershipvalue += " ([ownership_type] ='" + app.ownership + "')";
        }
        else if (app.ownership != "" && app.ownership != undefined && app.thirdpartyvendor != null) {
            app.filterOwnershipvalue += " ([ownership_type] ='" + app.ownership + "') AND ([third_party_vendor_id] in (" + '\'' + app.thirdpartyvendor.join('\',\'') + '\'' + "))";
        }
        if (app.filterOwnershipvalue == "") {
            app.filterOwnershipvalue = "1 = 1";
        }
    }
    this.SetSplitterFilter = function () {
        app.filterSplitterType = '';
        app.splitter_type = $('#ddlFilterSplitterType').val();
        if (app.splitter_type != '0' && app.splitter_type != undefined) {
            app.filterSplitterType += " ([splitter_type] ='" + app.splitter_type + "')";
        }
        if (app.splitter_type == "0" || app.splitter_type == undefined) {
            app.filterSplitterType = "1 = 1";
        }
    }
    this.SetPODFilters = function () {
        app.filterPODvalue = "";
        app.primary_pod_system_id = $("#ddlPrimaryPOD").val();
        app.secondary_pod_system_id = $("#ddlSecondaryPOD").val();
        if (app.primary_pod_system_id != "" && app.primary_pod_system_id != undefined) {
            app.filterPODvalue += " ([primary_pod_system_id] =" + app.primary_pod_system_id + ")";
        }
        if (app.secondary_pod_system_id != "" && app.secondary_pod_system_id != undefined) {
            if (app.filterPODvalue == "") {
                app.filterPODvalue += " ([secondary_pod_system_id] =" + app.secondary_pod_system_id + ")";
            }
            else {
                app.filterPODvalue += " and ([secondary_pod_system_id] =" + app.secondary_pod_system_id + ")";
            }
        }
        if (app.filterPODvalue == "") {
            app.filterPODvalue = "1 = 1";
        }
    }
    this.SetfilterNetworkTicketFilters = function (_isNetworkTicketRequest, _ticketId) {
        app.filterNetworkTicketValue = "1 = 1";
        if (_isNetworkTicketRequest) {
            app.filterNetworkTicketValue = " ([source_ref_id] ='" + _ticketId + "') and [source_ref_type]='Network_Ticket'";
        }

    }
    this.SetRegionProvinceFilters = function () {
        app.RegionFilter = '';
        app.ProvinceFilter = '';
        //get selected region provinces
        ////;
        app.ActiveRegionlayers = app.getActiveRegionLayers();
        app.ActiveProvincelayers = app.getActiveProvinceLayers();
        var provinceLayer = app.ActiveProvincelayers;
        if (app.role_Id == 1 && app.ActiveProvincelayers.length == 0) {
            provinceLayer = [0];
        }
        app.RegionFilter = " [region_id] in (" + app.ActiveRegionlayers.join(",") + ")";
        if (app.ActiveProvincelayers.length > 0) {
            app.ProvinceFilter = "([region_id] in (" + app.ActiveRegionlayers.join(",") + ") AND [province_id] in (" + provinceLayer.join(",") + "))";
        }
        else {
            app.ProvinceFilter = " [region_id] in (" + app.ActiveRegionlayers.join(",") + ")";
        }

    }

