    this.addPolygonLayer = function (layers, isWithLabel) {

        if (isWithLabel) {
            var areaObj = $(si.DE.ulNetworkLayers + " li input[data-layername='Area']");
            var isLabelOn = $(areaObj).next().next().children('.chknetwork-L').is(':checked')
            if ($(si.DE.ulNetworkLayers + " li input[data-layername='Area']").is(':checked') && layers.includes('ARA') == false && isLabelOn) {
                //layers.push('ARA');
                layers.splice(0, 0, 'ARA');
            }
            var surveyObj = $(si.DE.ulNetworkLayers + " li input[data-layername='Area']");
            var isSurveyLabelOn = $(surveyObj).next().next().children('.chknetwork-L').is(':checked')
            if ($(si.DE.ulNetworkLayers + " li input[data-layername='SurveyArea']").is(':checked') && layers.includes('SVA') == false && isSurveyLabelOn) {
                // layers.push('SVA');
                layers.splice(1, 0, 'SVA');
            }
            var subareaObj = $(si.DE.ulNetworkLayers + " li input[data-layername='Area']");
            var issubareaLabelOn = $(subareaObj).next().next().children('.chknetwork-L').is(':checked')
            if ($(si.DE.ulNetworkLayers + " li input[data-layername='SubArea']").is(':checked') && layers.includes('SBA') == false && issubareaLabelOn) {
                //layers.push('SBA');
                layers.splice(2, 0, 'SBA');
            }
        } else {
            if ($(si.DE.ulNetworkLayers + " li input[data-layername='Area']").is(':checked') && layers.includes('ARA') == false) {
                layers.push('ARA');
            }
            if ($(si.DE.ulNetworkLayers + " li input[data-layername='SurveyArea']").is(':checked') && layers.includes('SVA') == false) {
                layers.push('SVA');
            }
            if ($(si.DE.ulNetworkLayers + " li input[data-layername='SubArea']").is(':checked') && layers.includes('SBA') == false) {
                layers.push('SBA');
            }
        }
        return layers;
    }

