    this.addNewOverlay = function (lyrObj) {
        var foundFlag = true;
        var newLyr = { Name: lyrObj.name, layerObject: lyrObj, Opacity: lyrObj.opacity, visible: true }
        for (var i = 0; i < app.layerManager.length; i++) {
            if (app.layerManager[i].Name == lyrObj.name && lyrObj.name != 'OrthoImage') {
                app.layerManager[i] = newLyr;
                foundFlag = false;
                break;
            }
        }
        if (foundFlag)
            app.layerManager.push(newLyr);
        //app.reLoadGoogleLayers();
    }
    this.addNewNetworkOverlay = function (lyrObj) {
        var foundFlag = true;
        var newLyr = { Name: lyrObj.name, layerObject: lyrObj, Opacity: lyrObj.opacity, visible: true }
        for (var i = 0; i < app.layerNetworkManager.length; i++) {
            if (app.layerNetworkManager[i].Name == lyrObj.name) {
                app.layerNetworkManager[i] = newLyr;
                foundFlag = false;
                break;
            }
        }
        if (foundFlag)
            app.layerNetworkManager.push(newLyr);
        //app.reLoadGoogleLayers();
    }
    this.reLoadGoogleLayers = function () {
        app.removeAllWMSLayers();
        $.each(app.layerManager, function (i, item) {
            item.layerObject.isExistingLayersRequest = true;
            if (item.visible)
                app.map.overlayMapTypes.push(item.layerObject);
        });
    }
