    this.removeNetworkAllWMSLayers = function () {
        for (i = app.map.overlayMapTypes.length - 1; i >= 0; i--) {
            if (!si.map.overlayMapTypes.getAt(i).isExistingLayersRequest) { app.map.overlayMapTypes.removeAt(i); }
        }
    }
    this.removeAllWMSLayers = function () {
        for (i = app.map.overlayMapTypes.length - 1; i >= 0; i--) {
            app.map.overlayMapTypes.removeAt(i);
        }
    }
