    this.performSearch = function (source) {
        //;
        if ($('#SerchinType').is(':visible')) {
            $("#imgscrhtypes").trigger("click");
        }
        switch (source) {
            case "Google":
                $("#txtGoogleSearch").addClass('googleShow');
                $("#txtEntitySearch").addClass('entityHide');
                $("#txtEntitySearch").removeClass('entityShow');
                $("#txtLandBaseLayerSearch").addClass('landbaseHide');
                $("#txtLandBaseLayerSearch").removeClass('landbaseShow');
                $("#landbaselayerSearch").addClass('spnLandbaseNot');
                $("#landbaselayerSearch").removeClass('LandbaseNot');
                $("#entitySearch").addClass('spnEntityNot');
                $("#entitySearch").removeClass('spnEntity');                
                $("#googleSearch").addClass('spnGoogle');
                $("#googleSearch").removeClass('spnGoogleNot');
                $('.logout').fadeOut(500); // slide up logout menu
                $('.gMapProjSpecific, .gmapLineTools').not('.footerMenu').not('.footerRemove').addClass('bulkOhide'); // hide footer icon menus
                resetActiveClassFromMenuItem(); // remove activeToolBar class from all active menu;
                getAddressRemoveActiveClass() // remove activeGoogIcon class from get address map icons
                resetActiveClassFromMenuItem() // remove active class and close dropdown icons
                ///*$("#srchTypeDiv").removeClass("srchTypeEntity").addClass("srchTypeGoogle");
                //$('#txtEntitySearch').hide();
                //$('#txtLandBaseLayerSearch').hide();
                //$('#txtGoogleSearch').show();*/
                break;
            case "Entity":
                $("#txtEntitySearch").addClass('entityShow');
                $("#txtGoogleSearch").addClass('googleHide');
                $("#txtGoogleSearch").removeClass('googleShow');
                $("#txtLandBaseLayerSearch").addClass('landbaseHide');
                $("#txtLandBaseLayerSearch").removeClass('landbaseShow');
                $("#landbaselayerSearch").addClass('spnLandbaseNot');
                $("#landbaselayerSearch").removeClass('LandbaseNot');
                $("#entitySearch").addClass('spnEntity');
                $("#entitySearch").removeClass('spnEntityNot');
                $("#googleSearch").addClass('spnGoogleNot');
                $("#googleSearch").removeClass('spnGoogle');
                $('.logout').fadeOut(500); // slide up logout menu
                $('.gMapProjSpecific, .gmapLineTools').not('.footerMenu').not('.footerRemove').addClass('bulkOhide'); // hide footer icon menus
                resetActiveClassFromMenuItem(); // remove activeToolBar class from all active menu;
                getAddressRemoveActiveClass() // remove activeGoogIcon class from get address map icons
                resetActiveClassFromMenuItem() // remove active class and close dropdown icons
                //$("#srchTypeDiv").removeClass("srchTypeGoogle").addClass("srchTypeEntity");
                //$('#txtGoogleSearch').hide();
                //$('#txtLandBaseLayerSearch').hide();
                //$('#txtEntitySearch').show();
                break;
            case "LandBaselayer":
                $("#txtLandBaseLayerSearch").addClass('landbaseShow');
                $("#txtLandBaseLayerSearch").removeClass('landbaseHide');
                $("#txtEntitySearch").addClass('entityHide');
                $("#txtEntitySearch").removeClass('entityShow');
                $("#txtGoogleSearch").addClass('googleHide');
                $("#txtGoogleSearch").removeClass('googleShow');
                $("#landbaselayerSearch").addClass('spnLandbase');
                $("#landbaselayerSearch").removeClass('spnLandbaseNot');
                $("#entitySearch").addClass('spnEntityNot');
                $("#entitySearch").removeClass('spnEntity');
                $("#googleSearch").addClass('spnGoogleNot');
                $("#googleSearch").removeClass('spnGoogle');
                $("#txtLandBaseLayerSearch").removeClass('spnLandbaseNot');
                $('.logout').fadeOut(500); 
                $('.gMapProjSpecific, .gmapLineTools').not('.footerMenu').not('.footerRemove').addClass('bulkOhide'); 
                resetActiveClassFromMenuItem();
                getAddressRemoveActiveClass(); 
                resetActiveClassFromMenuItem();                
                break;
        }
    }
    this.findAddress = function () {
        //
        var geocoder = new google.maps.Geocoder();
        var gcFlag = true;
        var address = $(app.DE.txtGoogleSearch).val();
        var sepVals = address.split(',');
        if (sepVals.length == 2) {
            var lat = parseFloat(sepVals[0]);
            var lng = parseFloat(sepVals[1]);

            if (!isNaN(lat) && !isNaN(lng))
                gcFlag = false;

            if (lat > -90 && lat < 90 && lng > -180 && lng < 180) {
                var addrLocation = new google.maps.LatLng(lat, lng);
                app.map.setCenter(addrLocation);
                app.map.setZoom(21);
                app.showTempDownArrow(addrLocation, true);
            }
        }
        if (gcFlag) {
            geocoder.geocode({ 'address': address }, function (results, status) {
                if (status == google.maps.GeocoderStatus.OK) {
                    var addrLocation = results[0].geometry.location;
                    app.map.setCenter(addrLocation);
                    app.map.setZoom(21);
                    app.showTempDownArrow(addrLocation, true);
                }
            });
        }
    }



    this.showTempDownArrow = function (position, autohide) {
        app.clearTempdearchObj();
        app.gMapObj.tempSrchObj = app.createMarker(position, 'Content/images/dwnArrow.png');
        app.gMapObj.tempSrchObj.setAnimation(google.maps.Animation.BOUNCE);
        app.gMapObj.tempSrchObj.setMap(app.map);
        if (autohide)
            window.setTimeout(function () { app.gMapObj.tempSrchObj.setMap(null) }, 25000);
    }

    this.clearTempdearchObj = function () {
        if (app.gMapObj.tempSrchObj && app.gMapObj.tempSrchObj.map)
            app.gMapObj.tempSrchObj.setMap(null)
    }
    this.createMarker = function (mrkrLatlng, imageUrl) {
        var gmarkernew = new google.maps.Marker({
            position: mrkrLatlng,
            icon: imageUrl,
            draggable: true,
            label: "",
            id: app.grplibraryMarkercount++
        });

        return gmarkernew;
    }

    this.clearMarkers = function () {
        for (i = 0; i < MarkerList.length; i++) {
            MarkerList[i].setMap(null);
        }
        MarkerList = [];
        ClearRuler();
    }

    this.createMarkerForPathFinder = function (mrkrLatlng, imageUrl, system_id, en_type, port_no, network_id, is_virtual_port_allowed) {
        var gmarkernew = new google.maps.Marker({
            position: mrkrLatlng,
            icon: imageUrl,
            draggable: false,
            id: system_id,
            eType: en_type,
            portNo: port_no,
            networkId: network_id,
            isVirtualPortAllowed: is_virtual_port_allowed
        });

        return gmarkernew;
    }
    
    this.loadSearchEngine = function () {
        //;        
        $(app.DE.txtEntitySearch).autocomplete({

            //source: function (request, response) {
            //    var res = ajaxReq('main/GetEntitySearchResult', { SearchText: request.term }, true, function (data) {
            //        if (data.geonames.length == 0) {
            //            var result = [
            //                {
            //                    label: MultilingualKey.SI_GBL_GBL_JQ_GBL_001
            //                }
            //            ];
            //            response(result);
            //        }
            //        else {
            //            response($.map(data.geonames, function (item) {
            //                return {
            //                    label: item.label, value: item.label, geomType: item.geomType, entityName: item.entityName, entityTitle: item.entityTitle, systemID: item.systemId, status: item.status, entityId: item.entityID
            //                }
            //            }))
            //        }
            //    }, true, false);
            //},
            source: function (request, response) {

                var ntxt = request.term.split(':');
                var IsSrchValid = false;
                IsSrchValid = request.term.length >= 3 && (ntxt.length == 0 || ntxt.length == 1) ? true : ntxt.length > 1 && ntxt[1].length >= 3 ? true : false;
                if (IsSrchValid) {
                    var res = ajaxReq('main/GetEntitySearchResult', { SearchText: request.term }, true, function (data) {
                        if (data.geonames.length == 0) {
                            var result = [
                                {
                                    label: MultilingualKey.SI_GBL_GBL_JQ_GBL_001
                                }
                            ];
                            response(result);
                            $(app.DE.txtEntitySearch).removeClass('ui-autocomplete-loading');
                        }
                        else {
                            response($.map(data.geonames, function (item) {
                                return {
                                    label: item.label, value: item.label, geomType: item.geomType, entityName: item.entityName, entityTitle: item.entityTitle, systemID: item.systemId, status: item.status, entityId: item.entityID
                                }
                            }))
                        }
                    }, true, false);
                }
                else { $(app.DE.txtEntitySearch).removeClass('ui-autocomplete-loading'); }
            },
            minLength: 3,
            select: function (event, ui) {
                //;
                if (ui.item.label == MultilingualKey.SI_GBL_GBL_JQ_GBL_001) {
                    // this prevents "no results" from being selected
                    event.preventDefault();
                    $(app.DE.txtEntitySearch).removeClass('ui-autocomplete-loading');
                }
                else {                    
                    event.preventDefault();
                    app.gtype = ui.item.geomType;
                    if (ui.item.entityName != null) {
                        $(app.DE.txtEntitySearch).val(ui.item.entityTitle + ':' + ui.item.label);
                        app.ShowEntityOnMap(ui.item.systemID, ui.item.entityName, ui.item.geomType);
                        $(app.DE.txtEntitySearch).removeClass('ui-autocomplete-loading');                        
                    }
                    else {
                        $(app.DE.txtEntitySearch).val(ui.item.label + ':');
                    }
                }
            },
            open: function () {
                $(this).removeClass("ui-corner-all").addClass("ui-corner-top");
            },
            close: function () {
                $(this).removeClass("ui-corner-top").addClass("ui-corner-all");
            }
        });
    }

