        var northEast = new google.maps.LatLng(elemntExtant.northEast["Lat"], elemntExtant.northEast["Long"]);
        //var  northEast= new google.maps.LatLng("26.824699936479053", "80.98372910976745");
        //var southWest = new google.maps.LatLng("26.825597157642058", "80.983694");
