        //var southWest = new google.maps.LatLng("26.8236938476301", "80.981303");
        //var northEast = new google.maps.LatLng("26.8261257205708", "80.9855947033413");
        //80.9855947033413 26.8261257205708,80.981303 26.8236938476301

        //var geometryLatLong = getLatLongArr(elemntExtant.sp_geometry);
        //var bounds = new google.maps.LatLngBounds();
        //bounds.extend(geometryLatLong[0]);
        //si.map.fitBounds(bounds);

        // , 
        // var southWest = new google.maps.LatLng("26.823497808552474", "80.98108387617462");
        //var northEast = new google.maps.LatLng("26.826321759648426", "80.98579174366772");


