    this.createLine = function (_path, strokeWdth) {
        strokeWdth = (strokeWdth == undefined || strokeWdth == null || strokeWdth == '' || strokeWdth == 0) ? 2 : strokeWdth * 10;
        var tmpLine = new google.maps.Polyline({
            strokeColor: '#FF8800',
            strokeOpacity: 1,
            strokeWeight: 2,
            zIndex: 1,
            path: _path,
            //editable: true
        });
        ShowLineLength(_path);
        return tmpLine;
    }


    this.getLatLongArr = function (pgString) {
        var latLngArr = [];
        pgString = pgString.substring(pgString.lastIndexOf('(') + 1, pgString.indexOf(')'));
        var longLatArr = [];
        if (pgString.indexOf(',') > -1) {
            longLatArr = pgString.split(',')
        } else {
            longLatArr.push(pgString);
        }
        // var longLatArr = pgString.split(',');
        for (var i = 0; i < longLatArr.length; i++) {
            var LongLatsingle = longLatArr[i].trim().split(' ');
            if (LongLatsingle[0] == "" || LongLatsingle[1] == "") {
                ////;
                var df = 0;
            }
            latLngArr.push(new google.maps.LatLng(parseFloat(LongLatsingle[1]), parseFloat(LongLatsingle[0])));
        }
        return latLngArr;
    }

    this.getBufferedLatLongArr = function (longLatArr) {
        var latLngArr = [];
        ////pgString = pgString.substring(pgString.lastIndexOf('(') + 1, pgString.indexOf(')'));
        ////var longLatArr = pgString.split(',');
        //for (var i = 0; i < longLatArr.length; i++) {
        //    var LongLatsingle = longLatArr[i].trim().split(' ');
        //    if (LongLatsingle[0] == "" || LongLatsingle[1] == "") {
        //        ////;
        //        var df = 0;
        //    }
        //    latLngArr.push(new google.maps.LatLng(parseFloat(LongLatsingle[1]), parseFloat(LongLatsingle[0])));
        //}
        //return latLngArr;

        //for (var i = 0; i < longLatArr.length; i++) {
        //    var arr = longLatArr[i];

        //}

        $.each(longLatArr[0], function (index, value) {
            latLngArr.push(new google.maps.LatLng(parseFloat(value[1]), parseFloat(value[0])));
        });
        return latLngArr;


    }



    this.animateLine = function animateLine(_lineObj, offset) {
        if (_lineObj) {
            if (_lineObj.map) {
                var icons = _lineObj.get('icons');
                if (icons) {
                    if (offset == 5)
                        offset = 0;
                    else
                        offset++;
                    icons[0].offset = offset + 'px';
                    _lineObj.set('icons', icons);
                    setTimeout(function () { animateLine(_lineObj, offset) }, 50);
                }
            }
        }
    }

