    this.getWorkSpaces = function () {
        $(app.DE.InfoDiv).hide();
        $(app.DE.SplicingDiv).hide();
        si.resetShapeTools();
        app.collapseRemove();
        if ($(".logout").is(":visible"))
            $(app.DE.dvUsrSpecific).trigger("click");
        ajaxReq('WorkSpace/GetWorkSpace', '', true, function (resp) {
            $(app.DE.infoMain).html(resp);
            $(app.DE.InfoDiv).show();
            $("#lblInformation").text("Workspaces");
            app.ClearMapAddressTool();
            app.ClearJobPackAddressTool();
            app.clearBulkEntityInfo();
            google.maps.event.addListener(app.map, 'click', function (event) {
                app.ShowMapCordinateInFooter(event.latLng);
                $("#mEvent").prop("checked", false)
                $("#coordDiv").attr('title', 'Coordinate change on mouse over');
            });

            $("[name='DrawMarkings_" + app.OldWorkSpaceId + "']").removeClass('dvdisabled');
            for (k = 0; k < app.gpolyline.length; k++) {
                app.gpolyline[k].setMap(null);
            }
            for (k = 0; k < app.gpoint.length; k++) {
                app.gpoint[k].setMap(null);
            }
            for (k = 0; k < app.gpolygons.length; k++) {
                app.gpolygons[k].setMap(null);
            }
            app.gpolyline = [];
            app.gpoint = [];
            app.gpolygons = [];
            ajaxReq('Main/GetWorkareaByWorkspaceId', { id: app.OldWorkSpaceId }, true, function (resp) {
                if (resp.lstMarkings.length > 0) {
                    $("[name='diveditmarking_" + app.OldWorkSpaceId + "']").removeClass('dvdisabled');
                    $("[name='divdeletemarking_" + app.OldWorkSpaceId + "']").removeClass('dvdisabled');
                    $("[name='showmarking_" + app.OldWorkSpaceId + "']").removeClass('dvdisabled');
                    for (var i = 0; i < resp.lstMarkings.length; i++) {
                        app.ShowWorkAreaLayerOnMap(resp.lstMarkings[i].marking_type, resp.lstMarkings[i].geom);
                    }
                }
            });
        }, false, true);
    }


