    this.ChangePassword = function () {

        ////;
        if ($('#currentPassword').val() == "" || $('#NewPassword').val() == "" || $('#confirmNewPassword').val() == "") {
            $('#currentPassword').css('border', '#e60000 solid 1px'); $('#NewPassword').css('border', '#e60000 solid 1px'); $('#confirmNewPassword').css('border', '#e60000 solid 1px');
            $('#lblmsg').css('color', 'red');
        }
        else if (!app.passwordRegex($('#NewPassword').val())) {

            alert(MultilingualKey.SI_OSP_CHG_JQ_FRM_003);
        }
        else if ($('#NewPassword').val().trim() != $('#confirmNewPassword').val().trim()) {
            alert(MultilingualKey.SI_OSP_CHG_JQ_FRM_001)

        }
        else if ($('#currentPassword').val().trim() == $('#NewPassword').val().trim()) {
            alert(MultilingualKey.SI_OSP_CHG_JQ_FRM_002);
        }
        else {
            app.saveChangePassword();
        }
    }

    this.passwordRegex = function (val) {

        var pattern = /^.*(?=.{6,})(?=.*\d)(?=.*[a-z])(?=.*[A-Z])(?=.*[@#$%&]).*$/;
        //var pattern = /^(?=.*[0-9])(?=.*[a-z])(?=.*[A-Z])([a-zA-Z0-9]{8,})$/;
        if (pattern.test(val)) {
            $('#ImgPwd').show();
            $('#ImgPwd').attr('src', 'Content/images/tick_1.gif')
            return true;

        } else {
            $('#ImgPwd').show();
            $('#ImgPwd').attr('src', 'Content/images/cross.gif')
            return false;

        }
    }



