    function OpenNewWorkspace(wrkspcID) {
        //debugger;
        app.OldWorkSpaceId = wrkspcID;
        $("[name='divmarking_" + app.createMrkngs + "']").removeClass('toolBoxShow');
        app.Markingflag = 0;
        $("[name='showmarking_" + app.createMrkngs + "']").removeClass('activeBlue');
        $("[name='showmarking_" + app.createMrkngs + "']").removeClass('glyphicon-eye-close').addClass('glyphicon-eye-open');
        ajaxReq('WorkSpace/GetWorkSpaceById', { workSpaceId: wrkspcID }, true, function (resp) {
            if (resp.status == "OK") {
                if (resp.result != null) {
                    if (app.createMrkngs == 0) {
                        $("[name='DrawMarkings_" + wrkspcID + "']").removeClass('dvdisabled');
                        //$("[name='showmarking_" + wrkspcID + "']").removeClass('dvdisabled');
                        app.createMrkngs = wrkspcID;
                    }
                    else {
                        $("[name='DrawMarkings_" + app.createMrkngs + "']").addClass('dvdisabled');
                        $("[name='showmarking_" + app.createMrkngs + "']").addClass('dvdisabled');
                        $("[name='DrawMarkings_" + wrkspcID + "']").removeClass('dvdisabled');
                        //$("[name='showmarking_" + wrkspcID + "']").removeClass('dvdisabled');
                        app.createMrkngs = wrkspcID;
                    }
                    app.resetTreeLayer();
                    app.map.setZoom(resp.result.zoom);
                    app.map.setCenter(new google.maps.LatLng(resp.result.lat, resp.result.lng));
                    $(app.DE.chkShowLabelOnMap).prop("checked", resp.result.has_label);

                    var workSpaceLyrs = resp.result.WSLayers;
                    var workSpaceRegionProvinces = resp.result.WSRegionProvince;
                    var workSpaceLandbaseLyrs = resp.result.WSLandbaseLayers;
                    if (workSpaceLyrs.length > 0) {
                        for (var i = 0; i < workSpaceLyrs.length; i++) {
                            $('#chk_nLyr_' + workSpaceLyrs[i].layer_id).not(":disabled").prop('checked', true);
                            //console.log("Planned " + workSpaceLyrs[i].layer_id +":"+ workSpaceLyrs[i].is_planned);
                            $('#chk_netP_' + workSpaceLyrs[i].layer_id).not(":disabled").prop('checked', workSpaceLyrs[i].is_planned);
                            $('#chk_netA_' + workSpaceLyrs[i].layer_id).not(":disabled").prop('checked', workSpaceLyrs[i].is_as_built);
                            $('#chk_netD_' + workSpaceLyrs[i].layer_id).not(":disabled").prop('checked', workSpaceLyrs[i].is_dormant);
                            $('#chk_netL_' + workSpaceLyrs[i].layer_id).prop('checked', workSpaceLyrs[i].is_labels);


                            $.each($('input:checkbox[data-group-name="GRP"]'), function () {
                                var grpName = $(this).attr("data-mapabbr");
                                var _totalChild = $('input:checkbox[data-parent-group="' + grpName + '"]').length;
                                var _checkedChild = $('input:checkbox[data-parent-group="' + grpName + '"]:checked').length;
                                if (_totalChild = _checkedChild) { $(this).prop('checked', true); }
                            })
                            if ($('input:checkbox[data-group-name="GRP"]').length == $('input:checkbox[data-group-name="GRP"]:checked').length) { $("#checkAll").prop('checked', true); }

                        }
                    }
                    if (workSpaceRegionProvinces.length > 0) {
                        for (var i = 0; i < workSpaceRegionProvinces.length; i++) {

                            $('#chk_rLyr_' + workSpaceRegionProvinces[i].region_id).not(":disabled").prop('checked', true);
                            $('#chk_pLyr_' + workSpaceRegionProvinces[i].province_id).not(":disabled").prop('checked', true);
                        }
                    }
                    $('.landbaselyr input[type=checkbox]').prop('checked', false)
                    if (workSpaceLandbaseLyrs.length > 0) {
                        for (var i = 0; i < workSpaceLandbaseLyrs.length; i++) {
                            $('#chk_LBnLyr_' + workSpaceLandbaseLyrs[i].landbase_layer_id).not(":disabled").prop('checked', true);
                            $('#chk_nLBL_' + workSpaceLandbaseLyrs[i].landbase_layer_id).not(":disabled").prop('checked', workSpaceLandbaseLyrs[i].is_labels);
                        }
                        app.landbaseCheckboxCheck();
                    }
                    //Load Vector Layer//                   
                    if ($(app.DE.ulProvinceLayers + '>li>input[type="checkbox"]:checked').length > app.provinceLimitToSelectForLoadinVectorLayer) {
                        alert($.validator.format(MultilingualKey.SI_OSP_GBL_JQ_FRM_120, 1));

                    } else {
                        app.layerChekedState = app.GetLayerEnableState();
                        if (resp.result.zoom >= app.CollisionEnableZoomConfiguration) {
                            app.IsCollisionEnabled = false;
                        }
                        if (app.IsVecorLayerEnabled) {
                            app.RefreshVectorDataAndLayer();
                        }
                    }
                    //-----------------//

                    app.LoadLayersOnMap();
                    //START: Clear Markings & Load Markings according to workspace

                    for (k = 0; k < app.gpolyline.length; k++) {
                        app.gpolyline[k].setMap(null);
                    }
                    for (k = 0; k < app.gpoint.length; k++) {
                        app.gpoint[k].setMap(null);
                    }
                    for (k = 0; k < app.gpolygons.length; k++) {
                        app.gpolygons[k].setMap(null);
                    }
                    app.gpolyline = [];
                    app.gpoint = [];
                    app.gpolygons = [];
                    ajaxReq('Main/GetWorkareaByWorkspaceId', { id: wrkspcID }, true, function (resp) {
                        if (resp.lstMarkings.length > 0) {
                            $("[name='diveditmarking_" + wrkspcID + "']").removeClass('dvdisabled');
                            $("[name='divdeletemarking_" + wrkspcID + "']").removeClass('dvdisabled');
                            $("[name='showmarking_" + wrkspcID + "']").removeClass('dvdisabled');
                            for (var i = 0; i < resp.lstMarkings.length; i++) {
                                app.ShowWorkAreaLayerOnMap(resp.lstMarkings[i].marking_type, resp.lstMarkings[i].geom);
                            }
                        }
                    });
                    google.maps.event.addListener(app.map, 'click', function (event) {
                        app.ShowMapCordinateInFooter(event.latLng);
                        $("#mEvent").prop("checked", false)
                        $("#coordDiv").attr('title', 'Coordinate change on mouse over');
                    });
                    //END
                }
                else {
                    alert(MultilingualKey.SI_OSP_WSP_JQ_FRM_008);
                }
            }
            else {
                alert(MultilingualKey.SI_OSP_WSP_JQ_FRM_009);

            }
        }, true, true);
        if (app.VectorInfoWindow) {
            app.VectorInfoWindow.close();
        }
    }

