    this.GetEntityAttrDetails = function (libItem) {
        var attrDetails = {};
        attrDetails.geomType = $(libItem).attr("data-geomtype");
        attrDetails.enType = $(libItem).attr("data-lyrname");
        attrDetails.pageTitleText = $(libItem).attr('data-title');
        attrDetails.ntkIdType = $(libItem).attr('data-networkidtype');
        attrDetails.isTemplate = $(libItem).attr('data-istemplate');
        attrDetails.pageUrl = $(libItem).attr("data-href");
        attrDetails.saveUrl = $(libItem).attr("data-save-url");
        attrDetails.isDirectSave = $(libItem).attr("data-isdirectsave");
        attrDetails.detailImg = $(libItem).attr("src");


        if (attrDetails["enType"] == "Cable") {
            attrDetails.subCat = $(libItem).attr("data-cabletype");
        }
        else {
            attrDetails.subCat = '';
        }

        return attrDetails;
    }

