    this.handleLinePointDrag = function (dragPT, libItem) {
        //
        app.removeEventListnrs('click');
        app.map.setOptions({ draggableCursor: '' });
        var geomType = app.EntityAttributeDetails["geomType"];
        switch (geomType) {
            case 'Point':
                app.createTempLibPt(dragPT, $(libItem).attr("src").replace('big', 'small'), libItem);
                break;
            case 'Line':
                app.createTempLibLine(dragPT, libItem);
                break;
            case 'Polygon':
                app.createTempLibPolygon(dragPT, libItem);
                break;
            case 'Circle':
                app.createTempLibCircle(dragPT, libItem);
                break;
        }
    }

    this.removeEventListnrs = function (evt) {

        if (evt == "click") {
            //$('.infoSwitch').removeClass('blueInfo').addClass('greyInfo');
            app.gMapObj.ClickAction = '';
            //clear active classes from all the click event elements
            // $('.infoSwitch').removeClass('activeToolBar');
            //$('.infoSwitchLandBase').removeClass('activeToolBar');
            $('#dvSpliceHere').removeClass('activeToolBar');
        }
        if (app.gMapObj.tempBufferCircle) {
            if (app.gMapObj.tempBufferCircle.map)
                app.gMapObj.tempBufferCircle.setMap(null);
        }
        google.maps.event.clearListeners(app.map, evt);
    }

    this.createTempLibPt = function (dragPT, libImg, libItem) {
        ;
        app.clearTempNewEntity();
        LandBase.clearTempNewEntity();
        app.mapListners["TempLibItm"] = app.createMarker(app.getLatLongFromPT(dragPT), libImg);
        if ($("#hdnNEBuffer").val() != '') {
            app.NEBufferValue = $("#hdnNEDefaultBuffer").val() == $("#hdnNEBuffer").val() ? $("#hdnNEDefaultBuffer").val() : $("#hdnNEBuffer").val();
        }
        else if ($(app.DE.txtNEBuffer).val() == '') {
            app.NEBufferValue = 0;
        }
        else {
            app.NEBufferValue = $("#hdnNEDefaultBuffer").val();
        }

        app.LatLngForBuffer = new google.maps.LatLng(app.getLatLongFromPT(dragPT).lat(), app.getLatLongFromPT(dragPT).lng());
        app.initDistanceWidget_A(app.NEBufferValue, app.LatLngForBuffer, app.mapListners["TempLibItm"]);
        app.mapListners["TempLibItm"].setDraggable(true);
        app.mapListners["TempLibItm"].setMap(app.map);
        app.mapListners["mapListners"] = google.maps.event.addListener(app.mapListners["TempLibItm"], 'click', function () {
            app.setLibToolEvents(app.EntityAttributeDetails);
        });
    }

