    this.getGeomObjType = function (elementType, elementObj) {
        var entityGeom = '';
        switch (elementType) {
            case 'Point':
                entityGeom = app.roundNumber(elementObj.getPosition().lng(), 6) + ' ' + app.roundNumber(elementObj.getPosition().lat(), 6);
                break;
            case 'Line':
                entityGeom = app.getInfoEditLineGeom(elementObj);
                break;
            case 'Polygon':
                entityGeom = app.getInfoEditPolygonGeom(elementObj);
                break;
            //case 'Rectangle':
            //    entityGeom = app.getInfoEditRectangleGeom(elementObj);
            //    break;
            case 'Circle':
                entityGeom = app.getInfoEditCircleGeom(elementObj);

                break;
        }
        return entityGeom;
    }

    this.getInfoEditLineGeom = function (lineObj) {
        var _path = lineObj.getPath().getArray();
        if (_path.length > 1)
            return app.getGeomFromlatLngArr(_path);
        else {
            alert(MultilingualKey.SI_OSP_GBL_JQ_FRM_032);
            return false;
        }
    }

    this.getInfoEditPolygonGeom = function (lineObj) {

        var _path = lineObj.getPath().getArray();
        if (_path.length > 2) {
            _path.push(_path[0]);
            return app.getGeomFromlatLngArr(_path);
        }
        else {
            alert(MultilingualKey.SI_OSP_GBL_JQ_FRM_033);
            return false;
        }
    }

    this.getGeomFromlatLngArr = function (_path) {
        var geomTxt = '';
        for (i = 0; i < _path.length; i++) {
            geomTxt += (i == 0 ? '' : ',') + _path[i].lng() + ' ' + _path[i].lat();
        }
        return geomTxt;
    }

    this.getInfoEditCircleGeom = function (circleObj) {

        var center = circleObj.getCenter(), radius = circleObj.getRadius(), numSides = 90;
        var points = [], degreeStep = 360 / numSides;

        for (var i = 0; i < numSides; i++) {
            var gpos = google.maps.geometry.spherical.computeOffset(center, radius, degreeStep * i);
            points.push(new google.maps.LatLng(gpos.lat(), gpos.lng()));
        };
        // Duplicate the last point to close the geojson ring
        points.push(points[0]);
        return app.getGeomFromlatLngArr(points);
    }

