    this.focusItmInfoHover = function (systemID, eType, gType, _obj) {
        ////;
        ajaxReq('main/getGeometryDetail', { systemId: systemID, entityType: eType, geomType: gType }, true, function (resp) {
            if (resp.status = 'OK') {
                if (resp.result != null && resp.result != undefined) {
                    var latLngArr = app.getLatLongArr(resp.result.sp_geometry);
                    var sp_centroid = [];
                    if (eType == "Building") {
                        sp_centroid = app.getLatLongArr(resp.result.sp_centroid);
                    }
                    app._focusMe(gType, latLngArr, eType, sp_centroid);
                    $(_obj).attr("onmouseover", "si._focusMe('" + gType + "',si.getLatLongArr('" + resp.result.sp_geometry + "'),'" + eType + "',si.getLatLongArr('" + resp.result.sp_centroid + "'))");
                }
            }
        }, true, false);
    }

    this._focusMe = function (geomType, latLngArr, eType, sp_centroid) {

        app.removeInfoHoverItem();
        app.removeSrchHoverItem();
        switch (geomType) {
            case 'Point':
                app.gMapObj.infoHoverObj = app.createMarker(latLngArr[0], 'Content/images/dwnArrow.png');
                app.gMapObj.infoHoverObj.setAnimation(google.maps.Animation.BOUNCE);
                break;
            case 'Line':
            // PENDING : NEED TO CHECK THE SAME
            case 'Polygon':
                if (eType == "Building" || eType == "Structure") {
                    app.pgMapObj.infoHoverObj = app.createMarker(sp_centroid[0], 'Content/images/dwnArrow.png');
                    app.pgMapObj.infoHoverObj.setAnimation(google.maps.Animation.BOUNCE);

                    app.pgMapObj.infoHoverObj.setMap(app.map);
                    window.setTimeout(function () { if (app.pgMapObj.infoHoverObj) { app.pgMapObj.infoHoverObj.setMap(null) } app.pgMapObj.infoHoverObj = null; }, 25000);
                }

                app.gMapObj.infoHoverObj = app.createLine(latLngArr);
                var _lineIcon = [{
                    icon: {
                        path: 'M -.5,-.5 .5,-.5, .5,.5 -.5,.5',
                        fillOpacity: 1,
                        fillColor: 'blue'
                    },
                    repeat: '8px'
                }];

                app.gMapObj.infoHoverObj.strokeOpacity = 0;
                app.gMapObj.infoHoverObj.strokeWeight = 4;
                app.gMapObj.infoHoverObj.set('icons', _lineIcon);
                setTimeout(function () { animateLine(app.gMapObj.infoHoverObj, 0) }, 20);

                break;
            case 'Circle':


                app.gMapObj.infoHoverObj = app.createLine(latLngArr);
                var _lineIcon = [{
                    icon: {
                        path: 'M -.5,-.5 .5,-.5, .5,.5 -.5,.5',
                        fillOpacity: 1,
                        fillColor: 'blue'
                    },
                    repeat: '8px'
                }];

                app.gMapObj.infoHoverObj.strokeOpacity = 0;
                app.gMapObj.infoHoverObj.strokeWeight = 4;
                app.gMapObj.infoHoverObj.set('icons', _lineIcon);
                setTimeout(function () { animateLine(app.gMapObj.infoHoverObj, 0) }, 20);

                break;
        }

        app.gMapObj.infoHoverObj.setMap(app.map);
        window.setTimeout(function () { if (app.gMapObj.infoHoverObj) { app.gMapObj.infoHoverObj.setMap(null) } app.gMapObj.infoHoverObj = null; }, 25000);
    }



