    this.addPointEntityClone = function (latLng, imageUrl, entityType, geomType, radius) {
        // app.clearTempNewEntity();
        //app.bulkCloneGeom += latLng.lat() + ' ' + latLng.lng() + ',';
        var layerTitle = getLayerTltle(entityType);
        var cloneLimit = $('#hdnMultiCloneLimit').val();
        if (app.entityOBJ.length <= cloneLimit) {
            if (geomType == 'Point') {
                var marker = app.createMarker(latLng, imageUrl);
                marker.setMap(app.map);
                app.entityOBJ.push(marker);
                marker.addListener('rightclick', function () {
                    marker.setMap(null);
                    app.entityOBJ.pop(marker);
                });
            } else if (geomType == 'Circle') {
                var circle = app.createCircle(radius, latLng);
                circle.setEditable(false);
                circle.setMap(app.map);
                app.entityOBJ.push(circle);
                circle.addListener('rightclick', function () {
                    circle.setMap(null);
                    app.entityOBJ.pop(circle);
                });
            }
        } else { alert('Only ' + cloneLimit + ' ' + layerTitle + ' are allowed!'); }

    }



    this.drawAddLineEntity = function (latLng, libItem) {
        ;// cbl
        app.clearTempNewEntity();
        LandBase.clearTempNewEntity();
        app.gMapObj.libPath.push(latLng);
        app.gMapObj.lineflag = true;
        app.mapListners["TempLibItm"] = app.createLine(app.gMapObj.libPath, $(libItem).data().lyrname == 'ROW' ? parseFloat($(libItem).attr('data-stroke-width')) : 0);
        app.mapListners["TempLibItm"].setEditable(true);
        app.mapListners["TempLibItm"].setMap(app.map);
        app.IsCreateLineExist();
        google.maps.event.addListener(app.mapListners["TempLibItm"], 'rightclick', function (event) {
            if (event.vertex == undefined) {
                return;
            } else {
                app.removeNode(app.mapListners["TempLibItm"], event.vertex);
            }
            app.IsCreateLineExist();
            if ($(libItem).data().lyrname == 'ROW') {
                app.createLineBuffer(app.mapListners["TempLibItm"].getPath().getArray(), parseFloat($(libItem).attr('data-stroke-width')));
            }
            ShowLineLength();
        });

        google.maps.event.addListener(app.mapListners["TempLibItm"].getPath(), 'set_at', function (indx) {
            var newPath = app.mapListners["TempLibItm"].getPath();
            app.gMapObj.libPath = newPath.getArray();
            app.IsCreateLineExist();
            if ($(libItem).data().lyrname == 'ROW') {
                app.createLineBuffer(app.gMapObj.libPath, parseFloat($(libItem).attr('data-stroke-width')));
            }
            ShowLineLength();
        });

        google.maps.event.addListener(app.mapListners["TempLibItm"].getPath(), 'insert_at', function (indx) {
            var newPath = app.mapListners["TempLibItm"].getPath();
            app.gMapObj.libPath = newPath.getArray();
            if ($(libItem).data().lyrname == 'ROW') {
                app.createLineBuffer(app.gMapObj.libPath, parseFloat($(libItem).attr('data-stroke-width')));
            }
            ShowLineLength();
        });


        app.mapListners["mapListners"] = google.maps.event.addListener(app.mapListners["TempLibItm"], 'click', function (evt) {

            if ($(libItem).data().lyrname == 'ROW') {
                app.EntityAttributeDetails.strokeWidth = parseFloat($(libItem).attr('data-stroke-width'));
                app.setLibToolEvents(app.EntityAttributeDetails);
            } else {
                var selectPoint = '';
                selectPoint = app.roundNumber(evt.latLng.lng(), 6) + ' ' + app.roundNumber(evt.latLng.lat(), 6);
                var _zoom = app.map.getZoom();

                var lineArrayLst = app.mapListners["TempLibItm"].getPath().getArray();
                var lenLineArr = lineArrayLst.length;
                if (lenLineArr < 1) {
                    alert(MultilingualKey.SI_OSP_GBL_JQ_FRM_032);
                    return false;
                }
                else {

                    var startPoint = app.roundNumber(lineArrayLst[0].lng(), 6) + ' ' + app.roundNumber(lineArrayLst[0].lat(), 6);
                    var endPoint = app.roundNumber(lineArrayLst[lenLineArr - 1].lng(), 6) + ' ' + app.roundNumber(lineArrayLst[lenLineArr - 1].lat(), 6);
                    if (startPoint == selectPoint || endPoint == selectPoint) {
                        var chkPointType = (startPoint == selectPoint) ? 'start' : 'end';

                        app.IsTerminationPointExist(selectPoint, getMeterDistanceFromZoom(_zoom), 'other', chkPointType, 'creation');
                    }
                }
            }
        });
        if ($(libItem).data().lyrname == 'ROW') {
            app.createLineBuffer(app.mapListners["TempLibItm"].getPath().getArray(), parseFloat($(libItem).attr('data-stroke-width')));
        }

    }
    this.createLineBuffer = function (pointsArray, width) {
        //;
        //Main.js
        var overviewPathGeo = [];
        // var pointsArray = lineObj.getPath().getArray();
        if (pointsArray.length >= 2) {
            if (app.lineBufferObj != null) {
                app.lineBufferObj.setMap(null);
            }
            for (var i = 0; i < pointsArray.length; i++) {
                overviewPathGeo.push([pointsArray[i].lng(), pointsArray[i].lat()]);
            }
            var geoInput = {
                type: "LineString",
                coordinates: overviewPathGeo
            };
            var geoReader = new jsts.io.GeoJSONReader();
            var geoWriter = new jsts.io.GeoJSONWriter();
            var geometry = geoReader.read(geoInput).buffer(((((width + 0.2) / 2) / 1000) / 111.12), 0, 2);
            var polygon = geoWriter.write(geometry);
            var oLanLng = [];
            var oCoordinates;
            oCoordinates = polygon.coordinates[0];
            for (i = 0; i < oCoordinates.length; i++) {
                var oItem;
                oItem = oCoordinates[i];
                oLanLng.push(new google.maps.LatLng(oItem[1], oItem[0]));
            }

            app.lineBufferObj = new google.maps.Polygon({
                paths: oLanLng,
                map: si.map
            });
            app.gMapObj.ROWPath = app.lineBufferObj.getPath().getArray();
        }

    }
    this.drawAddLineEntity1 = function (latLng, libItem) {

        app.clearTempNewEntity();
        LandBase.clearTempNewEntity();
        app.gMapObj.libPath.push(latLng);
        app.firstPoint = app.createLine(app.gMapObj.libPath);
        app.mapListners["TempLibItm"] = app.firstPoint;
        app.mapListners["TempLibItm"].setEditable(true);
        app.mapListners["TempLibItm"].setDraggable(false);
        app.mapListners["TempLibItm"].setMap(app.map);
        app.mapListners["mapListners"] = google.maps.event.addListener(app.mapListners["TempLibItm"], 'click', function () {
            app.removeEventListnrs('click');
            app.map.setOptions({ draggableCursor: '' });
            app.setLibToolEvents(app.EntityAttributeDetails);
        });
    }

    this.drawPolygonEntity = function (latLng, libItem) {
        ;
        if (app.pointCount == 0 && app.firstPoint != null) { app.gMapObj.libPath = []; app.gMapObj.libPath.push(new google.maps.LatLng(app.firstPoint.getPath().getArray()[0].lat(), app.firstPoint.getPath().getArray()[0].lng())); }
        app.pointCount += 1;
        app.gMapObj.libPath.push(latLng);
        app.drawPolygonAndAttachEvents();
    }
    this.drawPolygonAndAttachEvents = function () {

        app.clearTempNewEntity();
        LandBase.clearTempNewEntity();
        app.mapListners["TempLibItm"] = app.createPolygon(app.gMapObj.libPath);
        app.mapListners["TempLibItm"].setEditable(true);
        app.mapListners["TempLibItm"].setDraggable(false);
        app.mapListners["TempLibItm"].setMap(app.map);
        app.mapListners["mapListners"] = google.maps.event.addListener(app.mapListners["TempLibItm"], 'click', function (event) {
            if (event.vertex == undefined) {
                ;
                app.removeEventListnrs('click');
                app.map.setOptions({ draggableCursor: '' });
                app.setLibToolEvents(app.EntityAttributeDetails);
            }
        });

        google.maps.event.addListener(app.mapListners["TempLibItm"], 'rightclick', function (event) {
            if (event.vertex == undefined) {
                return;
            } else {
                app.removeNodeNew(app.mapListners["TempLibItm"], event);
                app.drawPolygonAndAttachEvents();
            }
        });
        app.mapListners["TempLibItm"].getPaths().forEach(function (path, index) {
            google.maps.event.addListener(path, 'set_at', function (indx) {
                var newPath = path;
                app.gMapObj.libPath = newPath.getArray();
            });

            google.maps.event.addListener(path, 'insert_at', function (indx) {
                var newPath = path;
                app.gMapObj.libPath = newPath.getArray();
            });
        });
    }
    this.removeNodeNew = function removeVertex(poly, event) {
        //remove selected node and its duplicate entries if exists..
        var coordinateCounts = poly.getPath().getArray().length;
        for (var i = 0; i < coordinateCounts; i++) {
            // var index = poly.getPath().getArray().findIndex(m=>m.lat() == event.latLng.lat() && m.lng() == event.latLng.lng());
            //IE Solution
            var index = poly.getPath().getArray().findIndex(function (m) { return m.lat() == event.latLng.lat() && m.lng() == event.latLng.lng(); });
            if (index != -1) {
                poly.getPath().removeAt(index);
            }
        }
        //app.gMapObj.libPath=pointArray;
        app.gMapObj.libPath = poly.getPath().getArray();
    }

    this.removeNode = function removeVertex(poly, vertex) {
        poly.getPath().removeAt(vertex);
        app.gMapObj.libPath = poly.getPath().getArray();
    }
    this.createPolygon = function (_path) {
        var tmpLine = new google.maps.Polygon({
            strokeColor: '#FF8800',
            fillColor: '#FF8800',
            fillOpacity: 0.3,
            strokeOpacity: 1,
            strokeWeight: 2,
            path: _path,
            zIndex: 1,//<--
            editable: true,
            draggable: true
        });
        return tmpLine;
    }

    this.ShowOnMaps = function (_path) {
        var tmpLine = new google.maps.Polygon({
            paths: _path,
            strokeColor: '#FF8800',
            fillColor: '#FF8800',
            map: si.map
        });
        return tmpLine;
    }

    this.createRectangle = function (_path) {

        var tmpRectangle = new google.maps.Rectangle({
            strokeColor: '#FF8800',
            strokeOpacity: 0.6,
            strokeWeight: 2,
            fillColor: '#FF8800',
            fillOpacity: 0.35,
            editable: true,
            draggable: true,
            zIndex: 1,
            bounds: _path
        });
        return tmpRectangle;
    }

    this.setLibToolEvents = function (libItem) {

        var centerLineGeom = '';
        var bufferWidth = 0;
        var geomType = app.EntityAttributeDetails["geomType"];
        var detailImg = libItem["detailImg"];
        var eType = libItem["enType"];
        var pageTitleText = libItem["pageTitleText"];
        var isTemplate = libItem["isTemplate"];
        var ntkIdType = libItem["ntkIdType"];
        var txtGeom = null;
        txtGeom = app.getGeomObjType(geomType, app.mapListners["TempLibItm"]);

        if (txtGeom == false) {
            return false;
        }
        if (eType == 'ROW') {
            centerLineGeom = txtGeom;
            var _path = app.gMapObj.ROWPath;
            if (_path.length > 2) {
                _path.push(_path[0]);
                txtGeom = app.getGeomFromlatLngArr(_path);
            }
            geomType = 'Polygon';
            bufferWidth = app.EntityAttributeDetails['strokeWidth'];
        }
        var modalClass = getPopUpModelClass(eType);
        pageTitleText = getMultilingualKeyForLoadModalDialog(pageTitleText);
        //app.showLibraryTools();
        ajaxReq('Main/ValidateEntityGeom', { geomType: geomType, enType: eType, txtGeom: txtGeom, isTemplate: isTemplate }, true,
            function (resp) {
                if (resp.status == "OK") {
                    //debugger;


                    app.showLibraryTools();
                    $('#LibraryTools a:nth-child(2)').off('click');
                    $('#LibraryTools a:nth-child(2)').on('click', function () {

                        var pageUrl = libItem["pageUrl"];
                        var isDirectSaveAllowed = (libItem["isDirectSave"].toUpperCase() == "TRUE");

                        if (isDirectSaveAllowed == true) {
                            var saveUrl = libItem["saveUrl"];
                            ajaxReq(saveUrl, { geom: txtGeom, enType: geomType, networkIdType: ntkIdType, isDirectSave: isDirectSaveAllowed }, true, function (resp) {
                                if (resp.status == "OK") {
                                    app.closeLibTools();
                                    app.loadLayerOnEntity();
                                    app.clearDraggableLibrary();
                                }
                                alert(resp.message);

                            }, true, true);
                        }
                        else {
                            app.closeLibTools();
                            popup.LoadModalDialog(app.ParentModel, pageUrl, { geom: txtGeom, enType: geomType, networkIdType: ntkIdType, centerLineGeom: centerLineGeom, buffer_width: bufferWidth }, pageTitleText, modalClass);
                        }
                    });

                }
                else {
                    alert(resp.error_message);
                    if (geomType == 'Polygon') {
                        google.maps.event.addListener(app.map, 'click', function (evt) {
                            app.drawPolygonEntity(evt.latLng, '');
                        });
                    }
                }
            }, true, true);
    }


