    this.ValidateXML = function (systemId) {

        var SystemIds = "";
        $('.chkSurvey[type="checkbox"]:checked').each(function () {
            //var SystemId = $(this).attr('id');
            var currentval = $(this).val();
            SystemIds += currentval + ",";
        });
        SystemIds = SystemIds.replace(/,\s*$/, "");
        let selectedCount = SystemIds.split(',').length;
        let maxLimit = $("#rowCount").val();
        if (selectedCount > maxLimit) {
            alert("Maximum " + maxLimit + " Splitter are allowed to validate!");
            return false;
        }
        if (SystemIds == "") {
            alert("Please select a splitter to validate!");
            return false;
        }



        ajaxReq('Main/ProcessSplitterData', { pEntityType: 'Splitter', pSystemId: SystemIds, pUserId: $("#hdnCurrentUserId").val(), p_subareaid: systemId }, true, function (resp) {
            if (resp.length > 0) {
                $("#btnGenerateXML").prop('disabled', false);
                var Msg = '<table border="1" class="alertgrid"><tr><td><b>Design Id<b/></td><td><b>Message<b/></td></tr>';

                $.each(resp, function (index, item) {
                    var stat = '';

                    if (item.status == true) {
                        stat = 'Success';
                        $("#btnGenerateXML").prop('disabled', false);
                    }
                    else {
                        stat = 'Failed';
                    }
                    $("#tblProcessedXMLDetails tr td").filter(function () {
                        if ($(this).text() == item.gis_design_id && item.path == '1') {
                            $(this).next().next().next().text(stat);
                            Msg += '<tr><td>' + item.gis_design_id + ' </td><td> ' + item.message + '';
                        }
                        if ($(this).text() == item.gis_design_id && item.path == '2') {
                            $(this).next().next().next().next().text(stat);
                            Msg += '</br> ' + item.message + '</td></tr>';
                        }
                    });
                });
                Msg += '</table>';
                alert("Following are the status of processed splitters:" + Msg);

                $.each(resp, function (index, item) {
                    $("#tblProcessedXMLDetails tbody tr").filter(function () {
                        if ($($(this).find('td')[1].innerHTML).text() == item.gis_design_id) {
                            var path1_stat = '';
                            var path2_stat = '';
                            path1_stat = $(this).find('td')[4].innerHTML;
                            path2_stat = $(this).find('td')[5].innerHTML
                            if (path1_stat == 'Failed' && path2_stat == 'Failed') {
                                $("#btnGenerateXML").prop('disabled', true);
                            }
                        }
                    });
                    if (item.logs != null) {
                        var link = document.createElement('a');
                        document.body.appendChild(link);
                        link.href = "Main/DownloadProcessSplitterDataLogs?pEntityType=" + "Splitter" + '&pSystemId=' + SystemIds + '&pUserId=' + $("#hdnCurrentUserId").val() + '&p_subareaid=' + systemId;
                        link.click();
                    }
                });
            }

        }, false, true);

    }





