    this.handleEntitySpecificEvents = function (systemId, entityType, geomType, networkId) {

        if (entityType == "Duct") {
            //;
            si.DuctType = "";
            ajaxReq('Library/getDuctDetails', { systemId: systemId }, false, function (resp) {

                if (resp.duct_category == "Microduct") {
                    $('#EntityAddMicroduct').hide();
                }
            });
        }


        if (entityType == "Trench") {
            //;
            si.TrenchType = "";
            ajaxReq('Library/getTrenchDetails', { systemId: systemId }, false, function (resp) {

                if (resp.trench_category == "Conduit") {
                    $('#EntityAddConduit').hide();
                }
            });
        }
        //app.showhideIcon('#EntityPITTemplate', false);
        //PENDING
        if (entityType == "Building") {
            app.showhideIcon("#EntityAreaPotential,#EntityBulkOperation,#EntityAreareport", false);
            ajaxReq('Library/IsBuildingApproved', { buildingId: systemId }, false,
                function (resp) {
                    if (resp.status == "OK") {
                        app.showhideIcon('#EntityAreaPotential,#EntityBulkOperation,#EntityAreareport', true);
                    }
                });
        }
        //if (entityType == 'FDB') {
        //    //$('#infoTB div.auditEntity').hide();
        //    $('#infoTB #EntityLocationEdit').hide();

        //} else
        if (entityType.toLowerCase() == 'subarea') {
            ajaxReq('Library/getSubAreaDetails', { systemId: systemId }, false,
                function (resp) {
                    if (resp.buildingId > 0) {
                        $('#EntityAddStructure').show();
                    }
                }, true, true);
        }
        else if (entityType == 'ROW') {
            ajaxReq('Library/getROWDetails', { systemId: systemId }, true, function (resp) {
                if (resp.row_type == 'PIT') {
                    $('#EntityPITTemplate').show();
                    $('#EntityAddPITEntity').show();
                    $("#EntityCancelPIT").hide();
                    if (resp.isROWApplied) { $('#EntityAddPITEntity').addClass('dvdisabled'); $('#EntityPITTemplate').addClass('dvdisabled'); }
                } else {
                    $('#EntityPITTemplate').hide();
                    $('#EntityAddPITEntity').hide();
                }
                if (resp.isassociated) {
                    $('#infoTB #EntityAssociationBOMBOQ').show();
                }
            }, true, true);


        } else if (entityType == 'PIT') {
            ajaxReq('Library/getROWDetailsByPIT', { systemId: systemId }, true, function (resp) {
                if (resp.isROWApplied) { $('#EntityLocationEdit,#EntityAddCloneEntity').addClass('dvdisabled'); }
            }, true, true);
        }
        else if (entityType == 'Structure') {
            if (geomType == 'Point') {
                $('#EntityConvertToPolygon').show();
            }
            if (geomType == 'Polygon') {
                $('#EntityConvertToPoint').show();
            }
        }
        //else if (entityType == 'SpliceClosure' || entityType == 'Manhole') {
        //    ajaxReq('Main/GetPointTypeEntityDetails', { pSystemId: systemId, pEntityType: entityType }, true, function (resp) {
        //        if (resp.is_buried == 'True') { $('#EntityItemAssociate').addClass('dvdisabled'); }
        //    }, true, true);
        //}
    }
    this.addStructure = function (_buildingId, systemId, entityType, geomType) {
        app.ShowEntityOnMap(systemId, entityType, geomType); $('#EntityDragStructure').show();
        var libItms = $('#EntityDragStructure');
        $(libItms).draggable({
            helper: 'clone', containment: '#map_canvas',
            stop: function (e) {
                var dragPT = new google.maps.Point(e.pageX - 11, e.pageY - 82);
                var libItem = this;
                // get layer Detail...
                var lyrDetail = getLayerDetail("Structure");
                var pageUrl = lyrDetail['layer_form_url'];
                var titleText = lyrDetail['layer_title'];
                var eType = lyrDetail['layer_name'];
                var gType = lyrDetail['geom_type'];
                var enImage = "Content/images/icons/lib/small/" + eType + ".png";
                var buildingId = _buildingId;//
                var saveUrl = lyrDetail['save_entity_url'];
                var isDirectSaveAllowed = (lyrDetail['is_direct_save'].toUpperCase() == "TRUE");
                var isTemplateRequired = (lyrDetail['is_template_required'].toUpperCase() == "TRUE");
                var ntkIdType = lyrDetail['network_id_type'];
                var pageTitleText = lyrDetail['layer_title'];
                app.clearTempNewEntity();
                LandBase.clearTempNewEntity();
                app.mapListners["TempLibItm"] = app.createMarker(app.getLatLongFromPT(dragPT), enImage);
                app.mapListners["TempLibItm"].setDraggable(true);
                app.mapListners["TempLibItm"].setMap(app.map);
                app.mapListners["mapListners"] = google.maps.event.addListener(app.mapListners["TempLibItm"], 'click', function () {
                    var txtGeom = app.getGeomObjType(gType, app.mapListners["TempLibItm"]);
                    var modalClass = getPopUpModelClass(eType);
                    ajaxReq('Main/ValidateEntityGeom', { geomType: gType, enType: eType, txtGeom: txtGeom, systemId: buildingId, isTemplate: isTemplateRequired }, false,
                        function (resp) {
                            if (resp.status == "OK") {
                                if (isDirectSaveAllowed == true) {
                                    ajaxReq(saveUrl, { geom: txtGeom, building_id: buildingId, networkIdType: ntkIdType, isDirectSave: true }, true, function (resp) {
                                        if (resp.status == "OK") {
                                            app.loadLayerOnEntity();
                                        }
                                        alert(resp.message);
                                    }, true, true);
                                }
                                else {
                                    popup.LoadModalDialog(app.ParentModel, pageUrl, { geom: txtGeom, building_id: buildingId, networkIdType: ntkIdType }, pageTitleText, modalClass);
                                }
                            }
                            else {
                                alert(resp.error_message);
                            }
                        }, true, true);
                });
            }
        }, true, true);

    }

