    this.associateEntity = function (systemId, entityType, networkId) {
        //;
        var modelClass = getPopUpModelClass('EntityAssociate');
        var parentgeomType = 'Point';
        if (entityType == 'Manhole' || entityType == 'Pole') {
            parentgeomType = 'Line';
        }
        var titleText = 'Associate ' + entityType;
        var formURL = 'Library/entityAssociation';
        popup.LoadModalDialog(app.ParentModel, formURL, { systemId: systemId, entityType: entityType, pgeomType: parentgeomType }, titleText, modelClass, function () {
            $('#divParentEntity').show();
            var ddlParentEntType = $('#ddlParentEntType');
            var ddlallParentEntity = $('#ddlallParentEntity');
            var parentEnType = $('#ddlParentEntType').val();
            if (entityType == 'Manhole' || entityType == 'Pole') {
                $('#divParentEntity').hide();
                if ($('#hdnAssociateSystemId').val() == 0) {
                    app.getEntityInBuffer(systemId, entityType, 'Cable', 'Line');
                }
                parentEnType = 'Cable';
            } else {
                ddlParentEntType.chosen().change(function (event) {
                    ddlallParentEntity.html('').append($("<option></option>").val('0').html('-Select-')).trigger("chosen:updated");;
                    var pEntityTye = $(this).val();
                    $('#spnEntity').text('Entity');
                    if (pEntityTye != '') {
                        $('#spnEntity').text(pEntityTye);
                        if ($('#hdnAssociateSystemId').val() == 0) {
                            app.getEntityInBuffer(systemId, entityType, pEntityTye, 'Point');
                        }
                    }
                });
            }

            attachUnAttachEvt($('#bttnAssociateEntity'), 'click', function () {
                if (entityType == 'Manhole' || entityType == 'Pole') {
                    parentEnType = 'Cable';
                } else { parentEnType = $('#ddlParentEntType').val() }
                var _data = {
                    system_id: $('#hdnAssociateSystemId').val(),
                    entity_system_id: ddlallParentEntity.val(),
                    entity_network_id: $('#ddlallParentEntity :selected').text(),
                    entity_type: parentEnType,
                    associated_system_id: systemId,
                    associated_network_id: networkId,
                    associated_entity_type: entityType,
                    geomType: parentgeomType
                };
                app.saveAssociation(_data);
            });
        });
    }
    this.getEntityInBuffer = function (systemId, entityType, pEntityTye, pgeomType) {
        var ddlallParentEntity = $('#ddlallParentEntity');
        ajaxReq('Library/getEntityInBuffer', { systemId: systemId, entityType: entityType, pEntityType: pEntityTye, pgeomType: pgeomType }, false, function (resp) {
            if (resp != null) {
                $.each(resp, function (data, value) {
                    ddlallParentEntity.append($("<option></option>").val(value.system_id).html(value.network_id));
                });
                ddlallParentEntity.trigger("chosen:updated");
            }
        }, true, false);
    }
