    function RefreshMessageByAjax(systemId) {
        console.log("RefreshMessage Called at" + new Date().toLocaleString());
        if (app.IsActionEnabled == true) {
            return;
        }
        ajaxReq('Library/RefreshMessage', { 'systemId': systemId }
            , false, function (resp) {
                app.IsActionEnabled = resp;
                if (app.IsActionEnabled == false) {
                    $('#EntityDownloadlog').addClass('roledisabled');
                    $("#EntityDownloadlog").attr('title', 'Logs will be available to download after successful bulk association! permission is denied! ');
                    $('#EntityDownloadlog').off('click').attr('onclick', 'return disabledItem(event)');
                    $('#EntityXMLDASHBOARD').addClass('roledisabled');
                    $("#EntityXMLDASHBOARD").attr('title', 'Please run the association tool first! permission is denied!');
                    $('#EntityXMLDASHBOARD').off('click').attr('onclick', 'return disabledItem(event)');
                }
                else {
                    $('#EntityDownloadlog').removeClass('roledisabled');
                    $("#EntityDownloadlog").attr('title', 'Download Bulk Association Log');
                    $('#EntityDownloadlog').off('click').attr('onclick', 'return false');
                    $('#EntityXMLDASHBOARD').removeClass('roledisabled');
                    $("#EntityXMLDASHBOARD").attr('title', 'XML DASHBOARD');
                    $('#EntityXMLDASHBOARD').off('click').attr('onclick', 'return false');
                }

            }, false, false);
    }
