    this.saveLineEntityAssociation = function () {

        var isChanged = false;
        var messageHTML = '<table border="1" class="alertgrid"><tr><td><b>Entity</b></td><td><b>Network Id<b/></td><td><b>Display Name</b></tr>';
        $('#tblLineEnLstInfo input:checkbox:not(:checked)').each(function () {
            var entityType = $(this).attr('entityType');
            if (entityType != undefined || entityType != null) { var layerTitle = getLayerTltle(entityType); }
            var systemId = $(this).attr('systemId');
            var networkId = $(this).attr('network-id');
            if ($('#hdnIsAssociate_' + entityType + '_' + systemId).val() == 'True') {
                isChanged = true;
                messageHTML += '<tr><td>' + layerTitle + ' </td><td> ' + networkId + '</td><td> ' + entityType + '</td></tr>';
            }
        });
        messageHTML += '</table>';
        if (isChanged) {

            confirm($.validator.format(MultilingualKey.SI_OSP_GBL_JQ_FRM_094, messageHTML), function () {
                $('#frmAssociateLineEntity').submit();
            });
        } else {
            $('#frmAssociateLineEntity').submit();
        }
    }
    this.checkAllAssociation = function () {
        if ($('#checkAllAssociation').is(':checked')) {
            if ($('#parent_multi_association').val() == 'False') {
                if ($('#tblLineEnLstInfo tbody :checkbox:not(".disabledcheckbox"):checked').length == 0) {
                    $('#tblLineEnLstInfo tbody input:checkbox:not(".disabledcheckbox"):first').prop("checked", true);
                } else {
                    $('#tblLineEnLstInfo tbody :checkbox:not(".disabledcheckbox")').filter('[data-geom-type="Line"]').prop("checked", true);
                    $('#tblLineEnLstInfo tbody :checkbox:not(".disabledcheckbox")').filter('[data-geom-type="Point"][entitytype="SpliceClosure"]').prop("checked", true);
                }
            } else {
                $('#tblLineEnLstInfo input:checkbox:not(".disabledcheckbox")').prop("checked", true);
            }
        }
        else {
            $('#tblLineEnLstInfo input:checkbox:not(".disabledcheckbox")').prop("checked", false);
        }

    }
