    this.convertSCtoCDB = function (_data) {
        ////;
        //ajaxReq('main/getGeometryDetail', { systemId: _data.systemId, geomType: 'Point', entityType: _data.entityType }, true, function (resp) {
        ajaxReq('Main/GetPointTypeEntityDetails', { pSystemId: _data.systemId, pEntityType: _data.entityType }, true, function (resp) {
            if (resp.geom != null || resp.geom != undefined) {
                ajaxReq('Main/ValidateItemSpecificaton', { no_of_ports: resp.no_of_ports, entityType: 'CDB', vendor_id: resp.vendor_id }, true, function (result) {
                    if (result.length > 0) {
                        // var func = function () {
                        ajaxReq('Main/ValidateEntityGeom', { geomType: 'Point', enType: 'CDB', txtGeom: resp.geom, isTemplate: false, subEntityType: '' }, true,
                            function (res) {

                                if (res.status == "OK") {
                                    confirm($.validator.format(MultilingualKey.SI_OSP_CDB_JQ_FRM_002, getLayerTltle(_data.entityType), getLayerTltle('CDB')), function () {

                                        popup.LoadModalDialog('Parent', 'Library/AddCDB', { networkIdType: 'M', no_of_ports: resp.no_of_ports, vendor_id: resp.vendor_id, geom: resp.geom, isConvert: true, sc_system_id: resp.system_id }, 'CDB', 'modal-lg');

                                    });

                                }
                                else {
                                    alert(res.error_message);

                                }
                            }, true, true);
                    }
                    else {
                        // alert('Specifications are not compatible to convert!');
                        var Msg = '<table border="1" class="alertgrid"><tr><td><b>Vendor Name</b></td><td><b>Total Ports<b/></td></tr>';
                        Msg += '<tr><td>' + resp.vendor_name + ' </td><td> ' + resp.no_of_ports + '</td></tr>';
                        Msg += '</table>';

                        alert($.validator.format(getMultilingualStringValue(MultilingualKey.SI_OSP_CDB_JQ_FRM_001), Msg));

                    }
                });


            }
            else {
                alert(resp.message);

            }
        });

    }

