    this.editLandbaseGeomEntity = function (_systmId, _eType, geomType, jResp) {
        //;
        app.clearEditObj();
        try {
            if (jResp.status == "OK") {
                if ($('.infoSwitchLandBase').hasClass('activeToolBar'))
                    $('.infoSwitchLandBase').removeClass('activeToolBar');
                app.removeEventListnrs('click');

                $('#EntitySave').show();
                var latLngArr = app.getLatLongArr(jResp.result.sp_geometry);
                app.lineEntityOldGeom = latLngArr;
                switch (geomType) {
                    case 'Point':
                        app.gMapObj.infoEntity = app.createMarker(latLngArr[0], '');
                        app.gMapObj.infoEntity.setDraggable(true);
                        break;
                    case 'Line':
                        {
                            //if (_eType == 'Road') {
                            if (jResp.result.radious > 0) {
                                var width = parseFloat(jResp.result.radious);
                                var centerLineArray = app.getLatLongArr(jResp.result.sp_geometry);
                                app.createLineBuffer(centerLineArray, width);
                                app.gMapObj.infoEntity = app.createLine(centerLineArray);
                                app.gMapObj.infoEntity.setEditable(true);
                                app.gMapObj.infoEntity.strokeColor = '#FF0000';
                                app.gMapObj.infoEntity.strokeOpacity = 0.6;
                                app.gMapObj.infoEntity.strokeWeight = '2';
                                app.bindROWEditEvent(width);
                                google.maps.event.addListener(app.map, 'click', function (evt) {
                                    centerLineArray = app.gMapObj.infoEntity.getPath().getArray();
                                    centerLineArray.push(evt.latLng);
                                    app.gMapObj.infoEntity.setPath(centerLineArray, width);
                                    app.createLineBuffer(centerLineArray, width);
                                    app.bindROWEditEvent(width);
                                });
                                break;
                            } else {

                                app.gMapObj.lineflag = true;
                                app.gMapObj.lineEditflag = true;
                                app.gMapObj.infoEntity = app.createLine(latLngArr);
                                app.gMapObj.infoEntity.setEditable(true);
                                app.initialClickForEditLine();
                                app.initializeTPArrForEdit(_systmId, _eType, 'Line');

                                app.EntityAttributeDetails["enType"] = jResp.result.entity_type;
                                app.gMapObj.infoEntity.strokeColor = '#FF0000';
                                app.gMapObj.infoEntity.strokeOpacity = 0.6;
                                app.gMapObj.infoEntity.strokeWeight = '2';
                                break;
                            }
                        }
                    case 'Polygon':

                        {


                            latLngArr.pop();
                            app.gMapObj.infoEntity = app.createPolygon(latLngArr);
                            app.gMapObj.infoEntity.setEditable(true);
                            app.gMapObj.infoEntity.setDraggable(false);
                            app.bindGeomEvent(app.gMapObj.infoEntity, 'Polygon');
                            break;

                        }
                }
                app.gMapObj.infoEntity.setMap(app.map);
                // }

            }
            else {
                alert(jResp.message);
            }
        }
        catch (ex) {

        }
    }
