    this.setMapType = function (mapType, curobj) {
        //$(obj).find('img').addClass('');
        app.mapTypeId = mapType;
        var mapTypeID = google.maps.MapTypeId.ROADMAP;
        switch (mapType) {
            case 'roadmap':
                mapTypeID = google.maps.MapTypeId.ROADMAP;
                break;
            case 'terrain':
                mapTypeID = google.maps.MapTypeId.TERRAIN;
                break;
            case 'satellite':
                mapTypeID = google.maps.MapTypeId.SATELLITE;
                break;
            case 'hybrid':
                mapTypeID = google.maps.MapTypeId.HYBRID;
                break;
            case 'openstreetmap':
                app.map.mapTypes.set("OSM", new google.maps.ImageMapType({
                    getTileUrl: function (coord, zoom) {
                        return "http://tile.openstreetmap.org/" + zoom + "/" + coord.x + "/" + coord.y + ".png";
                    },

                    tileSize: new google.maps.Size(256, 256),
                    name: "OpenStreetMap",
                    maxZoom: 18
                }));
                app.map.setMapTypeId("OSM")
                return;
            case 'renderUserBaseLayers':
                // let curobj = $('#chk_wms_2');
                if ($(curobj).attr('data-layer-type') === "WMTS") {
                    app.map.mapTypes.set($(curobj).attr('data-layer'), new google.maps.ImageMapType({
                        getTileUrl: function (coord, zoom) {
                            let l_url = $(curobj).attr('data-url');
                            let l_key = $(curobj).attr('data-key');
                            let l_layer = $(curobj).attr('data-layer');
                            let l_style = $(curobj).attr('data-style') == "" || $(curobj).attr('data-style') == undefined ? 'default' : $(curobj).attr('data-style');
                            let l_TileMatrixSet = $(curobj).attr('data-TileMatrixSet') == "" || $(curobj).attr('data-TileMatrixSet') == undefined ? 'GoogleCRS84QuadExt:epsg:4326' : $(curobj).attr('data-TileMatrixSet');
                            let tileurl = l_url + "/" + l_key + "/wmts/" + l_layer + "/" + l_style + "/" + l_TileMatrixSet + "/" + zoom + "/" + coord.y + "/" + coord.x + ".png";
                            return tileurl;
                        },
                        tileSize: new google.maps.Size(256, 256),
                        name: $(curobj).attr('data-layer'),
                        maxZoom: 21,
                        transparent: true,
                        opacity: 0.99
                    }));
                    app.map.setMapTypeId($(curobj).attr('data-layer'));
                }
                return;
        }
        app.map.setMapTypeId(mapTypeID);
        // app.playSound('Apply');
    }

    this.showMapLyr = function (lyrName) {
        app.mapTypeId = lyrName;
        if (!app.gMapObj)
            app.gMapObj = {};

        if (app.gMapObj[lyrName]) {
            app.gMapObj[lyrName].setMap(null);
            app.gMapObj[lyrName] = undefined;
            return;
        }

        switch (lyrName) {
            case 'Weather':
                app.gMapObj[lyrName] = new google.maps.weather.WeatherLayer();
                app.map.setZoom(12);
                break;
            case 'Cloud':
                app.gMapObj[lyrName] = new google.maps.weather.CloudLayer();
                app.map.setZoom(6);
                break;
            case 'Panoramio':
                app.gMapObj[lyrName] = new google.maps.panoramio.PanoramioLayer();
                break;
            case 'Traffic':
                app.gMapObj[lyrName] = new google.maps.TrafficLayer();
                break;
        }

        if (app.gMapObj[lyrName])
            app.gMapObj[lyrName].setMap(app.map);
    }

    this.removeAddonLyr = function (lyrName) {
        if (app.gMapObj) {
            if (app.gMapObj[lyrName])
                app.gMapObj[lyrName].setMap(null);
        }
    }

