    this.checkCblTotalCore = function () {
        var ddlFiberCount = $("#fiberCountIn_chosen").children('a').text().trim();
        var tubeCount = parseInt($('#no_of_tube').val());
        var corePerTubeCount = parseInt($('#no_of_core_per_tube').val());

        if (ddlFiberCount == "Select Fiber Count") {
            alert(MultilingualKey.SI_OSP_GBL_JQ_FRM_039);
            return false;
        }
        else {
            var totalCount = tubeCount * corePerTubeCount;
            ddlFiberCount = ddlFiberCount.split(' ');
            if (totalCount != ddlFiberCount[0]) {
                alert(MultilingualKey.SI_OSP_GBL_JQ_FRM_012);
                return false;
            }
        }
    }
