    this.IsTerminationPointExist = function (geom, bufferMtr, enType, chkPointType, actionMode) {
        if (geom != null)
            var entityType = app.EntityAttributeDetails["enType"];
        ajaxReq('Library/TerminationEntity', { txtGeom: geom, entityType: entityType, mtrBuffer: parseInt(bufferMtr) }, false,
            function (resp) {
                //;
                $('#searchTpoint #lblInformation').text('Termination Points ');
                if (resp.status == "OK" && resp.results != null) {
                    var ulTP = $(app.DE.UlTerminationPoint);
                    //ulTP.empty().hide();
                    $('#searchTpoint').hide();
                    ulTP.html('');
                    if (resp.results.length > 7) { $('#divSearchtTpoint').show(); } else { $('#divSearchtTpoint').hide(); }
                    if (resp.results.length >= 1) {
                        ;
                        $.each(resp.results, function (indx, item) {
                            //;
                            ulTP.append('<li data-network-id="' + item["network_id"] + '"><a  onclick="si.clickLstTerminationPoint(\'' + item["system_id"] + '\',\'' + item["network_id"] + '\',\'' + item["entity_name"] + '\',\'' + item["latlng"] + '\',\'' + enType + '\',\'' + chkPointType + '\',\'' + actionMode + '\',\'' + item["display_name"] + '\');" href="#">' + item["display_name"] + '</a></li>');
                        });

                        //ulTP.css('left', app.currentMousePos.x);
                        $('#searchTpoint').css('left', app.currentMousePos.x);

                        if (app.currentMousePos.y + ulTP.height() > $(window).height()) {
                            //ulTP.css('top', (app.currentMousePos.y - (app.currentMousePos.y + ulTP.height() - $(window).height() + 25)));
                            $('#searchTpoint').css('top', app.currentMousePos.y - (app.currentMousePos.y + ulTP.height() - $(window).height() + 25));

                        }
                        else {
                            //ulTP.css('top', app.currentMousePos.y);
                            $('#searchTpoint').css('top', (app.currentMousePos.y));
                        }

                        //ulTP.show();
                        $('#searchTpoint').show();

                    }
                    else {
                        if (enType == 'other' && app.lstTerminationPoint.length != 0) {
                            $.map(app.lstTerminationPoint, function (value, index) {
                                if (value.termination_type == chkPointType) {
                                    app.RemoveTerminationPoint(index);
                                }
                            });
                        }
                        alert(MultilingualKey.SI_OSP_GBL_JQ_GBL_001);
                    }
                }
            }, true, true);
    }

    this.IsCreateLineExist = function () {
        ;
        if (app.lstTerminationPoint.length > 0) {
            var lineArrayLst = app.mapListners["TempLibItm"].getPath().getArray();
            var lenLineArr = lineArrayLst.length;
            if (lenLineArr > 1) {
                var startLatLng = lineArrayLst[0].lng() + ' ' + lineArrayLst[0].lat();
                var endLatLng = lineArrayLst[lenLineArr - 1].lng() + ' ' + lineArrayLst[lenLineArr - 1].lat();
                var startflag = false; var endflag = false;
                var startIndex = 0; var endIndex = 0;
                $.map(app.lstTerminationPoint, function (value, index) {

                    if (value.termination_type == 'start')
                        if (value.lnglat != startLatLng) {
                            startflag = true; startIndex = index;
                        }

                    if (value.termination_type == 'end')
                        if (value.lnglat != endLatLng) {
                            endflag = true; endIndex = index;
                        }

                });
                if (startflag) {
                    $(app.DE.tblTerminationPoint + " tbody tr:eq(" + startIndex + ")").remove();
                    app.lstTerminationPoint.splice(startIndex, 1);
                    app.addTPRowCount(app.DE.tblTerminationPoint);
                }
                if (endflag) {
                    $(app.DE.tblTerminationPoint + " tbody tr:eq(" + endIndex + ")").remove();
                    app.lstTerminationPoint.splice(endIndex, 1);
                    app.addTPRowCount(app.DE.tblTerminationPoint);
                }
            }
        }
    }

