    this.initializeTPArrForEdit = function (_systmId, _eType, _geomType) {

        app.editExistTerminationPoint = [];
        app.oldTerminationPoint = [];
        ajaxReq('Main/getExisitingTPDetails', { systemId: _systmId, eType: _eType }, false, function (resp) {
            if (resp != undefined && resp.length > 0)
                $.each(resp, function (index, item) {
                    app.editExistTerminationPoint.push({ entity_type: item.entity_type, mode: item.mode, network_id: item.network_id, system_id: item.system_id, isChanged: false });
                });
            // app.editExistTerminationPoint = resp;
            $.each(resp, function (index, item) {
                app.oldTerminationPoint.push({ entity_type: item.entity_type, mode: item.mode, network_id: item.network_id, system_id: item.system_id });
            });
            app.lstTerminationPoint = [];
        }, true, true);
    }
    this.initialClickForEditLine = function () {

        google.maps.event.addListener(app.gMapObj.infoEntity, 'rightclick', function (event) {

            if (event.vertex == undefined) {
                return;
            } else {
                app.removeNode(app.gMapObj.infoEntity, event.vertex);
            }
            ShowLineLength();
        });
        google.maps.event.addListener(app.gMapObj.infoEntity.getPath(), 'set_at', function (indx) {
            var newPath = app.gMapObj.infoEntity.getPath();
            app.gMapObj.libPath = newPath.getArray();
            ShowLineLength();
        });

        google.maps.event.addListener(app.gMapObj.infoEntity.getPath(), 'insert_at', function (indx) {
            var newPath = app.gMapObj.infoEntity.getPath();
            app.gMapObj.libPath = newPath.getArray();
            ShowLineLength();
        });
        app.mapListners["mapListners"] = google.maps.event.addListener(app.gMapObj.infoEntity, 'click', function (evt) {


            var selectPoint = '';
            selectPoint = app.roundNumber(evt.latLng.lng(), 6) + ' ' + app.roundNumber(evt.latLng.lat(), 6);
            var _zoom = app.map.getZoom();

            var lineArrayLst = app.gMapObj.infoEntity.getPath().getArray();
            var lenLineArr = lineArrayLst.length;
            if (lenLineArr < 1) {
                alert(MultilingualKey.SI_OSP_GBL_JQ_FRM_032);
                return false;
            }
            else {
                ;
                var startPoint = app.roundNumber(lineArrayLst[0].lng(), 6) + ' ' + app.roundNumber(lineArrayLst[0].lat(), 6);
                var endPoint = app.roundNumber(lineArrayLst[lenLineArr - 1].lng(), 6) + ' ' + app.roundNumber(lineArrayLst[lenLineArr - 1].lat(), 6);
                if (startPoint == selectPoint || endPoint == selectPoint) {
                    var chkPointType = (startPoint == selectPoint) ? 'start' : 'end';

                    app.IsTerminationPointExist(selectPoint, getMeterDistanceFromZoom(_zoom), 'other', chkPointType, 'edit_' + chkPointType);
                }
            }
        });

    }

