    this.CloneGeomEntity = function (geomType, jResp, systemId, _eType) {

        app.clearEditObj();
        try {
            if (jResp.status == "OK") {
                if ($('.infoSwitch').hasClass('activeToolBar'))
                    $('.infoSwitch').removeClass('activeToolBar');
                app.removeEventListnrs('click');
                $('#EntitySaveClone').hide();
                //showDiv('#infoTB .saveClone');
                var latLngArr = null;
                if (geomType == 'Polygon' && _eType == 'Structure') {
                    geomType = 'Point';
                    latLngArr = app.getLatLongArr(jResp.results.sp_centroid);
                } else {
                    latLngArr = app.getLatLongArr(jResp.results.sp_geometry);
                }
                app.lineEntityOldGeom = latLngArr;
                switch (geomType) {
                    case 'Point':
                        app.gMapObj.infoEntity = app.createMarker(latLngArr[0], 'Content/images/icons/lib/small/' + jResp.results.entity_type + '.png');
                        app.gMapObj.infoEntity.setDraggable(true);
                        app.gMapObj.infoEntity.setMap(app.map);
                        app.mapListners["mapListners"] = google.maps.event.addListener(app.gMapObj.infoEntity, 'click', function (LatLong) {

                            var txtGeom = app.roundNumber(LatLong.latLng.lng(), 6) + ' ' + app.roundNumber(LatLong.latLng.lat(), 6);

                            var postData = { refId: systemId, entityName: _eType, geomType: geomType, geom: txtGeom };
                            ajaxReq('Library/SaveCloneEntity', postData, true, function (resp) {
                                if (resp.status == "OK") {
                                    if (app.gMapObj.infoEntity) {
                                        {
                                            if (app.gMapObj.infoEntity.map)
                                                app.gMapObj.infoEntity.setMap(null);
                                            app.gMapObj.infoEntity = null;
                                        }
                                    }
                                    app.loadLayerOnEntity();
                                }
                                //app.gMapObj.infoEntity.setMap(null);
                                //app.gMapObj.infoEntity = null;
                                app.clearTempNewEntity();
                                LandBase.clearTempNewEntity();
                                $('#EntityCancel').hide();
                                alert(resp.message);
                            }, true, true);


                        });
                        break;

                }
                //app.gMapObj.infoEntity.setMap(app.map);


            }
            else {
                alert(jResp.message);
            }
        }
        catch (ex) {
        }
    }
    this.getTextGeom = function (entityObj) {

        var geomText = '';
        $.each(entityObj, function (key, value) { geomText += value.getPosition().lat() + ' ' + value.getPosition().lng() + ','; })
        return geomText;
    }
    this.getlnglatGeom = function (entityObj) {

        var geomText = '';
        $.each(entityObj, function (key, value) { geomText += value.getPosition().lng() + ' ' + value.getPosition().lat() + ','; })
        return geomText;
    }
    this.getCircleTextGeom = function (entityObj) {
        var geomText = '';
        $.each(entityObj, function (key, value) {
            geomText += value.getCenter().lat() + ' ' + value.getCenter().lng() + ',';
        })
        return geomText;
    }
