    this.removeShaftRow = function () {

        var row = app.shaftLstInfoD.selectedRow;
        var removeRowindex = row.index();
        row.remove();
        var shaftTblbody = $(app.DE.ShaftInfoTable + ' tbody tr');
        var rowCount = shaftTblbody.length;
        var shaftVal = rowCount;
        $("#no_of_shaft").val(shaftVal);
        $("#spTotalShaft").text(shaftVal);



        shaftTblbody.each(function (i, val) {
            if (removeRowindex <= i) {
                $(this).find("input,select").each(function (n, nval) {

                    if ($(this).attr('name') != undefined)
                        $(this).attr('name', $(this).attr('name').replace(/\[\d+\]/, "[" + (i) + "]"));

                    if ($(this).attr('id') != undefined)
                        $(this).attr('id', $(this).attr('id').replace(/\_\d+\_/, "_" + (i) + "_"));

                });
            }
        });
    }

