    this.removeFloorRow = function () {

        var row = app.floorLstInfoD.selectedRow;
        var removeRowindex = row.index();
        var count1 = removeRowindex;

        //$.each(row.nextAll(), function (i, item) {
        //    var floorName=$($(item).children()[0]).children('input').val()
        //    if (floorName.split('_').length > 1 && floorName.split('_')[1] != '' && !isNaN(floorName.split('_')[1])) {                                               
        //            if (floorName.toLowerCase().indexOf('floor_') == 0) {
        //                count1++;
        //                if (!isNaN(floorName.toLowerCase().split('floor_')[1])) {
        //                    $($(item).children()[0]).children('input').val('floor_' + count1);
        //                }
        //            }                              
        //    }
        //})

        var currentFloor = $(row).children('td:first').children();
        var count = 1;
        $.each($('#tblFloorLstInfo tbody tr'), function (i, item) {
            var child = ($(this).children('td')[0]);
            if (($(child).children().attr('id') == currentFloor.attr('id'))) {
                var floorName = currentFloor.val();
                if (floorName.split('_').length > 1 && floorName.split('_')[1] != '' && !isNaN(floorName.split('_')[1])) {
                    var count1 = parseInt(floorName.split('_')[1]) - 1;
                    $.each(currentFloor.parent('td').parent().nextAll(), function (j, itm) {
                        var child2 = ($(this).children('td')[0]);
                        if ($(child2).children().val().toLowerCase().indexOf('floor_') == 0) {
                            count1++;
                            if (!isNaN($(child2).children().val().toLowerCase().split('floor_')[1])) {
                                $(child2).children().val('floor_' + count1);
                            }
                        }
                    })
                    return false;
                }
                else {
                    var count = 0;
                    $.each(currentFloor.parent().parent().prevAll(), function (indx, item) {

                        var floorName = $(item.children[0]).children().val().toLowerCase();
                        if (!isNaN(floorName.split('floor_')[1])) {
                            indx = indx + 1;
                            count = count + parseInt(floorName.split('floor_')[1]) + indx;
                            $.each(currentFloor.parent('td').parent().nextAll(), function (j, itm) {
                                var child2 = ($(this).children('td')[0]);
                                if ($(child2).children().val().toLowerCase().indexOf('floor_') == 0) {

                                    if (!isNaN($(child2).children().val().toLowerCase().split('floor_')[1])) {
                                        $(child2).children().val('floor_' + count);
                                    }
                                    count++;
                                }
                            })
                            return false;
                        }
                        //count = count + 1;
                    })
                }
            }
            else {
                // i = i + 1;                  
                //if ($(child).children().val().indexOf('floor_') == 0) {
                //    $(child).children().val('floor_' + i); count++;
                //}
            }

        })

        row.remove();
        var floorTblbody = $(app.DE.FloorInfoTable + ' tbody tr');
        var rowCount = floorTblbody.length;
        var floorVal = rowCount;
        $("#no_of_floor").val(floorVal);
        $("#spTotalFloor").text(floorVal);



        floorTblbody.each(function (i, val) {
            if (removeRowindex <= i) {
                $(this).find("input,select").each(function (n, nval) {

                    if ($(this).attr('name') != undefined)
                        $(this).attr('name', $(this).attr('name').replace(/\[\d+\]/, "[" + (i) + "]"));

                    if ($(this).attr('id') != undefined)
                        $(this).attr('id', $(this).attr('id').replace(/\_\d+\_/, "_" + (i) + "_"));

                });
            }
        });


        //var unitValue = 0;
        //$.each($('#tblFloorLstInfo tbody tr .FloorUnit'), function () {
        //    var no_of_units = parseInt($(this).val());
        //    unitValue = unitValue + no_of_units;

        //});
        //$('#no_of_flat').val(unitValue);
    }

