    this.getNewDuctDetails = function () {
        var splitductsystemid = $("input[name='Duct']:checked").attr('s_id');
        $('#split_duct_system_id').val(splitductsystemid);
        var splitEnityNetworkId = $('#split_entity_networkId').val();
        var splitEntitytype = $('#split_entity_type').val();
        var splitEntitySystem_id = $('#split_entity_system_id').val();

        var ductValue = $("input[name='Duct']:checked").val();

        if (ductValue == undefined) {
            alert(MultilingualKey.SI_OSP_DUC_JQ_FRM_002);
        }
        else {
            ajaxReq('Library/getNearDuctDetail', { split_entity_system_id: splitEntitySystem_id, split_entity_type: splitEntitytype, splitEnityNetworkId: splitEnityNetworkId, split_duct_system_id: splitductsystemid }, false, function (resp) {
                if (resp.status == 'OK') {
                    $('#duct_one_calculated_length').val(resp.result.duct1CalculatedLength);
                    $('#duct_two_calculated_length').val(resp.result.duct2CalculatedLength);
                    $('#duct_one_measured_length').val(resp.result.duct1Length);
                    $('#duct_two_measured_length').val(resp.result.duct2Length);

                    var parentduct = resp.result.parentDuctNetworkId;
                    //if (parentduct.split('_').length <= 10) {                        		
                    var firstductNetworkId = parentduct + '_01';
                    $('#duct_one_network_id').val(firstductNetworkId);
                    $('#duct_one_name').val(firstductNetworkId);
                    $('#duct_one_a_location').val(resp.result.duct_one_a_location);
                    $('#duct_one_b_location').val(resp.result.duct_one_b_location);

                    var secondductNetworkId = parentduct + '_02';
                    $('#duct_two_network_id').val(secondductNetworkId);
                    $('#duct_two_name').val(secondductNetworkId);
                    $('#duct_two_a_location').val(resp.result.duct_two_a_location);
                    $('#duct_two_b_location').val(resp.result.duct_two_b_location);

                    $('#duct_one_name').rules('remove', 'required');
                    $('#duct_one_name').valid();
                    $('#duct_one_calculated_length').rules('remove', 'required');
                    $('#duct_one_calculated_length').valid();
                    $('#duct_one_measured_length').rules('remove', 'required');
                    $('#duct_one_measured_length').valid();
                    $('#duct_two_name').rules('remove', 'required');
                    $('#duct_two_name').valid();
                    $('#duct_two_calculated_length').rules('remove', 'required');
                    $('#duct_two_calculated_length').valid();
                    $('#duct_two_measured_length').rules('remove', 'required');
                    $('#duct_two_measured_length').valid();

                }
                else {

                    alert(resp.message);
                }
            }, true, false);
        }
    }

