    this.getNewCableDetails = function () {
        var splitcablesystemid = $("input[name='Cable']:checked").attr('s_id');
        $('#split_cable_system_id').val(splitcablesystemid);
        var splitEnityNetworkId = $('#split_entity_networkId').val();
        var splitEntitytype = $('#split_entity_type').val();
        var splitEntitySystem_id = $('#split_entity_system_id').val();
        var splitEntityCore = $('#splitCore').val();

        var CableValue = $("input[name='Cable']:checked").val();
        var displayname = $("input[name='Cable']:checked").attr('cbl_display_name');
        if (CableValue == undefined) {
            alert(MultilingualKey.SI_OSP_CAB_JQ_FRM_006);
        }
        else {
            ajaxReq('Library/getNearCableDetail', { split_entity_system_id: splitEntitySystem_id, split_entity_type: splitEntitytype, split_cable_system_id: splitcablesystemid, Split_entity_Core: splitEntityCore }, false, function (resp) {
                if (resp.status == 'OK') {
                    if ($('#cable_one_start_reading').length > 0 && $('#cable_one_end_reading').length > 0) {
                        $('#cable_one_start_reading,#cable_one_end_reading').keyup(function () {
                            app.calculateCableLength('', '' + resp.result.network_status + '', 'cable_one_start_reading', 'cable_one_end_reading', 'cable_one_calculated_length')
                        });
                        $('#cable_two_start_reading,#cable_two_end_reading').keyup(function () {
                            app.calculateCableLength('', '' + resp.result.network_status + '', 'cable_two_start_reading', 'cable_two_end_reading', 'cable_two_calculated_length')
                        });
                        if (resp.result.network_status == 'P' || resp.result.network_status == 'A') {
                            $('#cable_one_start_reading,#cable_one_end_reading,#cable_one_calculated_length').val(0);
                            $('#cable_two_start_reading,#cable_two_end_reading,#cable_two_calculated_length').val(0);
                        } else {
                            $('#cable_one_start_reading,#cable_one_end_reading').attr('required', true).val(null);
                            $('#cable_two_start_reading,#cable_two_end_reading').attr('required', true).val(null);
                            $('#icnsstartreading,#icnsendreading,#icnfstartreading,#icnfendreading').html('*');
                        }
                    } else {
                        $('#cable_one_calculated_length').val(resp.result.cable1CalculatedLength);
                        $('#cable_two_calculated_length').val(resp.result.cable2CalculatedLength);
                    }


                    $('#cable_one_measured_length').val(resp.result.cable1Length);
                    $('#cable_two_measured_length').val(resp.result.cable2Length);

                    $('#cable_one_end_reading,#cable_one_calculated_length').val(resp.result.cable1Length != null && resp.result.cable1Length != 0 ? resp.result.cable1Length : 0);
                    $('#cable_two_end_reading,#cable_two_calculated_length').val(resp.result.cable2Length != null && resp.result.cable2Length != 0 ? resp.result.cable2Length : 0);

                    var parentCable = resp.result.parentCableNetworkId;

                    var firstCableNetworkId = parentCable + '_01';
                    $('#cable_one_network_id').val(firstCableNetworkId);
                    /* $('#cable_one_name').val(firstCableNetworkId);*/
                    $('#cable_one_name').val(displayname);
                    $('#cable_one_a_location').val(resp.result.cable1_a_location);
                    $('#cable_one_b_location').val(splitEnityNetworkId);

                    var secondCableNetworkId = parentCable + '_02';
                    $('#cable_two_network_id').val(secondCableNetworkId);
                    /* $('#cable_two_name').val(secondCableNetworkId);*/
                    $('#cable_two_name').val(displayname);
                    $('#cable_two_a_location').val(splitEnityNetworkId);
                    $('#cable_two_b_location').val(resp.result.cable2_b_location);

                    $('#cable_one_name').rules('remove', 'required');
                    $('#cable_one_name').valid();
                    $('#cable_one_calculated_length').rules('remove', 'required');
                    $('#cable_one_calculated_length').valid();
                    $('#cable_one_measured_length').rules('remove', 'required');
                    $('#cable_one_measured_length').valid();
                    $('#cable_two_name').rules('remove', 'required');
                    $('#cable_two_name').valid();
                    $('#cable_two_calculated_length').rules('remove', 'required');
                    $('#cable_two_calculated_length').valid();
                    $('#cable_two_measured_length').rules('remove', 'required');
                    $('#cable_two_measured_length').valid();
                }
                else {

                    alert(resp.message);
                }
            }, true, false);
        }
    }

    this.updateStructure = function () {

        var validForm = app.isFormValid();
        $('#hdnStructureTab').val('GISInfoTab');
        if (!(validForm.isvalid)) {
            if (validForm.parentId == 'tblShaftLstInfo') {
                $('#linkShaftTab').trigger("click");
            } else if (validForm.parentId == 'tblFloorLstInfo') {
                $('#linkFloorTab').trigger("click");
            }
            return false;
        }
        var noOfUnits = $('#no_of_flat').val();

        var unitValue = 0;
        var isValidUnit = true;
        $.each($('#tblFloorLstInfo tbody tr .FloorUnit'), function () {
            var no_of_units = parseInt($(this).val());
            unitValue = unitValue + no_of_units;

            var totalPlacedUnits = $(this).attr('data-total-placed-unit');
            if (no_of_units < totalPlacedUnits) {
                isValidUnit = false;
                return false;
            }
        });
        if (noOfUnits != '' && !isValidUnit) {
            alert(MultilingualKey.SI_OSP_STR_JQ_FRM_004)
            $('#linkGisInfoTab').trigger("click");
            $('#no_of_flat').addClass('NotValid');
            return false;
        }
        if (noOfUnits != '' && noOfUnits < unitValue) {
            alert(MultilingualKey.SI_OSP_STR_JQ_FRM_005);
            $('#linkGisInfoTab').trigger("click");
            $('#no_of_flat').addClass('NotValid');
            return false;
        }

        if (parseInt(app.getTotalUnits()) < parseInt($('#no_of_flat').val()) || parseInt(app.getTotalUnits()) > parseInt($('#no_of_flat').val())) {

            alert(getMultilingualStringValue(MultilingualKey.SI_OSP_STR_JQ_FRM_006));

            //$('#linkGisInfoTab').trigger("click");
            //$('#no_of_flat').addClass('NotValid');
            return false;
        }

        //$.each($('#tblFloorLstInfo tbody tr .FloorUnit'), function () {             
        //    var totalPlacedUnits = $(this).attr('data-total-placed-unit');
        //    var no_of_units = $(this).val();
        //    if (no_of_units < totalPlacedUnits) {
        //        isValidUnit = false;
        //        $(this).addClass('NotValid');
        //        return false;
        //    }            
        //});

        var messageHTML = '<br/><table class="shaftLstInfo" cellpadding="0" cellspacing="0" style="font-size:smaller;text-align: center;"><thead><tr><th>' + MultilingualKey.SI_OSP_STR_JQ_FRM_010 + '</th></tr></thead><tbody>';
        var shaftName = '';
        var allShaftId = '';
        $('[withRiser^=True]').each(function () {
            var shaftId = $(this).attr('shaftId');
            if ($(this).is(':checked') == false) {
                shaftName += $('#shaft_' + shaftId).val() + ',';
                messageHTML += '<tr><td>' + $('#shaft_' + shaftId).val() + '</td></tr>';
            }
            allShaftId += shaftId + ',';
        });
        messageHTML += '</tbody></table>';
        $('#prevShaftWithoutRiser').val(allShaftId);
        if (shaftName != '') {
            //MultilingualKey.SI_OSP_STR_JQ_FRM_008 + ' ' + messageHTML + ' ' + MultilingualKey.SI_OSP_STR_GBL_GBL_001

            confirm($.validator.format(MultilingualKey.SI_OSP_STR_JQ_FRM_008, messageHTML), function () {
                $('#frmStructureEntity').submit();
            });
        } else { $('#frmStructureEntity').submit(); }
    }
    this.isFormValid = function isFormValid() {
        var isvalid = true;
        var parentId = '';
        $(app.DE.ShaftNFloorInut).each(function () {
            if ($(this).val().replace(/ /g, '') == '') {
                $(this).addClass('NotValid');
                isvalid = false;
                parentId = $(this).parent().parent().parent().parent().attr('id');
                return false;
            }
        })
        return { isvalid: isvalid, parentId: parentId };
    }
