    this.convertToAsBuilt = function (_systemId, _entityType, _oldStatus) {

        app.convertNetworkStage(_systemId, _entityType, 'A', _oldStatus);

    }
    this.convertToDorment = function (_systemId, _entityType, _oldStatus) {

        app.convertNetworkStage(_systemId, _entityType, 'D', _oldStatus);
    }
    this.convertToPlanned = function (_systemId, _entityType, _oldStatus) {
        app.convertNetworkStage(_systemId, _entityType, 'P', _oldStatus);
    }

    this.convertNetworkStage = function (_systemId, _entityType, _networkStage, _oldStatus) {
        var _old = app.getnetstatus(_oldStatus);
        var _new = app.getnetstatus(_networkStage);
        var layerTitle = getLayerTltle(_entityType);
        //Are you sure you want Convert
        //;
        _old = _old;
        _new = _new;
        confirm(getMultilingualStringValue($.validator.format(MultilingualKey.SI_ISP_GBL_JQ_GBL_020, layerTitle, _old, _new)), function () {
            ajaxReq('Main/NetworkStage', {
                systemid: _systemId, entity_type: _entityType, curr_status: _networkStage, old_status: _oldStatus
            }, true, function (resp) {
                if (resp.status == 'OK') {
                    // successfully converted from

                    //var retmsg = layerTitle +  MultilingualKey.SI_ISP_GBL_JQ_GBL_021+'  <b> ' + _old + '</b> to <b>' + _new + ' .</b>';
                    alert($.validator.format(MultilingualKey.SI_ISP_GBL_JQ_GBL_021, layerTitle, _old, _new));
                    //close info window
                    $(app.DE.InfoDiv).hide();
                    //load layers on status change..
                    app.loadLayerOnEntity();
                }
                else {
                    alert(resp.results.message);
                }

            }, false, true, false);
        });
    }

    this.getnetstatus = function (Status) {
        var network = '';
        if (Status == 'P')
            network = 'Planned';
        else if (Status == 'A')
            network = 'As-Built';
        else
            network = 'Dormant';
        return network;
    }
    this.srchelement = function () {
        var recordCount = 0;

        var searchtext = $('#txtInfoSrch').val();

        if (searchtext.length >= 2) {
            $('#ddNetLayerType').val();

            $('#infoTable tr').each(function () {
                $('.InfoElements').children('#noRecord').remove();
                if ($('td:nth-child(3)', $(this)).text().toLowerCase().indexOf(searchtext.toLowerCase()) > -1 || $('td:nth-child(5)', $(this)).text().toLowerCase().indexOf(searchtext.toLowerCase()) > -1 || $('td:nth-child(1)', $(this)).text().toLowerCase().indexOf(searchtext.toLowerCase()) > -1) {
                    recordCount++;
                    $(this).show();
                }
                else {

                    $(this).hide();
                }

            });
            if (recordCount <= 0) {
                $('.InfoElements').append('<div class="nr-found" id="noRecord">No record found</div>');
            }
            recordCount = 0;
        }
        else {
            $('.InfoElements').children('#noRecord').remove();
            $('#infoTable tr').css('display', 'table-row');
        }

    }
    this.changeNetworkStage = function () {
        var drpVal = $('#ddNetLayerType').val();
        $('#txtInfoSrch').val('');
        if (drpVal.toLowerCase() != 'all') {
            $("#infoTable tr").hide();
            if ($('#rdbDisplayedLayer').is(':checked')) {
                var checkedlyrs = [];
                $.each($(si.DE.ulNetworkLayers + " li .mainLyr:checked"), function () {
                    checkedlyrs.push($(this).attr('data-layername').toUpperCase());
                });
                $.each($("#infoTable tr"), function () {
                    if (checkedlyrs.includes($(this).children().first().text().toUpperCase()) && $(this).children().last().children().val().toLowerCase().indexOf(drpVal.toLowerCase()) > -1) {
                        $(this).show();
                    }
                });
            } else {
                $('#infoTable tr').each(function () {
                    if ($('td input[type=hidden]', $(this)).val().toLowerCase().indexOf(drpVal.toLowerCase()) > -1) {
                        $(this).show();
                    } else {
                        $(this).hide();
                    }

                });
            }
        } else {
            $("#infoTable tr").hide();
            if ($('#rdbDisplayedLayer').is(':checked')) {
                var checkedlyrs = [];
                $.each($(si.DE.ulNetworkLayers + " li .mainLyr:checked"), function () {
                    checkedlyrs.push($(this).attr('data-layername').toUpperCase());
                });
                $.each($("#infoTable tr"), function () {
                    if (checkedlyrs.includes($(this).children().first().text().toUpperCase())) {
                        $(this).show();
                    }
                });
            } else {
                $("#infoTable tr").show();
            }
        }
    }

