    this.BindUsersByParentUser = function () {
        //alert("Running");
        var ParentUserIds = "";
        var ddl_ParentUser = $('#ddlParentUsers').val();
        if (ddl_ParentUser != null) {
            if (ddl_ParentUser.length > 1) {
                ParentUserIds = ddl_ParentUser.join(",");
            }
            else {
                ParentUserIds = ddl_ParentUser[0];
            }
            //ajaxReq('Report/GetUsersByParentUser', { parentUser_ids: ddl_ParentUser }, false, function (resp) {
            ajaxReq('Report/GetReportUsersByParentUser', {
                parentUser_ids: ParentUserIds
            }, false, function (resp) {
                if (resp.Data.length > 0) {

                    //var g = _.groupBy(data, function (d) { return d.groupUser });;

                    //console.log(JSON.stringify(g));
                    $('#ddlUsers').empty();
                    var groupName = "";
                    var options = "";
                    $.each(resp.Data, function (data, value) {
                        var notChanged = groupName == value.groupUser;

                        if (!notChanged && value.groupUser == "Others") {
                            groupName = value.groupUser;
                            options = options + '<optgroup label="Others">'
                        }
                        options = options + '<option value=' + value.user_id + '>' + value.user_name + '</option>';
                        //$('#ddlUsers').append($("<option></option>").val(value.user_id).html(value.user_name));

                        if (value.groupUser == "Others" && resp.Data.length - 1 == data) {
                            options = options + " </optgroup>"
                        }
                    });
                    $('#ddlUsers').append(options);
                }
                else {
                    $('#ddlUsers').empty();
                }
            }, true, true);

        }
        else {
            $('#ddlUsers').empty();
        }
        $('#ddlUsers').trigger("chosen:updated");
    }
