    this.ShowOnMapImage = function (longitude, latitude, e) {

        if (app.imgLocationMarker != null) { app.imgLocationMarker.setMap(null); }
        var latLong = new google.maps.LatLng(parseFloat(latitude), parseFloat(longitude));
        app.imgLocationMarker = app.createMarker(latLong, '');
        app.imgLocationMarker.setMap(app.map);
        app.imgLocationMarker.setDraggable(false);
        app.map.setCenter(latLong);
        app.map.setZoom(17);
        e.stopPropagation();
    }

    this.exportAttachment = function (jResp) {
        try {
            jResp = $.parseJSON(jResp);
        }
        catch (e) {
        }
        try {
            // jResp = $.parseJSON(jResp);
            if (jResp.status) {
                window.open('AttachmentExport.aspx?path=' + jResp.Message, "_blank", 'height=50,width=100,top=0,left=0,toolbar=no,status=no,menubar=no,scrollbars=no,resizable=no,');
            }
            else
                alert(jResp.Message);

            closeProgress();
        }
        catch (e) {
            alert(MultilingualKey.SI_OSP_GBL_JQ_FRM_046);
        }
    }

