    this.uploadDocumentFile = function () {
        //;
        var frmData = new FormData();
        var filesize = $('#hdnMaxFileUploadSizeLimit').val();

        var Sizeinbytes = filesize * 1024;
        if ($("#fuAttachmentUpload").get(0).files[0].size > Sizeinbytes) {

            alert(getMultilingualStringValue($.validator.format(MultilingualKey.SI_OSP_GBL_JQ_FRM_109, (filesize / 1024).toFixed(2))));
            //alert(MultilingualKey.SI_OSP_GBL_JQ_FRM_048 + " " + " <b>" + (filesize / 1024).toFixed(2) + "</b> MB!");
        }
        else {
            var uploadedfile = $("#fuAttachmentUpload").get(0).files[0];

            if (uploadedfile.name.length > 100) {
                alert("File Name length should be less than <b>100</b>.</br>Current file name length: " + uploadedfile.name.length + "");
                return false;
            }
            if (!validateDocumentFileType()) {
                return false;
            }
            frmData.append(uploadedfile.name, uploadedfile);
            //frmData.append('ASPSESSID', ASPSESSID);
            //frmData.append('AUTHID', auth);
            frmData.append('system_Id', $('#infoTB').attr('att_systemid'));
            frmData.append('entity_type', $('#infoTB').attr('att_entityType'));
            frmData.append('document_type', 'Document');

            ajaxReqforFileUpload('Main/CheckFileExist', frmData, true, function (resp) {
                if (resp.status == "OK") {
                    ajaxReqforFileUpload('Main/UploadDocument', frmData, true, function (resp) {
                        if (resp.status == "OK") {
                            $('#closeModalPopup').trigger("click");
                            app.getAttachmentFiles();
                            alert(resp.message);
                        }
                        else {
                            alert(resp.message);
                        }

                    }, true);
                }
                else if (resp.status == "DUPLICATE_EXIST") {
                    confirm(resp.message, function () {

                        ajaxReqforFileUpload('Main/UploadDocument', frmData, true, function (resp) {
                            if (resp.status == "OK") {
                                $('#closeModalPopup').trigger("click");
                                app.getAttachmentFiles();
                                alert(resp.message);
                            }
                            else {
                                alert(resp.message);
                            }

                        }, true);
                    });
                }
                else {
                    console.log("MSG false:" + resp.message);

                    alert(resp.message);
                }
            }, true);



            //}
            //else {
            //    alert("File size is too large. Maximum file size allowed is 10 MB!");
            //}
        }
    }

    function isValidFileSize(data) {
        var checkstatus = false;
        ajaxReqforFileUpload('Main/isValidFileSize', data, false, function (resp) {

            if (resp.status == "OK") {
                checkstatus = true;

                return checkstatus;
            }
            else {

                checkstatus = false;

                alert('File size is too large !');
            }

        }, true);
        return checkstatus;
    }

