    this.srchworkspace = function () {
        var recordCount = 0;

        var searchtext = $('#txtWorkspaceSrch').val();
        $('#infoTable #noRecord').remove();
        if (searchtext.length > 3) {

            $('#ddNetLayerType').val();

            $('#infoTable tr').each(function () {

                if ($('td:nth-child(1)', $(this)).text().toLowerCase().indexOf(searchtext.toLowerCase()) > -1) {
                    recordCount++;
                    $(this).show();
                }
                else {

                    $(this).hide();
                }
            });

            if (recordCount <= 0) {
                $('#infoTable').append('<div class="nr-found" id="noRecord">No record found</div>');
            }
            recordCount = 0;
        }
        else {
            //$('#infoTable').children('#noRecord').remove();
            if ($('#noRecord').length > 1) {
                $('#noRecord').last().remove();
            }
            $('#infoTable tr').show();
        }

    }

