    this.ckhNetworksParentsALL = function (childnetworkClass) {

        var disCheckboxLength = $('input[type=checkbox]:disabled').filter('.' + childnetworkClass + '').length;
        var checkedCheckobxLength = $('input[type=checkbox]:checked').filter('.' + childnetworkClass + '').filter('[data-ntp=True]').not(":disabled").length;
        var totalCheckbox = $('.' + childnetworkClass + '').length;
        if (totalCheckbox == disCheckboxLength) {
            return false;
        }
        else if (checkedCheckobxLength == (totalCheckbox - disCheckboxLength)) {
            return true;
        }
        else {
            return false;
        }
    }

    // this function for change the color of updated records

    this.changeColor = function (tableId) {

        var tbl = $('#' + tableId);
        var rowCount = $('#' + tableId + ' tr').length;

        if (rowCount > 0) {
            for (var i = 0; i < tbl[0].rows.length; i++) {
                for (var j = 0; j < tbl[0].rows[i].cells.length; j++) {
                    if (i > 1) {
                        if (tbl[0].rows[i].cells[j].innerHTML != tbl[0].rows[i - 1].cells[j].innerHTML) {
                            tbl[0].rows[i - 1].cells[j].style.color = "red";
                        }
                    }
                }
            }
        }

        $(tbl).find('tfoot td').removeAttr("style")
    }
    this.latlongDistance = function (lat1, lng1, lat2, lng2) {
        var earthRadius = 6371000; //meters
        var dLat = app.toRadian(lat2 - lat1);
        var dLng = app.toRadian(lng2 - lng1);
        var a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
            Math.cos(app.toRadian(lat1)) * Math.cos(app.toRadian(lat2)) *
            Math.sin(dLng / 2) * Math.sin(dLng / 2);
        var c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
        var dist = parseFloat(earthRadius * c);

        return Number((dist).toFixed(2));
    }
    this.toRadian = function (value) {
        return Math.PI * value / 180;
    }

