    this.EnableJobPackAddressTool = function () {

        var geocoder = new google.maps.Geocoder;
        var marker;

        if (app.gMapObj.ClickAction && app.gMapObj.ClickAction == "JOBPACKADDRESS") {
            app.ClearJobPackAddressTool();
            if (marker && marker.setMap) {
                marker.setMap(null); marker = null;
            }
        }
        else {
            app.ClearJobPackAddressTool();
            $('.infoSwitch').removeClass('activeToolBar');
            $(app.DE.InfoDiv).hide();
            app.map.setOptions({ draggableCursor: 'crosshair' });
            google.maps.event.addListener(app.map, 'click', function (LatLong) {
                var input = LatLong.latLng;

                var latlng = { lat: LatLong.latLng.lat(), lng: LatLong.latLng.lng() };
                geocoder.geocode({ 'location': latlng }, function (results, status) {
                    if (status === 'OK') {
                        if (results[0]) {
                            setTimeout(function () {
                                if (marker && marker.setMap) {
                                    marker.setMap(null);
                                }

                                marker = new google.maps.Marker({
                                    position: latlng,
                                    map: app.map,
                                    icon: new google.maps.MarkerImage('../Content/images/google_locator.png')
                                });

                                if (results[0].formatted_address != '') {
                                    $("#latitude").val(app.roundNumber(LatLong.latLng.lat(), 6));
                                    $("#longitude").val(app.roundNumber(LatLong.latLng.lng(), 6));
                                    $("#gis_address").val(results[0].formatted_address);
                                    $("#manual_address").val(results[0].formatted_address);
                                    $("#latitude,#longitude,#gis_address,#manual_address").removeClass('input-validation-error').addClass('valid');
                                }
                            }, 20);

                        } else {
                            window.alert(MultilingualKey.SI_OSP_GBL_JQ_FRM_042);
                        }
                    }
                    else {
                        $("#latitude").val('');
                        $("#longitude").val('');
                        $("#gis_address").val('');
                        $("#manual_address").val('');
                        $("#latitude,#longitude,#gis_address,#manual_address").removeClass('input-validation-error').addClass('valid');
                    }
                });

            });
            app.gMapObj.ClickAction = "JOBPACKADDRESS";
        }

    }
    this.ClearJobPackAddressTool = function () {

        google.maps.event.clearListeners(app.map, 'click');
        app.map.setOptions({ draggableCursor: '' });
        $('img[src = "../Content/images/google_locator.png"]').hide();
        app.gMapObj.ClickAction = '';
        if (app.gMapObj.tempBufferCircle) {
            if (app.gMapObj.tempBufferCircle.map) {
                app.gMapObj.tempBufferCircle.setMap(null);
                app.gMapObj.tempBufferCircle = null;
            }
        }
        if (app.gMapObj.ClickAction == undefined) {
            app.clearTPRelatedObjects();
            app.removeEventListnrs('click');
        }
        if (app.gMapObj.tempBufferCircle) {
            if (app.gMapObj.tempBufferCircle.map) {
                app.gMapObj.tempBufferCircle.setMap(null);
                app.gMapObj.tempBufferCircle = null;
            }
        }
    }

    this.highlightJobOnMap = function (latitude, longitude) {
        if (app.gMapObj.JobMarker != null) {
            app.gMapObj.JobMarker.setMap(null);
        }
        var latLong = new google.maps.LatLng(parseFloat(latitude), parseFloat(longitude))
        app.gMapObj.JobMarker = app.createMarker(latLong, 'Content/images/dwnArrow.png');
        app.gMapObj.JobMarker.setAnimation(google.maps.Animation.BOUNCE);
        setTimeout(function () { animateLine(app.gMapObj.JobMarker, 0) }, 20);
        app.gMapObj.JobMarker.setMap(app.map);
        var southWest = new google.maps.LatLng(parseFloat(latitude), parseFloat(longitude));
        var northEast = new google.maps.LatLng(parseFloat(latitude), parseFloat(longitude));
        var bounds = new google.maps.LatLngBounds(southWest, northEast);
        app.map.fitBounds(bounds);
        window.setTimeout(function () { if (app.gMapObj.JobMarker) { app.gMapObj.JobMarker.setMap(null) } app.gMapObj.JobMarker = null; }, 25000);
    }
