    this.isValidAssociation = function () {
        ;
        var isValid = true;
        if ($('#ddlStructureList').val() != '' && $('#ddlStructureList').val() != null) {
            if ($('#ddlAssociationtype').val() == '') {
                alert(MultilingualKey.SI_OSP_GBL_JQ_FRM_053);
                $('#anchrAssociation').trigger("click");
                isValid = false;
                return false;
            }
            else if ($('#ddlAssociationtype').val() == 'Shaft' && $('#ddlShaftlist').val() == '') {
                alert(MultilingualKey.SI_OSP_GBL_JQ_FRM_054);
                $('#anchrAssociation').trigger("click");
                isValid = false;
                return false;
            }
            if ($('#ddlFloorlist').val() == '') {
                alert(MultilingualKey.SI_OSP_BUL_JQ_FRM_001);
                $('#anchrAssociation').trigger("click");
                isValid = false;
                return false;
            }

            if ($('#hdnIsShaftElement').val() == 'False' && $('#hdnIsFloorElement').val() == 'False' && $('#ddlUnitList').val() == '') {
                alert(MultilingualKey.SI_OSP_BUL_JQ_FRM_002);
                $('#anchrAssociation').trigger("click");
                isValid = false;
                return false;
            }
        }
        var selected_ownership = $("input[name='rdbOwnershipType']:checked").val();
        if (selected_ownership == 'Third Party' && $('#txt3rdPartyVendor').val() == "") {
            $('#txt3rdPartyVendor').next().addClass('input-validation-error');
            return false;
        }
        if ($('#txtbomsubcategory').val() == '') {
            $('#txtbomsubcategory').next().addClass('input-validation-error');
            return false;
        }

        var acquire_form = $("input[id='is_acquire_form']:checked").val();
        if (acquire_form == "True") {
            if ($("#txtacquire_from").val() == "") {
                $('#txtacquire_from').css('border-color', 'red');;
                return false;
            }
            else {
                $('#txtacquire_from').css('border-color', '');
            }
        }
        return isValid;
    }
