        getTotalAmount: function () {
            var riAmount = app.ROW.getRIAmount($('#txtROWArea').val(), $('#txtRiRate').val());
            var refundableAmount = null;
            if (!isNaN(riAmount)) {
                refundableAmount = app.ROW.getRefundableAmount(riAmount);
            }
            var nonRefundableAmount = app.ROW.getNonRefundableAmount($('#txtAccessCharge').val(), $('#txtROWRouteLength').val());
            if (!isNaN(nonRefundableAmount) && !isNaN(refundableAmount)) {
                return (parseFloat(refundableAmount) + parseFloat(nonRefundableAmount)).toFixed(2);
            }
            else {
                return null;
            }
        },
        getRIAmount: function (_rowArea, _rirate) {
            if (isNaN(_rowArea)) {
                return false;
            }
            if (isNaN(_rirate)) {
                return false;
            }
            var riAmount = parseFloat(_rowArea) * parseFloat(_rirate);
            return riAmount.toFixed(2);
        },
        setRIAmount: function () {
            var riAmount = app.ROW.getRIAmount($('#txtROWArea').val(), $('#txtRiRate').val());
            var refundableAmount = app.ROW.getRefundableAmount(riAmount);
            var nonRefundableAmount = app.ROW.getNonRefundableAmount($('#txtAccessCharge').val(), $('#txtROWRouteLength').val());
            var totalAmount = app.ROW.getTotalAmount();
            if (!isNaN(riAmount)) { $('#txtRIAmount').val(riAmount); }
            else {
                $('#txtRIAmount').val(null);
            }
            if (!isNaN(refundableAmount)) {
                $('#txtRefundableDepositAmount').val(refundableAmount);
            } else {
                $('#txtRefundableDepositAmount').val(null);
            }

            if (!isNaN(nonRefundableAmount)) {
                $('#txtNonRefundableDepositAmount').val(nonRefundableAmount);
            } else {
                $('#txtNonRefundableDepositAmount').val(null);
            }

            if (!isNaN(totalAmount)) {
                $('#txtTotalAmount').val(totalAmount);
            } else {
                $('#txtTotalAmount').val(null);
            }
        },
        getRefundableAmount: function (_riAmount) {
            var refundableAmount = (parseFloat(_riAmount) / 2);
            return refundableAmount.toFixed(2);
        },
        getNonRefundableAmount: function (_accessCharge, _routeLength) {
            var isValid = true;
            var nonRefundableAmount = 0;
            var riAmount = app.ROW.getRIAmount($('#txtROWArea').val(), $('#txtRiRate').val());
            if ((_accessCharge != '' && _accessCharge != null && !isNaN(_accessCharge)) && (_routeLength != '' && _routeLength != null && !isNaN(_routeLength))) {
                nonRefundableAmount = nonRefundableAmount + (parseFloat(_accessCharge) * parseFloat(_routeLength));
            }

            if (!isNaN(_routeLength)) {
                nonRefundableAmount = nonRefundableAmount + (isNaN(riAmount) ? 0 : parseFloat(riAmount));
            }
            if (nonRefundableAmount > 0) {
                return nonRefundableAmount.toFixed(2);
            }
            else {
                return null;
            }
        },
        isValidAmount: function (_rowArea, _routeLength, _rirate, _depositAmount, rowType) {

            if (rowType == 'PIT' && (_rowArea == '' || _rowArea == null || parseFloat(_rowArea) == 0)) {
                return false;
            } else if (rowType == 'Line' && (_routeLength == '' || _routeLength == null || parseFloat(_routeLength) == 0)) {
                return false;
            } else if (_rirate == '' || _rirate == null || parseFloat(_rirate) == 0) {
                return false;
            }
            return true;
        },
