        getActualTotalAmount: function () {
            var accessCharge = parseFloat($('#txtActualAccessCharge').val());
            var actualRIAmount = parseFloat($('#txtActualRIAmount').val());
            var actualDepost = parseFloat($('#txtActualDepositAmount').val());
            var actualpanilty = parseFloat($('#txtPaniltyAmount').val());
            var actualRouteLength = parseFloat($('#txtROWRouteLength').val());
            var totalAmount = ((isNaN(accessCharge) ? 0 : accessCharge) * actualRouteLength) +
                (isNaN(actualRIAmount) ? 0 : actualRIAmount)
                + (isNaN(actualDepost) ? 0 : actualDepost);
            if (!isNaN(totalAmount)) {
                $('#txtApproveTotalAmount').val(totalAmount.toFixed(2));
            }
        },
        getActualTotalPaidAmount: function () {
            var accessCharge = parseFloat($('#txtActualAccessCharge').val());
            var actualRIAmount = parseFloat($('#txtActualRIAmount').val());
            var actualDepost = parseFloat($('#txtActualDepositAmount').val());
            var actualpanilty = parseFloat($('#txtPaniltyAmount').val());
            var actualRouteLength = parseFloat($('#txtROWRouteLength').val());
            var totalAmount = ((isNaN(accessCharge) ? 0 : accessCharge) * actualRouteLength)
                + (isNaN(actualRIAmount) ? 0 : actualRIAmount)
                + (isNaN(actualDepost) ? 0 : actualDepost)
                + (isNaN(actualpanilty) ? 0 : actualpanilty);
            if (!isNaN(totalAmount)) {
                $('#txtApproveTotalPaidAmount').val(totalAmount.toFixed(2));
            }
        },
        setWindow: function () {
            var startDate = new Date();
            var endDate = new Date();
            var isValid = true;
            startDate = DateFormatter($('#txtStartDate').val());
            endDate = DateFormatter($('#txtEndDate').val());
            startDate = new Date(startDate);
            endDate = new Date(endDate);
            if (endDate.getTime() < startDate.getTime()) {
                isValid = false;
                $('#txtROWWindow').val(null);
                alert(MultilingualKey.SI_OSP_GBL_JQ_FRM_061);
            }
            if (isValid) {
                // To calculate the time difference of two dates 
                var diffirence = endDate.getTime() - startDate.getTime();

                // To calculate the no. of days between two dates 
                var days = diffirence / (1000 * 3600 * 24);
                if (!isNaN(days)) {
                    $('#txtROWWindow').val(days);
                }
            }

        },
