        setDateTimeCalendar: function (startdateid, startdateimgid, enddateid, enddateimgid, isBackDateAllowed, isFutureDateAllowed) {

            //calendar.refresh();
            //var setup1 = showtime;
            Calendar.setup({
                inputField: startdateid,   // id of the input field
                button: startdateimgid,
                ifFormat: "%d-%b-%Y",       // format of the input field datetime format %d-%b-%Y %I:%M %p
                showsTime: false,
                timeFormat: "12",
                weekNumbers: false,

                //new Date(new Date().setMonth(new Date().getMonth() + 2))

                //maxDate: "+6m",
                //onUpdate: catcalc,
                onUpdate: function () {
                    app.ROW.setWindow();
                },
                disableFunc: function (date) {
                    var endDateValue = document.getElementById(enddateid).value;

                    var enddt = DateFormatter(endDateValue);
                    enddt = new Date(enddt);
                    if (date.getTime() > enddt.getTime()) {
                        return true;
                    }
                    if (isBackDateAllowed) {
                        var now = new Date();
                        now.setDate(now.getDate());
                        if (date.getTime() > now.getTime()) {
                            return true;
                        }
                    }
                    ////
                    if (!isFutureDateAllowed) {
                        var now = new Date();
                        now.setDate(now.getDate());
                        //now.setMonth(now.getMonth()+2);
                        if (date.getTime() > now.getTime()) {
                            return true;
                        }
                    }
                }
            });

            //isFutureDateAllowed = true;
            Calendar.setup({
                inputField: enddateid,
                button: enddateimgid,
                ifFormat: "%d-%b-%Y",
                showsTime: false,
                timeFormat: "12",
                weekNumbers: false,
                //maxDate: new Date(new Date().setMonth(new Date().getMonth() + 6)),
                align: "Br",
                //maxDate: "+6m",
                onUpdate: function () {
                    app.ROW.setWindow();
                },
                disableFunc: function (date) {
                    var startDateValue = document.getElementById(startdateid).value;

                    var startdt = DateFormatter(startDateValue);
                    startdt = new Date(startdt);
                    if (date.getTime() < startdt.getTime()) {
                        return true;
                    }
                    if (isBackDateAllowed) {
                        var now = new Date();
                        now.setDate(now.getDate());
                        if (date.getTime() > now.getTime()) {
                            return true;
                        }
                    }
                    if (!isFutureDateAllowed) {
                        var now = new Date();
                        now.setDate(now.getDate());
                        if (date.getTime() > now.getTime()) {
                            return true;
                        }
                    }
                },

            });




        },
        isAttachmentTypeValid: function (isAppliedStage) {
            //
            var isvalid = true;
            var vMessage = '';
            if (isAppliedStage) {
                $.each($('#ddlAttachmentType  option[data-is-required="True"]'), function (indx, itm) {
                    var documentType = $(itm).attr('data-attachment-type');
                    if ($('#divApplyDocument #ulROWDocumentUpload tbody tr td[data-attachment-type="' + documentType + '"]').length == 0) {
                        isvalid = false;
                        vMessage = documentType + ' is required!';
                        return false;
                    }
                });

            } else {
                var rowStatus = $('#ddlRowStatus').val();
                $.each($('#ddlApproveRejectAttachmentType  option[data-is-required="True"][data-category="' + rowStatus + '"]'), function (indx, itm) {
                    var documentType = $(itm).attr('data-attachment-type');
                    if ($('#divRowStageDocument #ulROWDocumentUpload tbody tr td[data-attachment-type="' + documentType + '"]').length == 0) {
                        isvalid = false;
                        vMessage = documentType + ' is required!';
                        return false;
                    }
                });
            }
            if (!isvalid) {
                alert(vMessage);
            }
            return isvalid;
        },
