        setRecurringCharge: function () {
            var isValid = true;
            var accessCharge = $('#txtActualAccessCharge').val();
            var accessChargeStartDate = DateFormatter($('#txtAccessChargeDate').val());
            accessChargeStartDate = new Date(accessChargeStartDate);
            var currentDate = DateFormatter(new Date());
            currentDate = new Date(currentDate);

            if (isValid) {
                // To calculate the time difference of two dates 
                var diffirence = currentDate.getTime() - accessChargeStartDate.getTime();

                // To calculate the no. of days between two dates 
                var days = diffirence / (1000 * 3600 * 24);
                if (accessCharge != '' && accessCharge != null && !isNaN(accessCharge) && !isNaN(days)) {
                    var totalRecurringCharge = parseFloat(accessCharge) * parseInt((days / 365).toFixed(2));
                    $('#txtTotalRecurringCharge').val((parseInt(totalRecurringCharge) > 0 ? parseInt(totalRecurringCharge) : 0));
                } else {
                    $('#txtTotalRecurringCharge').val(0);
                }
            }
        },
