        setDateTimeCalendar: function (startdateid, startdateimgid, chkDisabled, isFutureDateAllowed) {

            Calendar.setup({
                inputField: startdateid,   // id of the input field
                button: startdateimgid,
                ifFormat: "%d-%b-%Y",       // format of the input field datetime format %d-%b-%Y %I:%M %p
                showsTime: false,
                timeFormat: "12",
                weekNumbers: false,
                onUpdate: function () {
                    ////;
                    var emID = $("#" + startdateid).val();
                    if (emID != "") {
                        $("#" + startdateid).removeClass('input-validation-error').removeClass('field-validation-error').addClass('field-validation-valid').html('');
                    }
                    else {
                        $("#" + startdateid).addClass('input-validation-error');
                    }
                },
                disableFunc: function (date) {
                    if (isFutureDateAllowed) {
                        var now = new Date();
                        now.setDate(now.getDate() - 1);
                        if (date.getTime() <= now.getTime()) {
                            return true;
                        }
                    }
                },

            });
        },

        initiateDrawingsNetworkTicket: function (obj, shapeFlag) {
            app.addRemoveActiveClass('');
            if (si.PointentityOBJ.length > 0) {
                for (var k = 0; k < si.PointentityOBJ.length; k++) {
                    si.PointentityOBJ[k].setMap(null);
                }
                app.PointentityOBJ = [];
            }
            si.resetShapeTools();
            $('#MainReportToolBar').find(".activeToolBar").removeClass('activeToolBar');
            if ($(obj).hasClass('activeToolBar')) { $(obj).removeClass('activeToolBar'); } else { $('#NetTicket >.iconBaricomoon >a').removeClass('activeToolBar'); $(obj).addClass('activeToolBar'); }
            if (si.gMapObj.shapeObj)
                si.gMapObj.shapeObj.setMap(null);
            si.removeEventListnrs('click');
            si.gMapObj.shapeType = shapeFlag;
            si.gMapObj.purposeType = "NetworkTicket";
            si.gMapObj.shapeArr = [];

            google.maps.event.addListener(si.map, 'click', app.Networkticket.handleShapeNetworkTicketEvents);
        },
        handleShapeNetworkTicketEvents: function (eventParam) {

            if (si.gMapObj.shapeObj)
                si.gMapObj.shapeObj.setMap(null);
            switch (si.gMapObj.shapeType) {
                case 'Polygon':
                    si.gMapObj.shapeArr.push(eventParam.latLng);
                    si.gMapObj.shapeObj = new google.maps.Polygon({
                        paths: si.gMapObj.shapeArr,
                        strokeColor: '#FF8800',
                        strokeOpacity: 0.6,
                        strokeWeight: 2,
                        fillColor: '#FF8800',
                        fillOpacity: 0.35,
                        editable: true,
                        zIndex: 1,
                        draggable: true
                    });
                    google.maps.event.addListener(si.gMapObj.shapeObj, 'mouseup', calculateArea);
                    google.maps.event.addListener(si.gMapObj.shapeObj, 'rightclick', function (event) {
                        if (event.vertex == undefined) {
                            return;
                        } else {
                            removeVertex(si.gMapObj.shapeObj, event.vertex);
                        }
                    });

                    google.maps.event.addListener(si.gMapObj.shapeObj.getPath(), 'set_at', function (indx) {
                        var newPath = si.gMapObj.shapeObj.getPath();
                        si.gMapObj.shapeArr = newPath.getArray();
                    });

                    google.maps.event.addListener(si.gMapObj.shapeObj.getPath(), 'insert_at', function (indx) {
                        var newPath = si.gMapObj.shapeObj.getPath();
                        si.gMapObj.shapeArr = newPath.getArray();
                    });
                    break;
                case 'Rectangle':
                    si.gMapObj.shapeArr.push(eventParam.latLng);
                    var rectBound = validateBounds();
                    si.gMapObj.shapeObj = new google.maps.Rectangle({
                        strokeColor: '#FF8800',
                        strokeOpacity: 0.6,
                        strokeWeight: 2,
                        fillColor: '#FF8800',
                        fillOpacity: 0.35,
                        editable: true,
                        draggable: true,
                        bounds: rectBound
                    });
                    google.maps.event.addListener(si.gMapObj.shapeObj, 'bounds_changed', calculateArea);

                    break;
                case 'Circle':
                    si.gMapObj.shapeArr = [];
                    si.gMapObj.shapeObj = new google.maps.Circle({
                        strokeColor: '#FF8800',
                        strokeOpacity: 0.6,
                        strokeWeight: 2,
                        fillColor: '#FF8800',
                        fillOpacity: 0.35,
                        center: eventParam.latLng, //new google.maps.LatLng(34.052234, -118.243684),   //event.latLng,     //circlArry[0],
                        radius: 200,
                        editable: true,
                        draggable: true
                    });
                    google.maps.event.addListener(si.gMapObj.shapeObj, 'radius_changed', calculateArea);
                    google.maps.event.addListener(si.gMapObj.shapeObj, 'rightclick', function (event) {
                        if (event.vertex == undefined) {
                            return;
                        } else {
                            removeVertex(si.gMapObj.shapeObj, event.vertex);
                        }
                    });

                    break;
                case 'PolyLine':

                    si.gMapObj.shapeArr.push(eventParam.latLng);
                    si.gMapObj.shapeObj = new google.maps.Polyline({
                        path: si.gMapObj.shapeArr,
                        strokeColor: '#FF8800',
                        strokeOpacity: 1,
                        strokeWeight: 2,
                        draggable: true

                    });

                    google.maps.event.addListener(si.gMapObj.RulerLine, 'click', function (event) { addPolyPoint });

                    si.gMapObj.RulerFlag = true;
                    break;
            }
            if (eventParam != 'PolyLine') {
                calculateArea();
                google.maps.event.addListener(si.gMapObj.shapeObj, 'click', app.Networkticket.shapeClickInfoNetworkTicket);
            }
            si.gMapObj.shapeObj.setMap(si.map);
        },
        shapeClickInfoNetworkTicket: function () {
            switch (si.gMapObj.shapeType) {
                case 'Polygon':
                    app.Networkticket.showNetworkTicketDetail(si.gMapObj.shapeObj.getPath().getArray(), 'polygon', si.gMapObj.purposeType);
                    break;
            }
        },
        showNetworkTicketDetail: function (latLongArr, selectionType, purposeType) {
            var longLatArr = '';
            if (latLongArr.length > 0) {
                for (i = 0; i < latLongArr.length; i++) {
                    longLatArr += (longLatArr == '' ? '' : ',') + latLongArr[i].lng() + ' ' + latLongArr[i].lat();
                }
                longLatArr += (longLatArr == '' ? '' : ',') + latLongArr[0].lng() + ' ' + latLongArr[0].lat();
                si.Networkticket.AddNetworkTicket(longLatArr, selectionType);
            }
        },
