        radioActionChange: function () {
            if ($("input[name='rdApprRej']:checked").val() == 'Reject') {
                $("#hdnStatus").val('R');
                $('#btnReject').show();
                $('#divApprove').hide();
                $('#btnApprove').hide();
                $('#dvRejectComment').show();
            }
            if ($("input[name='rdApprRej']:checked").val() == 'Approve') {
                $("#hdnStatus").val('A');
                $('#divApprove').show();
                $('#dvRejectComment').hide();
                $('#btnReject').hide();
                $('#btnApprove').show();
            }
        },
        EntityAction: function () {
            var p_remarks = $("#txtRemarks").val();
            if ($("#hdnStatus").val() == 'R') {
                ;
                var _comment = si.Networkticket.getRejectComment();
                if (_comment.trim() != '') {
                    si.Networkticket.ChangeEntityAction('Reject');
                }
            }
            else if (p_remarks != "") {
                $("#hdnStatus").val() == 'A';
                $("#hdnStatus").val('A');
                $("#txtRemarks").css('border-color', '');
                si.Networkticket.ChangeEntityAction('Approve');
            }
            else {
                $("#txtRemarks").css('border-color', 'red');
                //alert("Remarks cannot be blank!");
            }
        },
        ChangeEntityAction: function (type) {
            ;
            var p_remarks = $("#txtRemarks").val();
            if (p_remarks == "") {
                p_remarks = si.Networkticket.getRejectComment();
            }
            var p_entity_ids_types = $("#hdnEntityTypeSystemId").val();
            var p_ticket_id = $("#hdnTicketId").val();
            var _status = $("#hdnStatus").val();
            showConfirm($.validator.format(MultilingualKey.SI_OSP_BUL_JQ_RPT_001, type), function () {
                ajaxReq('NetworkTicket/VerifyEntities', { ticket_id: p_ticket_id, entity_ids_types: p_entity_ids_types, remarks: p_remarks, status: _status }, true, function (resp) {
                    ;
                    if (resp.status == "OK") {
                        alert(resp.message);
                        $('#closeModalPopup').trigger("click");
                        $("#txtRemarks").val("");

                    }

                    else {
                        alert(resp.message);
                    }
                }, false, false);
            });
        },
        showHideOtherCommentBox: function () {
            ;
            if ($('input[id="radioRejectComment"]:checked').val() == "Other") {
                $('#txtcommentother').attr('readonly', false);
            }
            else {
                $('#txtcommentother').attr('readonly', true);
                $('#txtcommentother').css('border-color', '');
            }
        },
        getRejectComment: function () {
            var _comment = '';
            var _selectedReason = $('input[id="radioRejectComment"]:checked').val();
            if (_selectedReason == undefined) {
                alert(MultilingualKey.SI_OSP_BUL_JQ_FRM_005);
            }
            else {
                _comment = _selectedReason != "Other" ? _selectedReason : $('#txtcommentother').val();
                if (_comment.trim() == '') {
                    $('#txtcommentother').css('border-color', 'red');
                }
            }
            return _comment;
        },
        removecss: function () {
            $('#txtcommentother').css('border-color', '');
        },
