    //Merge Cable Module
    this.MiscellaneousTools = {
        showMenu: function (divObj) {
            $(app.DE.InfoDiv).hide();
            $(app.DE.SplicingDiv).hide();
            app.showhideChildMenu('#MiscellaneousToolsToolBar', '.parentToolbar,.childtoolbar');
            app.addRemoveActiveClass(divObj);
            app.hideAllNetworkFile();
            if (typeof networkdata != "undefined") {
                networkdata.hideAllNetworkFile();
            }
        },

        MergeTool: function () {
            app.map.setOptions({ draggableCursor: 'crosshair' });
            google.maps.event.clearListeners(app.map, 'click');
            google.maps.event.addListener(app.map, 'click', function (LatLong) {
                var _zoom = app.map.getZoom();
                if (_zoom >= parseInt($('#hdnInfoToolZoom').val())) {
                    app.longitude = LatLong.latLng.lng();
                    app.latitude = LatLong.latLng.lat();
                    var latLong = new google.maps.LatLng(app.latitude, app.longitude);
                    app.showTempBufferforInfo(latLong);
                    $('#tblMergeCables tbody tr').remove();
                    ajaxReq('Main/GetNearByCables', {
                        latitude: app.latitude, longitude: app.longitude,
                        bufferInMtrs: getMeterDistanceFromZoom(_zoom),
                        user_id: 0
                    }, true, function (resp) {
                        for (var cable of resp) {
                            app.lstMergeCables = [];
                            app.lstMergeCables.push(cable);
                            app.addCableTobeMerged(app.lstMergeCables);

                        }
                    }, false, true);

                }
                else {
                    var func = function () {
                        app.map.setCenter(LatLong.latLng);
                        app.map.setZoom(parseInt($('#hdnInfoToolZoom').val()))
                    };
                    confirm(getMultilingualStringValue($.validator.format(MultilingualKey.SI_OSP_GBL_JQ_FRM_069, parseInt($('#hdnInfoToolZoom').val()), _zoom)), func);
                }

            });
        },

    }

    this.addCableTobeMerged = function (_result) {
        $("#dvNoMergesCables").hide();
        //;
        for (var cable of _result) {
            var sNo = $('#tblMergeCables tbody tr').length + 1;
            var result = "si._focusMe('Line', si.getLatLongArr('" + cable.geom + "'), '" + cable.entity_type + "',si.getLatLongArr('" + cable.centroid_geom + "'))";
            $('#tblMergeCables tbody').append('<tr class="cptr" data-system-id="' + cable.common_name + '" id="' + cable.entity_type + '" onmouseover="' + result + '"><td>' + sNo + '</td><td>' + cable.common_name + '</td><td><input type="radio" id="' + cable.system_id + '" data-id="' + cable.system_id + '" name="MergeCables" value = "' + cable.system_id + '"'
                + '></td><td style="font-weight: bold; color: red; cursor: pointer; " class="remove"><input type="checkbox" id="' + cable.system_id + '" data-id="' + cable.system_id + '"></td></tr>');
        }
    }
