        GetGroupListRegionalhead: function () {
            // 
            $('#ddl_UserRegionalHeadList').empty();
            $('#ddl_UserJOManagerList').empty();
            $('#ddl_UserGroupList').empty();
            $('#ddl_UserGroupList').append($("<option></option>").val('0').html('All Group'));
            $('#ddl_UserContractorList').empty();
            $('#ddl_UserContractorList').append($("<option></option>").val('0').html('All Dispatcher'));
            $('#ddl_UserFEList').empty();
            $('#ddl_UserFEList').append($("<option></option>").val('0').html('All FE'));
            var ResionalHead_id = $('#ddl_UserResionalHead').val();
            if (ResionalHead_id == "") {
                $('#ddl_UserJoList').empty();
                $('#ddl_UserJoList').append($("<option></option>").val('0').html('All JOManager'));
                return;
            }

            ajaxReq('Workforce/BindReportingManagerOnChange', { ContractorId: ResionalHead_id }, false, function (resp) {
                if (resp.Data.length > 0) {

                    $('#ddl_UserJoList').append($("<option></option>").val('0').html('All JOManager'));
                    $.each(resp.Data, function (data, value) {

                        $('#ddl_UserJoList').append($("<option></option>").val(value.user_id).html(value.user_name));
                    });
                }
                else {
                    $('#ddl_UserJoList').empty();
                    $('#ddl_UserJoList').append($("<option></option>").val('0').html('All JOManager'));
                }
                $('#ddl_UserJOManagerList').trigger("chosen:updated");
            }, true, true);

        },
