    this.showRegionProvinceOnMap = function (boundaryType, sp_geometry) {
        //sp_geometry = "POLYGON((77.3266197791946 28.1480022323056,77.326681470002 28.1479170926545,77.3268558135879 28.1478390479148,77.3270677081001 28.1478768877957,77.3270328393829 28.1480176047355,77.3269228688133 28.1481441315738,77.3266197791946 28.1480022323056,77.3266197791946 28.1480022323056))";
        app.ClearRegionProvinceFromMap();
        var latLngArr = [];  // nested arary of lat/lng..
        if (sp_geometry.indexOf("MULTI") != -1) {

            latLngArr = app.getLatLongArrMulti(sp_geometry);
            for (var i = 0; i < latLngArr.length; i++) {
                app.gRegionProvinceLayer.push(app.createPolygon(latLngArr[i]))
            }
        }
        else {
            var arr = app.getLatLongArr(sp_geometry);
            latLngArr.push(arr);
            app.gRegionProvinceLayer.push(app.createPolygon(arr))
        }
        for (var i = 0; i < app.gRegionProvinceLayer.length; i++) {
            app.gRegionProvinceLayer[i].setMap(app.map);
            app.gRegionProvinceLayer[i].setEditable(false);
            app.gRegionProvinceLayer[i].setDraggable(false);
            var path = app.gRegionProvinceLayer[i];
            app.map.fitBounds(path.getBound());
        }
        if (app.map.zoom > 10)
            app.map.setZoom(6);
        $(popup.DE.MinimizeModel).trigger("click");
    }

    this.ClearRegionProvinceFromMap = function () {
        for (var i = 0; i < app.gRegionProvinceLayer.length; i++) {
            app.gRegionProvinceLayer[i].setMap(null);
        }
        app.gRegionProvinceLayer = [];
    }
    this.getLatLongArrMulti = function (pgString) {
        var latLngArrMulti = [];
        pgString = pgString.replace("(((", "((").replace(")))", "))");
        var longLatArr = pgString.split('(');
        for (var i = 1; i < longLatArr.length; i++) {
            var latLngArr = [];
            var geom = longLatArr[i].replace(")),", "").trim();
            if (geom != "") {
                var longLatArrGeom = geom.split(',');
                for (var j = 0; j < longLatArrGeom.length; j++) {
                    var LongLatsingleGeom = longLatArrGeom[j].replace(")", "").trim().split(' ');
                    if (LongLatsingleGeom[0] == "" || LongLatsingleGeom[1] == "") {
                        ////;
                        var df = 0;
                    }
                    if (LongLatsingleGeom[0] != "") {
                        latLngArr.push(new google.maps.LatLng(parseFloat(LongLatsingleGeom[1]), parseFloat(LongLatsingleGeom[0])));
                    }
                }
            }
            if (latLngArr.length > 0)
                latLngArrMulti.push(latLngArr);
        }
        return latLngArrMulti;
    }
    this.ExportRegionProvince = function (_fileType) {
        var hdnRegProvExpMaxRecord = $("#hdnRegProvExpMaxRecord").val();
        var regionIds = app.getActiveRegionLayers();
        var provinceIds = app.getActiveProvinceLayers();
        $("#dropfiles").trigger("click");
        if (regionIds.length <= 0) {
            alert(MultilingualKey.SI_OSP_GBL_JQ_FRM_119);
            return;
        }
        else if (provinceIds.length > hdnRegProvExpMaxRecord) {

            alert($.validator.format(MultilingualKey.SI_OSP_GBL_JQ_FRM_067, hdnRegProvExpMaxRecord));
            return;
        }
        else {
            $("#dvRegProvExpProgr").show();
            setCookie('downloadStarted', 0, 3600); //Expiration could be anything... As long as we reset the value
            setTimeout(checkDownloadCookie, 1000); //Initiate the loop to check the cookie.
            window.location = appRoot + 'RegionProvince/DownloadRegionProvince?fileType=' + _fileType + '&regFilters=' + regionIds + '&provFilters=' + provinceIds;
            hideProgress();
        }
        //hideProgress();
    }
    var downloadTimeout;
    var checkDownloadCookie = function () {
        //console.log(getCookie("downloadStarted"));
        if (getCookie("downloadStarted") == 1) {
            //console.log(getCookie("downloadStarted") + "RT");
            setCookie("downloadStarted", false, 100); //Expiration could be anything... As long as we reset the value
            $('#dvRegProvExpProgr').hide();
        } else {
            downloadTimeout = setTimeout(checkDownloadCookie, 1000); //Re-run this function in 1 second.
        }
    }
    var setCookie = function (name, value, expiracy) {
        var exdate = new Date();
        exdate.setTime(exdate.getTime() + expiracy * 1000);
        var c_value = escape(value) + ((expiracy == null) ? "" : "; expires=" + exdate.toUTCString());
        document.cookie = name + "=" + c_value + '; path=/';
    };

    var getCookie = function (name) {
        var i, x, y, ARRcookies = document.cookie.split(";");
        for (i = 0; i < ARRcookies.length; i++) {
            x = ARRcookies[i].substr(0, ARRcookies[i].indexOf("="));
            y = ARRcookies[i].substr(ARRcookies[i].indexOf("=") + 1);
            x = x.replace(/^\s+|\s+$/g, "");
            if (x == name) {
                return y ? decodeURI(unescape(y.replace(/\+/g, ' '))) : y; //;//unescape(decodeURI(y));
            }
        }
    };

