    this.bufferGeometry = function (resp, geomType) {
        var bufferWidth = parseFloat($("#EntityBufferWidth").val());
        var pointsArray = app.getLatLongArr(resp.result.sp_geometry);
        var entityString = resp.result.sp_geometry.split('(');
        if (geomType.toUpperCase() == "LINE") {

            var overviewPathGeo = [];

            if (pointsArray.length >= 2) {
                if (app.lineBufferObj != null) {
                    app.lineBufferObj.setMap(null);
                }
                for (var i = 0; i < pointsArray.length; i++) {
                    overviewPathGeo.push([pointsArray[i].lng(), pointsArray[i].lat()]);
                }
                var geoInput = {
                    type: "LineString",
                    coordinates: overviewPathGeo
                };
                var geoReader = new jsts.io.GeoJSONReader();
                var geoWriter = new jsts.io.GeoJSONWriter();
                var geometry = geoReader.read(geoInput).buffer(((((bufferWidth + 0.2) / 2) / 1000) / 111.12), 0, 2);
                var polygon = geoWriter.write(geometry);
                //var oLanLng = [];
                var oCoordinates;
                oCoordinates = polygon.coordinates[0];
                var coordString = "";
                var lats = []; var lngs = [];
                for (i = 0; i < oCoordinates.length; i++) {
                    var oItem;
                    oItem = oCoordinates[i];
                    coordString = coordString + oItem[0] + ' ' + oItem[1]
                    if (i != oCoordinates.length - 1) {
                        coordString = coordString + ','
                    }
                    lngs.push(oItem[0]);
                    lats.push(oItem[1]);


                }
                // calc the min and max lng and lat
                var minlat = Math.min.apply(null, lats),
                    maxlat = Math.max.apply(null, lats);
                var minlng = Math.min.apply(null, lngs),
                    maxlng = Math.max.apply(null, lngs);

                resp.result.southWest["Lat"] = minlat;
                resp.result.southWest["Long"] = minlng;
                resp.result.northEast["Lat"] = maxlat;
                resp.result.northEast["Long"] = maxlng;

                // var southWest = new google.maps.LatLng("26.823497808552474", "80.98108387617462");
                //var northEast = new google.maps.LatLng("26.826321759648426", "80.98579174366772");

                resp.result.sp_geometry = entityString[0] + "(" + coordString + ")";


            }
        } else {
            var circle = app.createBufferCircle(bufferWidth, pointsArray[0]);

            var center = circle.getCenter(), radius = circle.getRadius(), numSides = 90;
            var points = [], degreeStep = 360 / numSides;
            var coordString = "";
            for (var i = 0; i < numSides; i++) {
                var gpos = google.maps.geometry.spherical.computeOffset(center, radius, degreeStep * i);
                coordString = coordString + gpos.lng() + ' ' + gpos.lat();

                if (i == 0) {

                    resp.result.southWest["Lat"] = gpos.lat();
                    resp.result.southWest["Long"] = gpos.lng();
                } else if (i == 44) {
                    resp.result.northEast["Lat"] = gpos.lat();
                    resp.result.northEast["Long"] = gpos.lng();
                }


                if (i != numSides - 1) {
                    coordString = coordString + ','
                }

            };
            var gpos = google.maps.geometry.spherical.computeOffset(center, radius, degreeStep * 0);
            var firstcoordString = gpos.lng() + ' ' + gpos.lat();
            resp.result.sp_geometry = "LINESTRING" + "(" + coordString + "," + firstcoordString + ")";

        }
        return resp;
    }


