    this.uploadRefLink = function () {
        if ($('#DocrefLinkText').val().trim() != "") {
            if ($('#DocrefLink').val().trim() != "") {
                $('#DocrefLinkText').removeClass("NotValid");
                $('#DocrefLink').removeClass("NotValid");
                var url = $("#DocrefLink").val().trim();
                //var pattern = /^(http|https)?:\/\/[a-zA-Z0-9-\.]+\.[a-z]{2,4}/; wi
                var pattern = new RegExp('^(https?:\\/\\/)?' + // protocol
                    '((([a-z\\d]([a-z\\d-]*[a-z\\d])*)\\.?)+[a-z]{2,}|' + // domain name
                    '((\\d{1,3}\\.){3}\\d{1,3}))' + // ip (v4) address
                    '(\\:\\d+)?(\\/[-a-z\\d%_.~+]*)*' + //port
                    '(\\?[;&a-z\\d%_.~+=-]*)?' + // query string
                    '(\\#[-a-z\\d_]*)?$', 'i');
                if (pattern.test(url)) {
                    var frmData = new FormData();
                    frmData.append('system_Id', $('#infoTB').attr('att_systemid'));
                    frmData.append('entity_type', $('#infoTB').attr('att_entityType'));
                    frmData.append('refDisplayTxt', $('#DocrefLinkText').val());
                    frmData.append('refLink', $('#DocrefLink').val());
                    ajaxReqforFileUpload('Main/UploadRefLink', frmData, true, function (resp) {
                        if (resp.status == "OK") {
                            $('#closeModalPopup').trigger("click");
                            app.getRefLinks();
                            alert(resp.message);
                        }
                        else {
                            alert(resp.message);
                        }

                    }, true);
                }
                else {
                    alert("Invalid reference link! <br> (Ex: 'http or https://www.xyz.com')");
                }
            }
            else {
                $('#DocrefLink').addClass("NotValid");
                return false;
            }
        }
        else {
            $('#DocrefLinkText').addClass("NotValid");
            return false;
        }
    }

