    this.CheckOffSetRequired = function () {

        //var is_offset_required = $("input[name='is_offset_required']:checked").val();
        //if (is_offset_required == "True") {
        //    $('#optionDiv').show();
        //}
        //else { $('#optionDiv').hide(); $('#offset_value').val(0); $('#is_offset_requiredRight').prop('checked', true); }
        var is_offset_required = $("input[name='is_offset_required']:checked").val();
        if (is_offset_required == "True") {
            // $('#optionDiv').show();
            $('#offset_value').attr('readonly', false);
            $(".offsetcheck").removeClass("dvDisabled").prop("onclick", null).off("click");;

        }
        else {
            //$('#optionDiv').hide(); 
            $('#offset_value').val(0);
            $('#offset_value').attr('readonly', true);
            $('#is_offset_requiredRight').prop('checked', true);
            $(".offsetcheck").addClass("dvDisabled");

        }
        app.createOffsetCable();
    }
    this.createOffsetCable = function () {

        app.geomToForm();
        var cablegemo = $('#directionGeometry').val();
        // $('#offset_value').removeClass('input-validation-error');
        if (cablegemo != '') {
            if ($('#offset_value').val() == '') {
                // $('#offset_value').addClass('input-validation-error');
                //alert(MultilingualKey.SI_OSP_GBL_JQ_FRM_034);
                return false;
            }
            else if (parseInt($('#offset_value').val()) > 10) {
                alert(MultilingualKey.SI_OSP_GBL_JQ_FRM_107);
                return false;
            }
            var offSet = '';
            if ($('#is_offset_requiredLeft').prop('checked'))
                offSet = '-' + parseFloat($('#offset_value').val()) / 100000;
            else
                offSet = parseFloat($('#offset_value').val()) / 100000;

            if (app.temp_gemo == "") {
                app.temp_gemo = cablegemo;
            }

            if ($('#offset_value').val() == 0) {
                var latLngArr = [];
                var longLatArr = app.temp_gemo.split(',');


                for (var i = 0; i < longLatArr.length; i++) {
                    var LongLatsingle = longLatArr[i].split(' ');
                    latLngArr.push(new google.maps.LatLng(parseFloat(LongLatsingle[1]), parseFloat(LongLatsingle[0])));
                }

                var startlatlng = latLngArr[0].lat() + ',' + latLngArr[0].lng();
                // $('#start_point').val(startlatlng);
                app.NetworkStartPoint = startlatlng;
                app.createStartMarker();

                var endIndex = latLngArr.length - 1;
                var endLatLngr = latLngArr[endIndex].lat() + ',' + latLngArr[endIndex].lng();
                app.NetworkEndPoint = endLatLngr;
                app.createEndMarker();

                //if (app.plan_mode == 'manual_planning') {
                //    var endIndex = latLngArr.length - 1;
                //    var endLatLngr = latLngArr[endIndex].lat() + ',' + latLngArr[endIndex].lng();
                //    $('#end_point').val(endLatLngr);
                //    app.NetworkEndPoint = endLatLngr;
                //    app.createEndMarker();
                //}



                //app.networkPlanningcable(latLngArr);
                $('#directionGeometry').val(longLatArr);
                app.networkPlanningcable(latLngArr);
            }
            else {

                ajaxReq('plan/getOffSetPolyLineCurve', { cablegemo: app.temp_gemo, offset: offSet }, false, function (jSonResp) {
                    var latLngArr = [];
                    var longLat = jSonResp.offsetGeom.substring(jSonResp.offsetGeom.indexOf('(') + 1, jSonResp.offsetGeom.lastIndexOf(')')).replace(/\(/, '').replace(/\)/, '');
                    longLat = longLat.replace(/\(/, '').replace(/\)/, '');
                    var longLatArr = longLat.split(',');
                    var _longLatArr = [];

                    if ($('#is_offset_requiredLeft').prop('checked')) { longLatArr.reverse(); _longLatArr.reverse(); }

                    var latlngEndPoint = app.NetworkEndPoint.split(',');
                    longLatArr.push(latlngEndPoint[1] + ' ' + latlngEndPoint[0]);


                    var latlngStartPoint = app.NetworkStartPoint.split(',');
                    _longLatArr.push(latlngStartPoint[1] + ' ' + latlngStartPoint[0]);

                    for (var i = 0; i < longLatArr.length; i++) {
                        var y = longLatArr[i].split(' ');
                        _longLatArr.push(y[0] + ' ' + y[1]);
                    }

                    for (var i = 0; i < _longLatArr.length; i++) {
                        var LongLatsingle = _longLatArr[i].split(' ');
                        latLngArr.push(new google.maps.LatLng(parseFloat(LongLatsingle[1]), parseFloat(LongLatsingle[0])));
                    }

                    var startlatlng = latLngArr[0].lat() + ',' + latLngArr[0].lng();
                    app.NetworkStartPoint = startlatlng;
                    app.createStartMarker();

                    var endIndex = latLngArr.length - 1;
                    var endLatLngr = latLngArr[endIndex].lat() + ',' + latLngArr[endIndex].lng();
                    app.NetworkEndPoint = endLatLngr;
                    app.createEndMarker();

                    $('#directionGeometry').val(_longLatArr);
                    app.networkPlanningcable(latLngArr);
                }, true, false);
            }

        }

    }
