    this.setDateTimeCalendar = function (startdateid, enddateid, startdateimgid, enddateimgid, isBackDateAllowed) {
        Calendar.setup({
            inputField: startdateid,   // id of the input field
            button: startdateimgid,
            ifFormat: "%d-%b-%Y",       // format of the input field datetime format %d-%b-%Y %I:%M %p
            showsTime: false,
            timeFormat: "12",
            weekNumbers: false,

            disableFunc: function (date) {
                ////;
                if (!isBackDateAllowed) {
                    var now = new Date();
                    now.setDate(now.getDate() - 1);
                    if (date.getTime() < now.getTime()) {
                        return true;
                    }
                }
            }
        });
        Calendar.setup({
            inputField: enddateid,
            button: enddateimgid,
            ifFormat: "%d-%b-%Y",
            showsTime: false,
            timeFormat: "12",
            weekNumbers: false,
            align: "Br",
            disableFunc: function (date) {
                var startDateValue = document.getElementById(startdateid).value;
                var startdt = DateFormatter(startDateValue);
                startdt = new Date(startdt);
                if (date.getTime() < startdt.getTime()) {
                    return true;
                }
                if (!isBackDateAllowed) {
                    var now = new Date();
                    now.setDate(now.getDate() - 1);
                    if (date.getTime() < now.getTime()) {
                        return true;
                    }
                }

            }
        });
    }


