    //Response After Save Data
    this.handleSuccess = function (data) {
        ;
        if (data == "Success_UpdateStatus_Assigned") {
            alert("Job assigned successfully!!");
            $(popup.DE.CloseChildPopup).trigger("click");
            //refresh view route grid..
            if ($('#frmAssignJobOrder').length > 0) { si.SubmitForm("frmAssignJobOrder"); }
            return false;
        }
        else if (data == "Success_UpdateStatus_Re-Assigned") {
            alert("Job assigned successfully!!");
            $(popup.DE.CloseChildPopup).trigger("click");
            //refresh view route grid..
            if ($('#frmViewRoute').length > 0) { si.SubmitForm("frmViewRoute"); }
            return false;
        }


        else if (data == "Error_UpdateStatus") {
            alert("Error occurred!!");
            $(popup.DE.CloseChildPopup).trigger("click");
        }

        else if (data == "Success_UpdateStatus_UnAssigned") {
            alert("Job assigned to dispatcher successfully!!");
            $(popup.DE.CloseChildPopup).trigger("click");
            //refresh view route grid..
            if ($('#frmAssignJobOrder').length > 0) { si.SubmitForm("frmAssignJobOrder"); }
            return false;
        }

        else if (data == "Success_UpdateStatus_Close") {
            alert("Job order close successfully!!");
            $(popup.DE.CloseChildPopup).trigger("click");
            //refresh view route grid..
            if ($('#frmCloseticket').length > 0) { si.SubmitForm("frmCloseticket"); }
            return false;
        }
        else if (data == "Success_UpdateStatus_SUpdate") {
            alert("Serial Number updated successfully!!");
            $(popup.DE.CloseChildPopup).trigger("click");
            //refresh view route grid..
            if ($('#frmUserTimeSheet').length > 0) { si.SubmitForm("frmUserTimeSheet"); }
            return false;
        }
        // response after assign multiple joborder
        else {
            alert(data);
            $(popup.DE.CloseChildPopup).trigger("click");
            //refresh view route grid..
            if ($('#frmAssignJobOrder').length > 0) { si.SubmitForm("frmAssignJobOrder"); }
            return false;
        }


        if (data.indexOf(":") > 0) {
            var val = data.split(':');
            if (val[0] == "MSG") {
                alert(val[1]);
                $(popup.DE.CloseChildPopup).trigger("click");
                if ($('#frmAssignJobOrder').length > 0) { si.SubmitForm("frmAssignJobOrder"); }
                return false;
            }
        }



    }
