    this.ManageMapRelatedEvents = function (curEvent) {
        app.CloseInfoWindow();
        app.ClearRouteIssueLocMarkers();
        if (curEvent == "PATROLLER_LOC") {
            app.hideRoutePanel();
            app.ClearRouteRelatedEventsFromMap();
            app.ClearFRTLocationsFromMap();
            app.ClearAllLocationsFromMap();
        }
        else if (curEvent == "ROUTE") {
            app.ClearFRTLocationsFromMap();
            app.ClearPatrollerLocationsFromMap();
            app.ClearAllLocationsFromMap();
        }
        else if (curEvent == "FRT_LOC") {
            app.hideRoutePanel();
            app.ClearRouteRelatedEventsFromMap();
            app.ClearAllLocationsFromMap();
        }
        else if (curEvent == "ALL_LOC") {
            app.hideRoutePanel();
            app.ClearRouteRelatedEventsFromMap();
            app.ClearPatrollerLocationsFromMap();
            app.ClearFRTLocationsFromMap();
        }
        else {
            app.hideRoutePanel();
            app.ClearRouteRelatedEventsFromMap();
            app.ClearPatrollerLocationsFromMap();
            app.ClearFRTLocationsFromMap();
            $(app.DE.ChkViewAllPatrollersLocation).prop("checked", false);
            $(app.DE.ChkViewAllFRTsloc).prop("checked", false);

        }
    }
    this.ShowRouteIssueOnMap = function (ticket_source_id, hpsm_ticketid, issue_Id, task_tracking_id) {
        ;
        app.ManageMapRelatedEvents();// clear all from map..
        //Minimize modal popup...

        $(popup.DE.MinimizeParentModel).trigger("click");

        issue_Id = issue_Id || 0;
        task_tracking_id = task_tracking_id || 0;
        app.ajaxReqNew("Main/getRouteIssueTrackingDetail", { issueId: issue_Id, taskTrackingId: task_tracking_id, ticketid: hpsm_ticketid }, true, function (resp) {

            if (resp != undefined) {
                app.selectedFRTForLocation = parseInt(resp.frt_id);
                var curLocMarker = "";
                if (resp.status != undefined && resp.status == 'InProgress') {
                    app.ajaxReqNew("Main/GetFRTsCurrentLocation", { FRTId: parseInt(app.selectedFRTForLocation || 0), circleId: 0 }, true, function (resp) {
                        if (resp != undefined && resp.FRTLocations != undefined && resp.FRTLocations.length > 0) {
                            var requestCoordinates = [];
                            $.each(resp.FRTLocations, function (index, loc) {
                                requestCoordinates.push(loc.checkin_lat + ',' + loc.checkin_lng);
                            });

                            app.GetNearestToRoadPoints(requestCoordinates, function (snappedPoints) {

                                //update locations to nearest road..
                                for (var i = 0; i < snappedPoints.length; i++) {
                                    if (resp.FRTLocations[i] != undefined) {
                                        resp.FRTLocations[i].checkin_lat = snappedPoints[i].lat();
                                        resp.FRTLocations[i].checkin_lng = snappedPoints[i].lng();
                                    }
                                }

                                //process each point...
                                $.each(resp.FRTLocations, function (index, loc) {

                                    var latlng = new google.maps.LatLng(loc.checkin_lat, loc.checkin_lng);
                                    //nearset to road.. 100..
                                    var title = loc.frt_full_name + ' (' + loc.frt_user_name + ')';
                                    var markerImg = 'content/images/Current_Location_Green.gif';
                                    var infoId = 'frt_' + loc.frt_id;
                                    //Prepare content
                                    var content = '';
                                    //content = content + '<B>Battery Percentage : </B> ' + (loc.battery_percentage != null ? loc.battery_percentage : 'NA') + ' <br/>';
                                    if (loc.last_tracked_on != null) {
                                        content = content + '<B>Last Tracked On : </B> ' + app.JsonDateTimeFormator(loc.last_tracked_on) + ' <br/>';
                                    }

                                    content = content + '</div>';
                                    curLocMarker = app.createMarkerWithInfo(latlng, markerImg, title, content, infoId);
                                    curLocMarker.setAnimation(google.maps.Animation);
                                    curLocMarker.setOptions({ key: loc.frt_id });
                                    if (curLocMarker != "" && curLocMarker != undefined)
                                        app.routeIssueLocMarkers.push(curLocMarker);
                                });

                            });

                        }

                    }, true, true);
                }
                var latlng = new google.maps.LatLng(resp.issue_lat, resp.issue_lng);
                var title = resp.issue_desc;
                var markerImg = 'Content/images/';
                var infoId = 'frt_' + resp.issue_id;
                var status = resp.status == undefined || resp.status == '' ? 'UnAssigned' : resp.status;
                markerImg += status == "InProgress" ? "task_yellow.png" : (status == "Completed" ? "task_green.png" : "task_red.png");
                //Prepare content
                var content = '';
                content = content + '<B>Issue Raised By : </B> ' + resp.patroller_full_name + ' <br/>';
                content = content + '<B>Remark : </B> ' + (resp.patroller_remark != null ? resp.patroller_remark : 'NA') + ' <br/>';
                content = content + '<B>Manager Remark : </B> ' + (resp.manager_remark != null ? resp.manager_remark : 'NA') + '<br/>';
                content = content + '<B>Status : </B> ' + status + ' <br/>';

                if (ticket_source_id == "3") {
                    content = content + '<B>Network Entity : </B> ' + resp.NetworkEntity + ' <br/>';
                }

                if (status != 'UnAssigned') {
                    content = content + '<B>FRT Name : </B> ' + (resp.frt_full_name != null ? resp.frt_full_name : 'NA') + ' <br/>';
                    content = content + '<B>Assigned Date : </B> ' + app.JsonDateTimeFormator(resp.assigned_date) + ' <br/>';

                    if (resp.checkin_time != null && resp.checkin_time != undefined) {
                        content = content + '<B>Check-In Time : </B> ' + app.JsonDateTimeFormator(resp.checkin_time) + '<br/>';
                        content = content + '<B>Check-In Remark : </B> ' + resp.checkin_remarks + ' <br/>';
                    }
                    if (resp.checkout_time != null && resp.checkout_time != undefined) {
                        content = content + '<B>Check-Out Time : </B> ' + app.JsonDateTimeFormator(resp.checkout_time) + '<br/>';
                        content = content + '<B>Check-Out Remark : </B> ' + resp.checkout_remarks + ' <br/>';
                    }
                }
                var checkInMarker;
                var checkOutMarker;

                content = content + '<div class="tt-img">';
                // if (resp.issue_img != null)
                //{
                content = content + '<a href="#" onclick="sp.showFullImage(\'' + resp.issue_img + '\',\'\')" >Issue Image</a>&nbsp;&nbsp;';

                // }

                if (resp.checkin_img != null) {
                    content = content + '<a href="#" onclick="sp.showFullImage(\'' + resp.checkin_img + '\',\'\')" >Check-In Image</a>&nbsp;&nbsp;';
                    checkInMarker = app.ShowRouteIssueAttachmentOnMap('checkin', issue_Id, resp.actual_lat, resp.actual_lng, resp.checkin_img);

                }
                if (resp.checkout_img != null) {
                    content = content + '<a href="#" onclick="sp.showFullImage(\'' + resp.checkout_img + '\',\'\')" >Check-Out Image</a>&nbsp;&nbsp;';
                    checkOutMarker = app.ShowRouteIssueAttachmentOnMap('checkout', issue_Id, resp.checkOut_lat, resp.checkOut_lng, resp.checkout_img);
                }
                content = content + '</div>';
                app.ClearRouteIssueLocMarkers();
                var routeIssueMarker = app.createMarkerWithInfo(latlng, markerImg, title, content, infoId);

                routeIssueMarker.setOptions({ key: resp.issue_id });
                app.routeIssueLocMarkers.push(routeIssueMarker);



                //if (curLocMarker != "" && curLocMarker != undefined)
                //    app.routeIssueLocMarkers.push(curLocMarker);
                if (checkInMarker != undefined)
                    app.routeIssueLocMarkers.push(checkInMarker);
                if (checkOutMarker != undefined)
                    app.routeIssueLocMarkers.push(checkOutMarker);

                google.maps.event.trigger(routeIssueMarker, 'click');
                app.map.setCenter(routeIssueMarker.getPosition());

                var bounds = new google.maps.LatLngBounds();
                for (var i = 0; i < app.routeIssueLocMarkers.length; i++) {
                    bounds.extend(app.routeIssueLocMarkers[i].getPosition());
                }

                //app.ajaxReqNew("Main/GetNmsTktBoundaryByManager", {  }, true, function (resp3)
                //{
                //    if (resp3 != undefined && resp3.result != undefined && resp3.result.length > 0)
                //    {
                //        $.each(resp3.result, function (j, u)
                //        {

                //            var latlng = new google.maps.LatLng(u.lat, u.lng);
                //            var title = 'Marker';
                //            var markerImg = 'Content/images/task_yellow.png';
                //            var content = 'abcd';
                //            content = content + '</div>';

                //            var routeIssueMarker = app.createMarkerWithInfo(latlng, markerImg, title, content, 'aaaa');

                //            routeIssueMarker.setOptions({ key: 101 });
                //            app.routeIssueLocMarkers.push(routeIssueMarker);



                //            var points = [];
                //            $.each(u.boundary, function (i, v) {
                //                points.push(new google.maps.LatLng(v.Lat, v.Lng));
                //            });

                //            var outageBoundary = app.createPolygon(points);
                //            app.routeIssueLocMarkers.push(outageBoundary);

                //        });

                //    }
                //}, true, true);

                //Show boundary of outage tickets 
                /////////////////////////////////////////////////////////////////////////////////
                if (ticket_source_id == "3")// outage type of tickets
                {
                    app.ajaxReqNew("Main/GetNmsTicketBoundary", { hpsm_ticketid: hpsm_ticketid }, true, function (resp1) {
                        if (resp1 != undefined && resp1.boundary != undefined && resp1.boundary.length > 0) {
                            var points = [];
                            $.each(resp1.boundary, function (i, v) {
                                points.push(new google.maps.LatLng(v.Lat, v.Lng));
                            });

                            var outageBoundary = app.createPolygon(points);
                            app.routeIssueLocMarkers.push(outageBoundary);
                        }

                    }, true, true);
                }
                /////////////////////////////////////////////////////////////////////////////////
                app.map.fitBounds(bounds);
                // app.map.setZoom(15);
                checkInMarker = null;
                checkOutMarker = null;
            }
        }, true, true);

    }
