    // for get route asset details Report
    this.infoGetRoute = function (enable) {

        var enable = (enable != undefined ? enable : true);
        splicing.ClearSplicingRelatedObjs();
        if (enable) {
            app.mapReport.clearSelection();
        }
        if ((app.gMapObj.ClickAction && app.gMapObj.ClickAction == "INFO") || !enable) {
            app.resetShapeTools();
            $(app.DE.InfoDiv).hide();
            app.map.setOptions({ draggableCursor: '' });
            app.map.ClickAction = '';
            app.gMapObj.ClickAction = '';

            if (app.gMapObj.tempBufferCircle) { app.gMapObj.tempBufferCircle.setMap(null); app.gMapObj.tempBufferCircle = null; }
        }
        else {
            app.clearTPRelatedObjects();
            app.map.setOptions({ draggableCursor: 'crosshair' });
            google.maps.event.addListener(app.map, 'click', function (LatLong) {
                if (app.lineBufferObj != null) {
                    app.lineBufferObj.setMap(null);
                }
                app.clearInfoRelatedObjects();
                app.GetRouteAssetDetails(LatLong.latLng);
            });

            //Apply above event on External Data view map as well.
            if (app.externalViewerObj.length != 0) {
                app.externalViewerObj.forEach(function (layer) {
                    google.maps.event.addListener(layer, 'click', function (LatLong) {
                        if (app.lineBufferObj != null) {
                            app.lineBufferObj.setMap(null);
                        }
                        app.clearInfoRelatedObjects();
                        app.GetRouteAssetDetails(LatLong.latLng);

                    });
                });
            }
            app.gMapObj.ClickAction = "INFO"
            app.map.ClickAction = "INFO";
        }
    }

    this.GetRouteAssetDetails = function (latLng) {

        app.collapseRemove();
        var _zoom = app.map.getZoom();
        if (_zoom >= parseInt($('#hdnInfoToolZoom').val())) {
            app.showTempBufferforInfo(latLng);
            ajaxReq('Main/GetRouteAssetDetails', { latitude: latLng.lat(), longitude: latLng.lng(), bufferInMtrs: getMeterDistanceFromZoom(_zoom) }, true, function (resp) {

                // $(app.DE.infoMain).html(resp);
                if (resp != null) {
                    if (resp.length > 50) {
                        let conf = resp.substr(0, 45);
                        if (conf !== "<script>alert('Please Select Trench Entity');") {
                            var w = window.open();
                            $(w.document.body).html(resp);
                            //$("#exportexcel").tabs();
                            /* $(app.DE.InfoDiv).show();*/
                            $('.infoBack').hide();
                            $("#rdbDisplayedLayer").click();
                        }
                        else {
                            alert("Please Select Trench Entity");
                            return;

                        }
                    }
                }


            }, false, true);
        }
        else {
            // //;
            var func = function () { app.map.setCenter(latLng); app.map.setZoom(parseInt($('#hdnInfoToolZoom').val())) };

            confirm(getMultilingualStringValue($.validator.format(MultilingualKey.SI_OSP_GBL_JQ_FRM_216, parseInt($('#hdnInfoToolZoom').val()), _zoom)), func);
        }
    }







