function ConvertDMSToLatLong(degrees, minutes, seconds, direction) {

    //var dd = degrees + minutes / 60 + seconds / (60 * 60);
    var dd = Number(degrees) + Number(minutes) / 60 + Number(seconds) / (60 * 60);

    if (direction == "S" || direction == "W") {
        dd = dd * -1;
    } // Don't do anything for N or E
    return dd;
}
function GenerateMapScaleRatio(zoomlbl) {
    //;
    var scl;
    if ($('#hdnIsMapScaleDynamic').val() == "False") {
        var result = [
            { "zoom": "21", "scale": "250" },
            { "zoom": "20", "scale": "500" },
            { "zoom": "19", "scale": "1000" },
            { "zoom": "18", "scale": "2000" },
            { "zoom": "17", "scale": "4000" },
            { "zoom": "16", "scale": "8000" },
            { "zoom": "15", "scale": "16000" },
            { "zoom": "14", "scale": "32000" },
            { "zoom": "13", "scale": "64000" },
            { "zoom": "12", "scale": "128000" },
            { "zoom": "11", "scale": "256000" },
            { "zoom": "10", "scale": "512000" },
            { "zoom": "9", "scale": "1024000" },
            { "zoom": "8", "scale": "2048000" },
            { "zoom": "7", "scale": "4096000" },
            { "zoom": "6", "scale": "8138000" },
            { "zoom": "5", "scale": "16276000" }
        ]
        result.forEach(function (e, index) {
            if (zoomlbl == result[index].zoom) {
                scl = result[index].scale;
            };
        });
    }
    else {
        scl = Math.round(((156543.03392 * Math.cos(si.map.getCenter().lat() * Math.PI / 180) / Math.pow(2, zoomlbl)) * 1000 / 0.2645833333));
    }
    return "Scale:-1:" + scl + " (mm)";
}
function SetMapScaleRatio(zoomlbl) {
    $("#maplblScaleRto").html(GenerateMapScaleRatio(zoomlbl));
}
function CheckUnCheckAll(PntIDs, IsPntID, ChldID, IsChldID) {
    let ptid, chldid;
    ptid = IsPntID == true ? $("#" + PntIDs) : $("." + PntIDs);
    chldid = IsChldID == true ? $("#" + ChldID) : $("." + ChldID);
    $(chldid).prop("checked", $(ptid).prop("checked"));
}
function CheckUnCheckAllOnSingle(PntIDs, IsPntID, ChldID, IsChldID) {
    let ptid, chldid;
    ptid = IsPntID == true ? "#" + PntIDs : "." + PntIDs;
    chldid = IsChldID == true ? "#" + ChldID : "." + ChldID;
    if ($('' + chldid + ':checked').length == $('' + chldid + '').length)
        $('' + ptid + '').prop('checked', true);
    else
        $('' + ptid + '').prop('checked', false);
}
function ValidateFormsWithParentID(ClosetParentIDWithSelector) {
    var isvalidForm = true;
    $(ClosetParentIDWithSelector + " input[type=text], select").each(function () {
        if ($(this).val() == "" && ($(this).attr("disabled") != "disabled" || $(this).attr("disabled") != true) && ($(this).attr("readonly") != "readonly" || $(this).attr("readonly") != true) && $(this).is(":visible") && $(this).css('display') != 'none' && $(this).attr("data-val-required") != "") {
            $(this).addClass('notvalid input-validation-error');
            isvalidForm = false;
        }
        else {
            $(this).removeClass('notvalid notvalid input-validation-error');
        }
    })
    return isvalidForm;
}

function validateSpecialChars(event, spChar) {
    var regex = new RegExp("^[A-Za-z0-9" + spChar + "]");
    var key = String.fromCharCode(event.charCode ? event.which : event.charCode);
    if (!regex.test(key)) {
        event.preventDefault();
        return false;
    }
}
